fn validate_config(loaded: &LoadedConfig) -> Result<()> {
    DecoderRegistry::from_config(loaded)?;
    let _ = loaded.validate_autopilot()?;
    let _ = loaded.validate_r2()?;
    let _ = loaded.validate_edge_mode();
    validate_autopilot_disk_config(loaded)?;
    validate_low_disk_config(loaded)?;
    let geyser = GeyserIngestService::new(loaded.config.geyser.clone());
    let payload = json!({
        "config_hash": loaded.hash,
        "cluster": loaded.config.environment.cluster,
        "strategy_version": loaded.config.environment.strategy_version,
        "runtime_mode": format!("{:?}", loaded.config.runtime.mode).to_lowercase(),
        "idl_hash": combined_idl_hash(loaded)?,
        "idl_count": loaded.config.pump.idl_paths.len(),
        "subscription": geyser.subscription_request(),
        "live_enabled": loaded.config.live.enabled,
        "shred_enabled": loaded.config.shred.enabled,
        "geyser_enabled": loaded.config.geyser.enabled,
        "stream_only_enabled": loaded.config.stream_only.enabled,
    });
    println!("{}", serde_json::to_string_pretty(&payload)?);
    Ok(())
}

fn validate_edge_mode_command(loaded: &LoadedConfig) -> Result<()> {
    let summary = loaded.validate_edge_mode()?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn forbid_heavy_vps_research_paths_in_edge_mode(
    loaded: &LoadedConfig,
    command_name: &str,
) -> Result<()> {
    if loaded.config.runtime.mode == RuntimeModeName::EdgeCollector
        || normalize_mode_name(&loaded.config.autopilot.mode) == "edge_collector"
    {
        return Err(anyhow!(
            "{command_name} is disabled in edge_collector mode; run it via research_worker on a non-VPS machine"
        ));
    }
    Ok(())
}

fn validate_autopilot_disk_config(loaded: &LoadedConfig) -> Result<()> {
    let disk = &loaded.config.autopilot.disk;
    if disk.warning_free_mb == 0
        || disk.pre_cycle_min_free_mb == 0
        || disk.critical_free_mb == 0
        || disk.emergency_free_mb == 0
    {
        return Err(anyhow!(
            "autopilot.disk warning/pre_cycle_min/critical/emergency free_mb values must be > 0"
        ));
    }
    if !(disk.warning_free_mb > disk.pre_cycle_min_free_mb
        && disk.pre_cycle_min_free_mb > disk.critical_free_mb
        && disk.critical_free_mb > disk.emergency_free_mb)
    {
        return Err(anyhow!(
            "autopilot.disk thresholds must satisfy warning_free_mb > pre_cycle_min_free_mb > critical_free_mb > emergency_free_mb"
        ));
    }
    if loaded.config.live.enabled {
        return Err(anyhow!(
            "live trading must remain disabled in autopilot disk-guard mode"
        ));
    }
    Ok(())
}

fn validate_low_disk_config(loaded: &LoadedConfig) -> Result<()> {
    let low_disk = &loaded.config.storage.low_disk_mode;
    if !low_disk.enabled {
        return Ok(());
    }
    if low_disk.target_local_runtime_mb == 0 {
        return Err(anyhow!(
            "storage.low_disk_mode.target_local_runtime_mb must be > 0"
        ));
    }
    if low_disk.max_local_export_mb == 0 {
        return Err(anyhow!(
            "storage.low_disk_mode.max_local_export_mb must be > 0"
        ));
    }
    if low_disk.warning_free_mb == 0
        || low_disk.critical_free_mb == 0
        || low_disk.emergency_free_mb == 0
    {
        return Err(anyhow!(
            "storage.low_disk_mode warning/critical/emergency free_mb values must be > 0"
        ));
    }
    if !(low_disk.warning_free_mb > low_disk.critical_free_mb
        && low_disk.critical_free_mb > low_disk.emergency_free_mb)
    {
        return Err(anyhow!(
            "storage.low_disk_mode thresholds must satisfy warning_free_mb > critical_free_mb > emergency_free_mb"
        ));
    }
    if loaded.config.exports.chunked_enabled && loaded.config.exports.feature_export_chunk_rows == 0
    {
        return Err(anyhow!(
            "exports.feature_export_chunk_rows must be > 0 when chunked exports are enabled"
        ));
    }
    if loaded.config.live.enabled {
        return Err(anyhow!(
            "live trading must remain disabled in low-disk mode"
        ));
    }
    Ok(())
}

fn force_stream_only_config(loaded: &mut LoadedConfig) {
    loaded.config.stream_only.enabled = true;
    loaded.config.rpc.hot_path_enabled = false;
    loaded.config.rpc.daily_credit_budget = 0;
    loaded.config.rpc.monthly_credit_budget = 0;
    loaded.config.rpc_budget.daily_credit_limit = 0;
    loaded.config.rpc_budget.monthly_credit_limit = 0;
    loaded.config.rpc_budget.emergency_reserve = 0;
    loaded.config.execution.enabled = false;
    loaded.config.execution.use_rpc_send = false;
    loaded.config.metadata.fetch_uri = false;
    loaded.config.metadata.hot_path_fetch_enabled = false;
    loaded.config.confirmation.source = "geyser_stream".to_owned();
    loaded.config.confirmation.allow_rpc_status_fallback = false;
    if loaded.config.autopilot.stream_only_required {
        loaded.config.autopilot.live_trading_allowed = false;
    }
}

fn validate_stream_only(loaded: &LoadedConfig) -> Result<()> {
    let summary = loaded.validate_stream_only()?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn inspect_rpc_budget(loaded: &LoadedConfig) -> Result<()> {
    let manager = RpcBudgetManager::new(
        loaded.config.rpc_budget.clone(),
        loaded.config.execution.clone(),
        loaded.config.stream_only.clone(),
        loaded.config.rpc.clone(),
    );
    println!("{}", serde_json::to_string_pretty(&manager.summary())?);
    Ok(())
}

fn inspect_deshred_capability_command(loaded: &LoadedConfig) -> Result<()> {
    let capability = runtime::inspect_deshred_capability(loaded, None, None);
    let deshred = loaded.config.ingest.deshred.clone().unwrap_or_default();
    let endpoint_env = if deshred.endpoint_env.trim().is_empty() {
        "GEYSER_ENDPOINT"
    } else {
        deshred.endpoint_env.as_str()
    };
    let auth_env = if deshred.auth_token_env.trim().is_empty() {
        "GEYSER_AUTH_TOKEN"
    } else {
        deshred.auth_token_env.as_str()
    };
    let payload = json!({
        "command": "inspect-deshred-capability",
        "enabled_in_config": deshred.enabled,
        "required_in_config": deshred.required,
        "endpoint_env": endpoint_env,
        "auth_token_env": auth_env,
        "auth_metadata_key": if deshred.auth_metadata_key.trim().is_empty() { "x-token" } else { deshred.auth_metadata_key.as_str() },
        "proto_support": capability.supported_by_proto,
        "client_support": capability.supported_by_client,
        "supports_program_filters": capability.supports_program_filters,
        "supports_account_filters": capability.supports_account_filters,
        "exposes_loaded_addresses": capability.exposes_loaded_addresses,
        "exposes_signature": capability.exposes_signature,
        "exposes_slot": capability.exposes_slot,
        "exposes_raw_transaction": capability.exposes_raw_transaction,
        "exposes_instruction_data": capability.exposes_instruction_data,
        "exposes_transaction_status_meta": capability.exposes_transaction_status_meta,
        "endpoint_configured": capability.endpoint_configured,
        "auth_configured": capability.auth_configured,
        "can_enable": capability.can_enable,
        "reason_if_unsupported": capability.reason_if_unsupported,
    });
    println!("{}", serde_json::to_string_pretty(&payload)?);
    Ok(())
}

fn inspect_raw_shred_capability(loaded: &LoadedConfig) -> Result<()> {
    let feature_flag_compiled = cfg!(feature = "production-shred-decoder");
    let fixture_decoder_available = true;
    let production_mode_allowed = loaded.config.early_intent.allow_production_raw_shred;
    let backend_available = feature_flag_compiled;
    let production_supported = feature_flag_compiled && production_mode_allowed;
    let reason_if_unsupported = if !feature_flag_compiled {
        Some(
            "production raw shred decoder is not compiled; enable feature production-shred-decoder with a supported backend"
                .to_owned(),
        )
    } else if !production_mode_allowed {
        Some("production raw shred decoder is compiled but disabled by config".to_owned())
    } else {
        None
    };
    let payload = json!({
        "command": "inspect-raw-shred-capability",
        "feature_flag_compiled": feature_flag_compiled,
        "backend_available": backend_available,
        "fixture_decoder_available": fixture_decoder_available,
        "production_mode_allowed": production_mode_allowed,
        "production_supported": production_supported,
        "reason_if_unsupported": reason_if_unsupported,
    });
    println!("{}", serde_json::to_string_pretty(&payload)?);
    Ok(())
}

fn deshred_endpoint_value(loaded: &LoadedConfig) -> Option<String> {
    let deshred = loaded.config.ingest.deshred.clone().unwrap_or_default();
    if !deshred.endpoint.trim().is_empty() {
        return Some(deshred.endpoint);
    }
    let env_name = if deshred.endpoint_env.trim().is_empty() {
        "GEYSER_ENDPOINT"
    } else {
        deshred.endpoint_env.as_str()
    };
    std::env::var(env_name)
        .ok()
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty())
}

fn geyser_endpoint_value(loaded: &LoadedConfig) -> Option<String> {
    let geyser = &loaded.config.geyser;
    if !geyser.endpoint.trim().is_empty() {
        return Some(geyser.endpoint.clone());
    }
    let env_name = if geyser.endpoint_env.trim().is_empty() {
        "GEYSER_ENDPOINT"
    } else {
        geyser.endpoint_env.as_str()
    };
    std::env::var(env_name)
        .ok()
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty())
}

fn endpoint_host_hash(endpoint: Option<&str>) -> String {
    let host = endpoint
        .and_then(|value| {
            let without_scheme = value
                .split_once("://")
                .map(|(_, rest)| rest)
                .unwrap_or(value);
            without_scheme
                .split('/')
                .next()
                .map(|segment| segment.split('@').next_back().unwrap_or(segment))
        })
        .unwrap_or_default();
    if host.is_empty() {
        return String::new();
    }
    format!("{:x}", Sha256::digest(host.as_bytes()))
}

