fn artifact_content_type(path: &Path) -> String {
    match path.extension().and_then(|value| value.to_str()) {
        Some("json") => "application/json".to_owned(),
        Some("jsonl") => "application/x-ndjson".to_owned(),
        Some("csv") => "text/csv".to_owned(),
        Some("md") => "text/markdown".to_owned(),
        Some("txt") => "text/plain".to_owned(),
        Some("zst") => "application/zstd".to_owned(),
        _ => "application/octet-stream".to_owned(),
    }
}

fn write_jsonl_records<T: Serialize>(path: &Path, records: &[T]) -> Result<()> {
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }
    let mut output = String::new();
    for record in records {
        output.push_str(&serde_json::to_string(record)?);
        output.push('\n');
    }
    fs::write(path, output)?;
    Ok(())
}

fn ensure_run_dataset_snapshots(loaded: &LoadedConfig, run_id: &str) -> Result<Vec<PathBuf>> {
    let store = storage_engine(loaded)?;
    let report_dir = store.run_report_dir(run_id);
    fs::create_dir_all(&report_dir)?;
    let normalized_events_path = report_dir.join("dataset_normalized_events.jsonl");
    let decisions_path = report_dir.join("dataset_trade_decisions.jsonl");
    let fills_path = report_dir.join("dataset_fills.jsonl");
    let runtime_audit_path = report_dir.join("dataset_runtime_audit.jsonl");
    let run_metadata_path = report_dir.join("dataset_run_metadata.json");

    let events = store.read_normalized_events_filtered(Some(run_id), None)?;
    write_jsonl_records(&normalized_events_path, &events)?;
    let decisions = store.read_trade_decisions_filtered(Some(run_id), None)?;
    write_jsonl_records(&decisions_path, &decisions)?;
    let fills = store.read_fills_filtered(Some(run_id), None)?;
    write_jsonl_records(&fills_path, &fills)?;
    let audits = load_runtime_audits_for_run(&store, run_id)?;
    write_jsonl_records(&runtime_audit_path, &audits)?;
    let metadata = latest_metadata_for_run(&store, run_id)?;
    fs::write(
        &run_metadata_path,
        serde_json::to_vec_pretty(&metadata.map(|record| record.record))?,
    )?;

    Ok(vec![
        normalized_events_path,
        decisions_path,
        fills_path,
        runtime_audit_path,
        run_metadata_path,
    ])
}

