fn load_manifest_if_present(
    loaded: &LoadedConfig,
    run_id: &str,
) -> Result<Option<ArtifactManifest>> {
    let path = r2_manifest_path_for_run(loaded, run_id)?;
    if !path.exists() {
        return Ok(None);
    }
    Ok(Some(load_manifest(&path)?))
}

async fn verify_r2_manifest_for_run(
    loaded: &LoadedConfig,
    run_id: &str,
    dry_run: bool,
    check_manifest_consistency: bool,
) -> Result<(ArtifactManifest, u64, Vec<String>)> {
    let manifest_path = r2_manifest_path_for_run(loaded, run_id)?;
    let mut manifest = load_manifest(&manifest_path)?;
    if dry_run {
        let artifact_count = manifest.artifacts.len() as u64;
        return Ok((manifest, artifact_count, Vec::new()));
    }
    let client = r2_client_for_command(loaded, false, true, false)?;
    let mut verified_count = 0u64;
    let mut failures = Vec::new();
    for artifact in &mut manifest.artifacts {
        match client
            .verify_object(
                &artifact.bucket,
                &artifact.remote_key,
                artifact.size_bytes,
                Some(&artifact.checksum_sha256),
            )
            .await
        {
            Ok(true) => {
                artifact.verified = true;
                verified_count = verified_count.saturating_add(1);
            }
            Ok(false) => failures.push(artifact.remote_key.clone()),
            Err(error) => failures.push(format!("{}: {error}", artifact.remote_key)),
        }
    }
    let consistency = if check_manifest_consistency {
        Some(manifest_consistency_report_for_run(loaded, run_id).await?)
    } else {
        None
    };
    if check_manifest_consistency {
        let consistency = consistency.as_ref().expect("consistency report present");
        if consistency.drift_detected {
            failures.push(format!(
                "segment_manifest_consistency_drift:size={} checksum={} remote_key={}",
                consistency.expected_size_bytes,
                consistency.expected_checksum_sha256,
                consistency.remote_key
            ));
        }
    }
    manifest.uploaded = manifest.upload_summary.uploaded_count == manifest.artifacts.len() as u64
        && manifest.upload_summary.failed_count == 0
        && !manifest.upload_summary.dry_run;
    if let Some(report) = consistency.as_ref() {
        apply_manifest_consistency_report(&mut manifest, report);
    } else {
        refresh_manifest_verification_state(&mut manifest);
    }
    manifest.uploaded_at = manifest
        .uploaded_at
        .or_else(|| Some(OffsetDateTime::now_utc()));
    if let Some(segment_manifest) = load_run_segment_manifest_if_present(loaded, run_id)? {
        let report_dir = run_report_dir_for(loaded, run_id)?;
        let quality = read_json_file::<LiveCollectionQualitySummary>(
            &report_dir.join("live_collection_quality.json"),
        );
        let readiness =
            read_json_file::<BacktestReadinessSummary>(&report_dir.join("backtest_readiness.json"));
        let backfill = load_metadata_backfill_summary(&report_dir);
        let dataset_index_status = manifest.dataset_index_status.clone();
        let repair_warnings = manifest.repair_warnings.clone();
        apply_terminal_manifest_state(
            &mut manifest,
            &segment_manifest,
            quality.is_some(),
            readiness.is_some(),
            dataset_index_status,
            quality.as_ref(),
            readiness.as_ref(),
            backfill.as_ref(),
            &repair_warnings,
        );
    } else {
        refresh_manifest_verification_state(&mut manifest);
        manifest.run_status = current_manifest_run_status(&manifest);
    }
    manifest.verified = manifest.r2_full_verification_status == "verified";
    write_manifest(&manifest_path, &manifest)?;
    if manifest_verified(&manifest) {
        let _ = refresh_dataset_index(loaded)?;
    }
    Ok((manifest, verified_count, failures))
}

fn recovered_run_status(
    loaded: &LoadedConfig,
    store: &StorageEngine,
    run_id: &str,
) -> Result<(bool, String)> {
    let records = store.read_run_metadata_filtered(Some(run_id), None)?;
    let had_failure = records.iter().any(|record| {
        matches!(
            record.record.status,
            storage::RunStatus::Failed | storage::RunStatus::Interrupted
        )
    });
    let alerts = read_autopilot_alerts(loaded).unwrap_or_default();
    let failed_alert = alerts.iter().any(|record| {
        record.run_id.as_deref() == Some(run_id)
            && record.alert_type == AutopilotAlertType::AutopilotFailed
    });
    let recovered_alert = alerts.iter().any(|record| {
        record.run_id.as_deref() == Some(run_id)
            && record.alert_type == AutopilotAlertType::AutopilotRecovered
    });
    let latest = latest_metadata_for_run(store, run_id)?;
    let latest_completed = latest
        .as_ref()
        .map(|record| record.record.status == storage::RunStatus::Completed)
        .unwrap_or(false);
    let recovered_run = (had_failure || failed_alert) && latest_completed;
    let repair_status = if recovered_run {
        if recovered_alert {
            "recovered_after_recorded_failure".to_owned()
        } else {
            "recovered_from_previous_failure".to_owned()
        }
    } else if had_failure || failed_alert {
        "failure_history_present_not_completed".to_owned()
    } else {
        "not_recovered".to_owned()
    };
    Ok((recovered_run, repair_status))
}

