fn refresh_backtest_readiness_reports_from_backfill(
    loaded: &LoadedConfig,
    run_id: &str,
    backfill: &RunMetadataBackfillSummary,
) -> Result<()> {
    let report_root = run_report_dir_for(loaded, run_id)?;
    let readiness_path = report_root.join("backtest_readiness.json");
    let Some(mut readiness) = read_json_file::<BacktestReadinessSummary>(&readiness_path) else {
        return Ok(());
    };
    readiness.stream_only_proof.stream_only_passed = backfill.stream_only_passed;
    readiness.stream_only_proof.rpc_network_calls_total = backfill.rpc_network_calls_total;
    readiness.stream_only_proof.rpc_credits_used_total = backfill.rpc_credits_used_total;
    readiness.r2_verified = backfill.r2_verified;
    readiness.run_terminal_status = backfill.run_terminal_status.clone();
    readiness.finalization_status = backfill.finalization_status.clone();
    readiness.stream_only_passed = backfill.stream_only_passed;
    readiness.rpc_network_calls_total = backfill.rpc_network_calls_total;
    readiness.rpc_credits_used_total = backfill.rpc_credits_used_total;
    if let Some(observed) = readiness.observed_values.as_mut() {
        observed.stream_only_passed = backfill.stream_only_passed;
        observed.rpc_network_calls_total = backfill.rpc_network_calls_total;
        observed.rpc_credits_used_total = backfill.rpc_credits_used_total;
    }
    let _ = write_backtest_readiness_reports(loaded, &readiness)?;
    Ok(())
}

fn provider_env_precheck_summary(
    loaded: &LoadedConfig,
    provider_name: Option<&str>,
    expect_deshred: bool,
    expect_geyser: bool,
    report_dir: Option<&str>,
) -> Result<(ProviderEnvPrecheckSummary, PathBuf)> {
    let precheck_run_id = derived_run_id("provider-precheck");
    let report_root =
        resolve_report_root(loaded, "provider_precheck", &precheck_run_id, report_dir);
    let stream_only_proof = wrapper_stream_only_summary(loaded, &report_root)?;
    let endpoint_value = geyser_endpoint_value(loaded);
    let endpoint_present = endpoint_value
        .as_ref()
        .map(|value| !value.trim().is_empty())
        .unwrap_or(false);
    let endpoint_scheme_valid = endpoint_value
        .as_deref()
        .map(valid_endpoint_scheme)
        .unwrap_or(false);
    let deshred_cfg = loaded.config.ingest.deshred.clone().unwrap_or_default();
    let auth_required = loaded.config.geyser.auth_required || deshred_cfg.auth_required;
    let auth_present = env_value_present(&loaded.config.geyser.auth_token_env)
        || env_value_present(&deshred_cfg.auth_token_env);
    let validation = loaded.stream_only_validation_summary();
    let rpc_budget_zero = loaded.config.rpc.daily_credit_budget == 0
        && loaded.config.rpc.monthly_credit_budget == 0
        && loaded.config.rpc_budget.daily_credit_limit == 0
        && loaded.config.rpc_budget.monthly_credit_limit == 0;
    let deshred_capability = runtime::inspect_deshred_capability(loaded, None, None);
    let raw_shred = raw_shred_capability_payload(loaded);
    let raw_shred_production_supported = raw_shred
        .get("production_supported")
        .and_then(|value| value.as_bool())
        .unwrap_or(false);
    let compatibility = load_provider_compatibility_records(loaded)?
        .into_iter()
        .last();
    let mut blockers = Vec::new();
    let mut warnings = Vec::new();
    if !endpoint_present {
        blockers.push("missing GEYSER_ENDPOINT-compatible stream endpoint".to_owned());
    } else if !endpoint_scheme_valid {
        blockers.push("stream endpoint must start with http:// or https://".to_owned());
    }
    if auth_required && !auth_present {
        blockers.push("required provider auth token env var is missing".to_owned());
    }
    if !validation.passed {
        blockers.push(format!(
            "stream-only validation failed: {}",
            validation.violations.join("; ")
        ));
    }
    if !rpc_budget_zero {
        blockers.push("stream-only requires zero RPC budgets".to_owned());
    }
    if loaded.config.live.enabled {
        blockers.push("live trading must remain disabled for provider validation".to_owned());
    }
    if expect_geyser && !loaded.config.geyser.enabled {
        blockers.push("geyser streaming is disabled in config".to_owned());
    }
    if expect_deshred && !deshred_cfg.enabled {
        blockers.push("deshred streaming is disabled in config".to_owned());
    }
    if expect_deshred && !deshred_capability.can_enable {
        blockers.push(
            deshred_capability
                .reason_if_unsupported
                .clone()
                .unwrap_or_else(|| "deshred unsupported by this build".to_owned()),
        );
    }
    if !raw_shred_production_supported {
        warnings
            .push("production raw shred decoding remains unavailable and fail-closed".to_owned());
    }
    if let Some(record) = &compatibility {
        warnings.push(format!(
            "latest_provider_compatibility_status={} confidence={}",
            record.subscribe_deshred_result, record.supports_deshred_confidence
        ));
    }
    if !deshred_cfg.enabled {
        warnings.push("deshred is disabled; geyser-only smoke remains available".to_owned());
    } else if !deshred_capability.can_enable {
        warnings.push("deshred is enabled in config but unsupported by this build".to_owned());
    }

    let ready_for_geyser_smoke = blockers.is_empty() && loaded.config.geyser.enabled;
    let ready_for_deshred_smoke = blockers.is_empty()
        && deshred_cfg.enabled
        && deshred_capability.can_enable
        && deshred_capability.endpoint_configured;
    let next_commands = if ready_for_deshred_smoke {
        vec![
            "cargo run -q -p cli -- smoke-geyser-provider --config config/default.toml --duration-seconds 30 --stream-only --dry-run --strict-env".to_owned(),
            "cargo run -q -p cli -- smoke-deshred-provider --config config/default.toml --duration-seconds 30 --stream-only --dry-run --strict-env".to_owned(),
            "cargo run -q -p cli -- collect-first-live-paper --config config/default.toml --duration-seconds 300 --stream-only --dry-run --with-deshred".to_owned(),
        ]
    } else if ready_for_geyser_smoke {
        vec![
            "cargo run -q -p cli -- smoke-geyser-provider --config config/default.toml --duration-seconds 30 --stream-only --dry-run --strict-env".to_owned(),
            "cargo run -q -p cli -- collect-first-live-paper --config config/default.toml --duration-seconds 300 --stream-only --dry-run --geyser-only".to_owned(),
        ]
    } else {
        vec![
            "export GEYSER_ENDPOINT=<redacted-endpoint>".to_owned(),
            "cargo run -q -p cli -- provider-env-precheck --config config/default.toml --strict"
                .to_owned(),
        ]
    };

    let summary = ProviderEnvPrecheckSummary {
        precheck_run_id,
        provider_name: provider_name
            .filter(|value| !value.trim().is_empty())
            .map(ToOwned::to_owned)
            .or_else(|| {
                (!loaded.config.provider.name.trim().is_empty())
                    .then(|| loaded.config.provider.name.clone())
            }),
        endpoint_present,
        endpoint_scheme_valid,
        auth_required,
        auth_present,
        stream_only_valid: validation.passed,
        rpc_budget_zero,
        live_enabled: loaded.config.live.enabled,
        geyser_enabled: loaded.config.geyser.enabled,
        deshred_enabled: deshred_cfg.enabled,
        deshred_required: deshred_cfg.required,
        raw_shred_production_supported,
        ready_for_geyser_smoke,
        ready_for_deshred_smoke,
        provider_compatibility_status: compatibility
            .as_ref()
            .map(|record| record.subscribe_deshred_result.clone()),
        provider_compatibility_confidence: compatibility
            .as_ref()
            .map(|record| record.supports_deshred_confidence.clone()),
        blockers,
        warnings,
        next_commands,
        stream_only_proof,
    };
    Ok((summary, report_root))
}

fn provider_env_precheck_command(
    loaded: &LoadedConfig,
    json_output: bool,
    markdown_output: bool,
    strict: bool,
    provider_name: Option<&str>,
    expect_deshred: bool,
    expect_geyser: bool,
    report_dir: Option<&str>,
) -> Result<()> {
    let (summary, report_root) = provider_env_precheck_summary(
        loaded,
        provider_name,
        expect_deshred,
        expect_geyser,
        report_dir,
    )?;
    let json_path = report_root.join("provider_env_precheck.json");
    let markdown_path = report_root.join("provider_env_precheck.md");
    fs::create_dir_all(&report_root)?;
    fs::write(&json_path, serde_json::to_vec_pretty(&summary)?)?;
    write_report(
        &markdown_path,
        &format!(
            "# Provider Environment Precheck\n\n- precheck_run_id: {}\n- provider_name: {}\n- endpoint_present: {}\n- endpoint_scheme_valid: {}\n- auth_required: {}\n- auth_present: {}\n- stream_only_valid: {}\n- rpc_budget_zero: {}\n- live_enabled: {}\n- geyser_enabled: {}\n- deshred_enabled: {}\n- deshred_required: {}\n- raw_shred_production_supported: {}\n- ready_for_geyser_smoke: {}\n- ready_for_deshred_smoke: {}\n- provider_compatibility_status: {}\n- provider_compatibility_confidence: {}\n- blockers: {:?}\n- warnings: {:?}\n- next_commands: {:?}\n{}\n",
            summary.precheck_run_id,
            summary.provider_name.clone().unwrap_or_default(),
            summary.endpoint_present,
            summary.endpoint_scheme_valid,
            summary.auth_required,
            summary.auth_present,
            summary.stream_only_valid,
            summary.rpc_budget_zero,
            summary.live_enabled,
            summary.geyser_enabled,
            summary.deshred_enabled,
            summary.deshred_required,
            summary.raw_shred_production_supported,
            summary.ready_for_geyser_smoke,
            summary.ready_for_deshred_smoke,
            summary
                .provider_compatibility_status
                .clone()
                .unwrap_or_default(),
            summary
                .provider_compatibility_confidence
                .clone()
                .unwrap_or_default(),
            summary.blockers,
            summary.warnings,
            summary.next_commands,
            render_stream_only_proof(&summary.stream_only_proof),
        ),
    )?;
    if markdown_output && !json_output {
        println!("{}", fs::read_to_string(&markdown_path)?);
    } else {
        println!(
            "{}",
            serde_json::to_string_pretty(&json!({
                "command": "provider-env-precheck",
                "summary": summary.clone(),
                "markdown_path": markdown_path,
                "json_path": json_path,
            }))?
        );
    }
    if strict && !summary.blockers.is_empty() {
        return Err(anyhow!(
            "provider environment precheck failed: {}",
            summary.blockers.join("; ")
        ));
    }
    Ok(())
}

fn signer_env_names() -> &'static [&'static str] {
    &[
        "SOLANA_PRIVATE_KEY",
        "PRIVATE_KEY",
        "KEYPAIR_PATH",
        "SOLANA_KEYPAIR",
    ]
}

fn env_file_permission_warning(path: &Path) -> Option<String> {
    #[cfg(unix)]
    {
        let mode = fs::metadata(path).ok()?.permissions().mode() & 0o777;
        if mode & 0o077 != 0 {
            return Some(format!(
                "env file permissions are too broad ({mode:o}); expected 600 or stricter"
            ));
        }
    }
    None
}

fn env_file_repo_warning(loaded: &LoadedConfig, path: &Path) -> Option<String> {
    let env_path = path.canonicalize().ok()?;
    let workspace = workspace_root_from_config(loaded).canonicalize().ok()?;
    if env_path.starts_with(&workspace) && !env_path.to_string_lossy().contains(".example") {
        Some(
            "env file is inside the repo/workspace; prefer keeping secrets outside the repo tree"
                .to_owned(),
        )
    } else {
        None
    }
}

fn env_bootstrap_check_summary(
    loaded: &LoadedConfig,
    env_file: Option<&str>,
    require_geyser: bool,
    require_r2: bool,
    require_deshred: bool,
) -> Result<(EnvBootstrapCheckSummary, PathBuf)> {
    let report_root = resolve_report_root(
        loaded,
        "env_bootstrap",
        "env_bootstrap_check",
        Some("reports/env_bootstrap"),
    );
    fs::create_dir_all(&report_root)?;
    let env_file_values = if let Some(path) = env_file {
        parse_env_file(&resolve_user_path(loaded, path))?
    } else {
        BTreeMap::new()
    };
    let geyser_endpoint_env = if loaded.config.geyser.endpoint_env.trim().is_empty() {
        "GEYSER_ENDPOINT"
    } else {
        loaded.config.geyser.endpoint_env.as_str()
    };
    let geyser_endpoint = if !loaded.config.geyser.endpoint.trim().is_empty() {
        Some(loaded.config.geyser.endpoint.clone())
    } else {
        env_value_from_sources(geyser_endpoint_env, &env_file_values)
    };
    let geyser_auth_present =
        env_value_present_in_sources(&loaded.config.geyser.auth_token_env, &env_file_values);
    let geyser_endpoint_present = geyser_endpoint.is_some();
    let geyser_endpoint_scheme_valid = geyser_endpoint
        .as_deref()
        .map(valid_endpoint_scheme)
        .unwrap_or(false);
    let stream_only_summary = loaded.stream_only_validation_summary();
    let stream_only_valid = stream_only_summary.passed;
    let live_disabled = !loaded.config.live.enabled && !loaded.config.execution.live_enabled;
    let rpc_budget_zero = loaded.config.rpc.daily_credit_budget == 0
        && loaded.config.rpc.monthly_credit_budget == 0
        && loaded.config.rpc_budget.daily_credit_limit == 0
        && loaded.config.rpc_budget.monthly_credit_limit == 0;
    let r2_required = require_r2 || loaded.config.r2.upload_enabled;
    let r2_account_id_present =
        env_value_present_in_sources(&loaded.config.r2.account_id_env, &env_file_values);
    let r2_access_key_present =
        env_value_present_in_sources(&loaded.config.r2.access_key_id_env, &env_file_values);
    let r2_secret_key_present =
        env_value_present_in_sources(&loaded.config.r2.secret_access_key_env, &env_file_values);
    let r2_dataset_bucket_present = env_value_present_in_sources(
        &loaded.config.r2.buckets.datasets_bucket_env,
        &env_file_values,
    );
    let r2_reports_bucket_present = env_value_present_in_sources(
        &loaded.config.r2.buckets.reports_bucket_env,
        &env_file_values,
    );
    let r2_calibration_bucket_present = env_value_present_in_sources(
        &loaded.config.r2.buckets.calibration_bucket_env,
        &env_file_values,
    );
    let r2_provider_compat_bucket_present = env_value_present_in_sources(
        &loaded.config.r2.buckets.provider_compat_bucket_env,
        &env_file_values,
    );
    let mut blockers = Vec::new();
    let mut warnings = Vec::new();
    if require_geyser && !geyser_endpoint_present {
        blockers.push("missing GEYSER_ENDPOINT-compatible stream endpoint".to_owned());
    }
    if geyser_endpoint_present && !geyser_endpoint_scheme_valid {
        blockers.push("GEYSER endpoint must use http:// or https://".to_owned());
    }
    if loaded.config.geyser.auth_required && !geyser_auth_present {
        blockers.push("required Geyser auth token env var is missing".to_owned());
    }
    if !stream_only_valid {
        blockers.push("stream-only validation failed".to_owned());
    }
    if !live_disabled {
        blockers.push("live trading must remain disabled".to_owned());
    }
    if !rpc_budget_zero {
        blockers.push("RPC budgets must remain zero".to_owned());
    }
    if require_deshred {
        let deshred = loaded.config.ingest.deshred.clone().unwrap_or_default();
        let capability = runtime::inspect_deshred_capability(loaded, None, None);
        if !deshred.enabled {
            blockers.push("deshred is required but disabled in config".to_owned());
        }
        if !capability.can_enable {
            blockers.push(
                capability
                    .reason_if_unsupported
                    .unwrap_or_else(|| "deshred unsupported by current build".to_owned()),
            );
        }
    }
    if r2_required {
        if !r2_account_id_present {
            blockers.push("missing CF_ACCOUNT_ID for R2 upload".to_owned());
        }
        if !r2_access_key_present {
            blockers.push("missing R2_ACCESS_KEY_ID for R2 upload".to_owned());
        }
        if !r2_secret_key_present {
            blockers.push("missing R2_SECRET_ACCESS_KEY for R2 upload".to_owned());
        }
        if !r2_dataset_bucket_present {
            blockers.push("missing R2_DATASET_BUCKET for R2 upload".to_owned());
        }
        if !r2_reports_bucket_present {
            blockers.push("missing R2_REPORTS_BUCKET for R2 upload".to_owned());
        }
        if !r2_calibration_bucket_present {
            blockers.push("missing R2_CALIBRATION_BUCKET for R2 upload".to_owned());
        }
    }
    if let Some(path) = env_file {
        let resolved = resolve_user_path(loaded, path);
        if let Some(warning) = env_file_permission_warning(&resolved) {
            warnings.push(warning);
        }
        if let Some(warning) = env_file_repo_warning(loaded, &resolved) {
            warnings.push(warning);
        }
    }
    if signer_env_names()
        .iter()
        .any(|name| env_value_present_in_sources(name, &env_file_values))
    {
        warnings.push(
            "signer/private-key env vars are present but are not required for paper/autopilot mode"
                .to_owned(),
        );
    }
    let ready_for_provider_smoke = require_geyser
        && geyser_endpoint_present
        && geyser_endpoint_scheme_valid
        && (!loaded.config.geyser.auth_required || geyser_auth_present)
        && stream_only_valid
        && live_disabled
        && rpc_budget_zero;
    let ready_for_r2_upload = r2_required
        && r2_account_id_present
        && r2_access_key_present
        && r2_secret_key_present
        && r2_dataset_bucket_present
        && r2_reports_bucket_present
        && r2_calibration_bucket_present
        && stream_only_valid
        && live_disabled
        && rpc_budget_zero;
    let next_commands = if ready_for_r2_upload && ready_for_provider_smoke {
        vec![
            "cargo run -q -p cli -- smoke-r2-upload --config config/local.toml --verify".to_owned(),
            "cargo run -q -p cli -- smoke-geyser-provider --config config/local.toml --duration-seconds 30 --stream-only --dry-run --strict-env".to_owned(),
        ]
    } else if ready_for_r2_upload {
        vec![
            "cargo run -q -p cli -- smoke-r2-upload --config config/local.toml --dry-run"
                .to_owned(),
            "cargo run -q -p cli -- inspect-r2 --config config/local.toml".to_owned(),
        ]
    } else {
        vec![
            "Set the required env vars in a local env file outside the repo.".to_owned(),
            "cargo run -q -p cli -- env-bootstrap-check --config config/default.toml --strict"
                .to_owned(),
        ]
    };
    Ok((
        EnvBootstrapCheckSummary {
            geyser_endpoint_present,
            geyser_endpoint_scheme_valid,
            geyser_endpoint_host_hash: endpoint_host_hash(geyser_endpoint.as_deref()),
            geyser_auth_present,
            r2_account_id_present,
            r2_access_key_present,
            r2_secret_key_present,
            r2_dataset_bucket_present,
            r2_reports_bucket_present,
            r2_calibration_bucket_present,
            r2_provider_compat_bucket_present,
            stream_only_valid,
            live_disabled,
            rpc_budget_zero,
            ready_for_provider_smoke,
            ready_for_r2_upload,
            blockers,
            warnings,
            next_commands,
        },
        report_root,
    ))
}

fn env_bootstrap_check_command(
    loaded: &LoadedConfig,
    env_file: Option<&str>,
    require_geyser: bool,
    require_r2: bool,
    require_deshred: bool,
    json_output: bool,
    markdown_output: bool,
    _redacted: bool,
    strict: bool,
) -> Result<()> {
    let (summary, report_root) = env_bootstrap_check_summary(
        loaded,
        env_file,
        require_geyser,
        require_r2,
        require_deshred,
    )?;
    let json_path = report_root.join("env_bootstrap_check.json");
    let markdown_path = report_root.join("env_bootstrap_check.md");
    fs::write(&json_path, serde_json::to_vec_pretty(&summary)?)?;
    write_report(
        &markdown_path,
        &format!(
            "# Environment Bootstrap Check\n\n- geyser_endpoint_present: {}\n- geyser_endpoint_scheme_valid: {}\n- geyser_endpoint_host_hash: {}\n- geyser_auth_present: {}\n- r2_account_id_present: {}\n- r2_access_key_present: {}\n- r2_secret_key_present: {}\n- r2_dataset_bucket_present: {}\n- r2_reports_bucket_present: {}\n- r2_calibration_bucket_present: {}\n- r2_provider_compat_bucket_present: {}\n- stream_only_valid: {}\n- live_disabled: {}\n- rpc_budget_zero: {}\n- ready_for_provider_smoke: {}\n- ready_for_r2_upload: {}\n- blockers: {:?}\n- warnings: {:?}\n- next_commands: {:?}\n",
            summary.geyser_endpoint_present,
            summary.geyser_endpoint_scheme_valid,
            summary.geyser_endpoint_host_hash,
            summary.geyser_auth_present,
            summary.r2_account_id_present,
            summary.r2_access_key_present,
            summary.r2_secret_key_present,
            summary.r2_dataset_bucket_present,
            summary.r2_reports_bucket_present,
            summary.r2_calibration_bucket_present,
            summary.r2_provider_compat_bucket_present,
            summary.stream_only_valid,
            summary.live_disabled,
            summary.rpc_budget_zero,
            summary.ready_for_provider_smoke,
            summary.ready_for_r2_upload,
            summary.blockers,
            summary.warnings,
            summary.next_commands,
        ),
    )?;
    if markdown_output && !json_output {
        println!("{}", fs::read_to_string(&markdown_path)?);
    } else {
        println!(
            "{}",
            serde_json::to_string_pretty(&json!({
                "command": "env-bootstrap-check",
                "summary": summary,
                "json_path": json_path.display().to_string(),
                "markdown_path": markdown_path.display().to_string(),
            }))?
        );
    }
    if strict && !summary.blockers.is_empty() {
        return Err(anyhow!(
            "environment bootstrap check failed: {}",
            summary.blockers.join("; ")
        ));
    }
    Ok(())
}

fn collect_secret_scan_files(root: &Path, output: &mut Vec<PathBuf>) {
    let Ok(entries) = fs::read_dir(root) else {
        return;
    };
    for entry in entries.filter_map(|entry| entry.ok()) {
        let path = entry.path();
        let name = path
            .file_name()
            .and_then(|value| value.to_str())
            .unwrap_or_default();
        if matches!(name, "target" | ".git") {
            continue;
        }
        if path.is_dir() {
            collect_secret_scan_files(&path, output);
        } else {
            output.push(path);
        }
    }
}

fn secret_scan_patterns() -> Vec<(&'static str, String)> {
    vec![
        ("cloudflare_token_prefix", ["cf", "k_"].concat()),
        ("rpc_api_key_query", ["?", "api", "-", "key", "="].concat()),
        (
            "erpc_hostname_literal",
            [".", "erpc", ".", "global"].concat(),
        ),
        ("shell_password_label", ["Pass", "word", ":"].concat()),
        ("shell_username_label", ["User", "name", ":"].concat()),
        ("shell_ip_label", ["I", "P", ":"].concat()),
        (
            "helius_host_literal",
            ["mainnet", ".", "helius", "-", "rpc", ".", "com"].concat(),
        ),
    ]
}

fn secret_scan_env_names() -> &'static [&'static str] {
    &[
        "GEYSER_ENDPOINT",
        "GEYSER_AUTH_TOKEN",
        "SHREDSTREAM_ENDPOINT",
        "SHREDSTREAM_AUTH_TOKEN",
        "CF_ACCOUNT_ID",
        "R2_ACCESS_KEY_ID",
        "R2_SECRET_ACCESS_KEY",
        "R2_ENDPOINT",
        "RPC_URL",
    ]
}

fn scan_secrets_command(loaded: &LoadedConfig, env_file: Option<&str>) -> Result<()> {
    let scan_id = derived_run_id("scan-secrets");
    let report_root = resolve_report_root(
        loaded,
        "scan_secrets",
        &scan_id,
        Some("reports/scan_secrets"),
    );
    fs::create_dir_all(&report_root)?;
    let mut warnings = Vec::new();
    let env_file_values = if let Some(path) = env_file {
        let resolved = resolve_user_path(loaded, path);
        if let Some(warning) = env_file_permission_warning(&resolved) {
            warnings.push(warning);
        }
        if let Some(warning) = env_file_repo_warning(loaded, &resolved) {
            warnings.push(warning);
        }
        parse_env_file(&resolved)?
    } else {
        BTreeMap::new()
    };
    let env_values = secret_scan_env_names()
        .iter()
        .filter_map(|name| {
            env_value_from_sources(name, &env_file_values)
                .filter(|value| value.len() >= 8)
                .map(|value| ((*name).to_owned(), value))
        })
        .collect::<Vec<_>>();
    let workspace = workspace_root_from_config(loaded);
    let scan_roots = [
        workspace.join("config"),
        workspace.join("docs"),
        workspace.join("deploy"),
        workspace.join("crates"),
        workspace.join("fixtures"),
        workspace.join("reports"),
        workspace.join("data"),
    ];
    let scanned_roots = scan_roots
        .iter()
        .map(|path| path.display().to_string())
        .collect::<Vec<_>>();
    let mut files = Vec::new();
    for root in &scan_roots {
        collect_secret_scan_files(root, &mut files);
    }
    files.sort();
    let mut files_scanned = 0usize;
    let mut skipped_binary_or_large_files = 0usize;
    let mut pattern_hits = Vec::new();
    let mut env_value_hits = Vec::new();
    let pattern_specs = secret_scan_patterns();
    for path in files {
        let Ok(bytes) = fs::read(&path) else {
            continue;
        };
        if bytes.len() > 5 * 1024 * 1024 || bytes.contains(&0) {
            skipped_binary_or_large_files += 1;
            continue;
        }
        files_scanned += 1;
        let content = String::from_utf8_lossy(&bytes);
        for (label, pattern) in &pattern_specs {
            if content.contains(pattern) {
                pattern_hits.push(SecretScanHit {
                    path: path.display().to_string(),
                    indicator: (*label).to_owned(),
                    source: "pattern".to_owned(),
                });
            }
        }
        for (name, value) in &env_values {
            if content.contains(value) {
                env_value_hits.push(SecretScanHit {
                    path: path.display().to_string(),
                    indicator: name.clone(),
                    source: "env_value".to_owned(),
                });
            }
        }
    }
    pattern_hits.sort_by(|left, right| {
        left.path
            .cmp(&right.path)
            .then_with(|| left.indicator.cmp(&right.indicator))
    });
    env_value_hits.sort_by(|left, right| {
        left.path
            .cmp(&right.path)
            .then_with(|| left.indicator.cmp(&right.indicator))
    });
    let passed = pattern_hits.is_empty() && env_value_hits.is_empty();
    let summary = SecretScanSummary {
        scan_id: scan_id.clone(),
        env_file_provided: env_file.is_some(),
        env_file_exists: env_file
            .map(|path| resolve_user_path(loaded, path).exists())
            .unwrap_or(false),
        files_scanned,
        skipped_binary_or_large_files,
        pattern_hits,
        env_value_hits,
        warnings,
        scanned_roots,
        passed,
    };
    let json_path = report_root.join("scan_secrets.json");
    let markdown_path = report_root.join("scan_secrets.md");
    fs::write(&json_path, serde_json::to_vec_pretty(&summary)?)?;
    write_report(
        &markdown_path,
        &format!(
            "# Secret Scan\n\n- scan_id: {}\n- env_file_provided: {}\n- env_file_exists: {}\n- files_scanned: {}\n- skipped_binary_or_large_files: {}\n- pattern_hits: {:?}\n- env_value_hits: {:?}\n- warnings: {:?}\n- scanned_roots: {:?}\n- passed: {}\n",
            summary.scan_id,
            summary.env_file_provided,
            summary.env_file_exists,
            summary.files_scanned,
            summary.skipped_binary_or_large_files,
            summary.pattern_hits,
            summary.env_value_hits,
            summary.warnings,
            summary.scanned_roots,
            summary.passed,
        ),
    )?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "scan-secrets",
            "summary": summary,
            "json_path": json_path.display().to_string(),
            "markdown_path": markdown_path.display().to_string(),
        }))?
    );
    if !passed {
        return Err(anyhow!(
            "secret scan detected secret-like content in workspace paths"
        ));
    }
    Ok(())
}

async fn execute_geyser_smoke(
    loaded: &LoadedConfig,
    options: &SmokeGeyserCommandOptions,
) -> Result<GeyserSmokeExecutionResult> {
    loaded.validate_stream_only()?;
    let smoke_run_id = derived_run_id("geyser-smoke");
    let report_root = resolve_report_root(
        loaded,
        "geyser_smoke",
        &smoke_run_id,
        options.report_dir.as_deref(),
    );
    let stream_only_proof = wrapper_stream_only_summary(loaded, &report_root)?;
    let endpoint_present = geyser_endpoint_value(loaded)
        .map(|value| !value.trim().is_empty())
        .unwrap_or(false);
    let auth_present = env_value_present(&loaded.config.geyser.auth_token_env);
    if let Some(endpoint) = geyser_endpoint_value(loaded) {
        if !valid_endpoint_scheme(&endpoint) {
            return Err(anyhow!(
                "geyser endpoint must start with http:// or https://"
            ));
        }
    }
    if options.strict_env && !endpoint_present && !options.allow_missing_endpoint_report {
        return Err(anyhow!(
            "geyser endpoint missing: expected non-empty {}",
            if loaded.config.geyser.endpoint_env.trim().is_empty() {
                "GEYSER_ENDPOINT"
            } else {
                loaded.config.geyser.endpoint_env.as_str()
            }
        ));
    }
    if loaded.config.geyser.auth_required && !auth_present {
        return Err(anyhow!(
            "geyser auth token missing: expected non-empty {}",
            loaded.config.geyser.auth_token_env
        ));
    }

    let summary = smoke_geyser_provider(
        loaded,
        GeyserProviderSmokeOptions {
            duration_seconds: options.duration_seconds,
            max_updates: options.max_updates,
            strict: options.strict_env,
        },
    )
    .await?;
    let json_path = report_root.join("geyser_provider_smoke.json");
    let markdown_path = report_root.join("geyser_provider_smoke.md");
    let operator_path = report_root.join("operator_next_steps.md");
    fs::create_dir_all(&report_root)?;
    let result = GeyserSmokeExecutionResult {
        smoke_run_id: smoke_run_id.clone(),
        provider_name: options
            .provider_name
            .clone()
            .filter(|value| !value.trim().is_empty())
            .or_else(|| {
                (!loaded.config.provider.name.trim().is_empty())
                    .then(|| loaded.config.provider.name.clone())
            }),
        endpoint_present,
        auth_present,
        summary: summary.clone(),
        report_root: report_root.display().to_string(),
        markdown_report_path: Some(markdown_path.display().to_string()),
        json_report_path: Some(json_path.display().to_string()),
        operator_runbook_path: Some(operator_path.display().to_string()),
        stream_only_proof,
    };
    fs::write(&json_path, serde_json::to_vec_pretty(&result)?)?;
    write_report(
        &markdown_path,
        &format!(
            "# Geyser Provider Smoke\n\n- smoke_run_id: {}\n- provider_name: {}\n- endpoint_configured: {}\n- auth_configured: {}\n- provider_status: {}\n- connected: {}\n- duration_seconds: {}\n- transaction_updates: {}\n- account_updates: {}\n- slot_updates: {}\n- block_updates: {}\n- block_meta_updates: {}\n- pump_relevant_transactions: {}\n- pump_create_decoded: {}\n- pump_buy_decoded: {}\n- pump_sell_decoded: {}\n- bonding_curve_updates: {}\n- holder_updates: {}\n- funding_events: {}\n- decode_errors: {}\n- unknown_instructions: {}\n- no_live_orders: {}\n- rpc_calls_used: {}\n- errors: {:?}\n- limitations: {:?}\n{}\n",
            result.smoke_run_id,
            result.provider_name.clone().unwrap_or_default(),
            result.summary.endpoint_configured,
            result.summary.auth_configured,
            result.summary.provider_status,
            result.summary.connected,
            result.summary.duration_seconds,
            result.summary.transaction_updates,
            result.summary.account_updates,
            result.summary.slot_updates,
            result.summary.block_updates,
            result.summary.block_meta_updates,
            result.summary.pump_relevant_transactions,
            result.summary.pump_create_decoded,
            result.summary.pump_buy_decoded,
            result.summary.pump_sell_decoded,
            result.summary.bonding_curve_updates,
            result.summary.holder_updates,
            result.summary.funding_events,
            result.summary.decode_errors,
            result.summary.unknown_instructions,
            result.summary.no_live_orders,
            result.summary.rpc_calls_used,
            result.summary.errors,
            result.summary.limitations,
            render_stream_only_proof(&result.stream_only_proof),
        ),
    )?;
    write_report(
        &operator_path,
        &format!(
            "# Operator Next Steps\n\n- sanitized_command: `cargo run -q -p cli -- smoke-geyser-provider --config config/default.toml --duration-seconds {} --stream-only --dry-run`\n- expected_env_vars: {} {}\n- endpoint_env_present: {}\n- auth_env_present: {}\n- provider_status: {}\n- next_recommended_action: {}\n",
            options.duration_seconds,
            if loaded.config.geyser.endpoint_env.trim().is_empty() {
                "GEYSER_ENDPOINT"
            } else {
                loaded.config.geyser.endpoint_env.as_str()
            },
            loaded.config.geyser.auth_token_env,
            endpoint_present,
            auth_present,
            result.summary.provider_status,
            match result.summary.provider_status.as_str() {
                "not_attempted_missing_endpoint" =>
                    "Set the stream endpoint and rerun smoke-geyser-provider in strict mode.",
                "auth_rejected" => "Fix Geyser auth configuration and rerun the smoke command.",
                "updates_received" => "Proceed to smoke-streams or collect-first-live-paper.",
                "connected_zero_updates" =>
                    "Retry during a busier market window or with a longer duration.",
                _ => "Inspect the smoke report and provider logs before the next attempt.",
            },
        ),
    )?;
    Ok(result)
}

async fn smoke_geyser_provider_command(
    loaded: &LoadedConfig,
    duration_seconds: u64,
    max_updates: Option<usize>,
    provider_name: Option<&str>,
    strict_env: bool,
    allow_missing_endpoint_report: bool,
    report_dir: Option<&str>,
    json_output: bool,
    markdown_output: bool,
    _pump_only: bool,
    _no_paper: bool,
    _dry_run: bool,
) -> Result<()> {
    let result = execute_geyser_smoke(
        loaded,
        &SmokeGeyserCommandOptions {
            duration_seconds,
            max_updates,
            provider_name: provider_name.map(ToOwned::to_owned),
            strict_env,
            allow_missing_endpoint_report,
            report_dir: report_dir.map(ToOwned::to_owned),
        },
    )
    .await?;
    if markdown_output && !json_output {
        if let Some(path) = result.markdown_report_path.as_deref() {
            println!("{}", fs::read_to_string(path)?);
        }
    } else {
        println!("{}", serde_json::to_string_pretty(&result)?);
    }
    if result.summary.provider_status == "not_attempted_missing_endpoint"
        && !allow_missing_endpoint_report
    {
        return Err(anyhow!(
            "geyser provider smoke not attempted because GEYSER_ENDPOINT was not configured"
        ));
    }
    if matches!(
        result.summary.provider_status.as_str(),
        "auth_rejected" | "connection_failed" | "stream_error"
    ) && strict_env
    {
        return Err(anyhow!(
            "geyser provider smoke failed with status {}",
            result.summary.provider_status
        ));
    }
    Ok(())
}

async fn execute_deshred_smoke(
    loaded: &LoadedConfig,
    options: &SmokeDeshredCommandOptions,
) -> Result<DeshredSmokeExecutionResult> {
    if options.no_paper && options.paper {
        return Err(anyhow!("cannot combine --paper and --no-paper"));
    }
    let mut loaded_for_smoke = loaded.clone();
    {
        let deshred = loaded_for_smoke
            .config
            .ingest
            .deshred
            .get_or_insert_with(Default::default);
        deshred.endpoint_env = options.geyser_endpoint_env.clone();
        deshred.auth_token_env = options.auth_token_env.clone();
        deshred.auth_metadata_key = options.auth_metadata_key.clone();
        if let Some(connection_timeout_ms) = options.connection_timeout_ms {
            deshred.connect_timeout_ms = connection_timeout_ms;
        }
    }
    let deshred_config = loaded_for_smoke
        .config
        .ingest
        .deshred
        .clone()
        .unwrap_or_default();

    let smoke_id = derived_run_id("deshred-smoke");
    let endpoint_present = deshred_endpoint_value(&loaded_for_smoke)
        .map(|value| !value.trim().is_empty())
        .unwrap_or(false);
    if let Some(endpoint) = deshred_endpoint_value(&loaded_for_smoke) {
        if !valid_endpoint_scheme(&endpoint) {
            return Err(anyhow!(
                "deshred endpoint must start with http:// or https://"
            ));
        }
    }
    let auth_present = env_value_present(&options.auth_token_env);
    if (options.strict_env || options.strict)
        && !endpoint_present
        && !options.allow_missing_endpoint_report
    {
        return Err(anyhow!(
            "deshred endpoint missing: expected non-empty {}",
            options.geyser_endpoint_env
        ));
    }
    if deshred_config.auth_required && !auth_present {
        return Err(anyhow!(
            "deshred auth token missing: expected non-empty {}",
            options.auth_token_env
        ));
    }
    if deshred_config.auth_required && options.auth_metadata_key.trim().is_empty() {
        return Err(anyhow!(
            "deshred auth metadata key is required when auth_required=true"
        ));
    }

    let capability = runtime::inspect_deshred_capability(&loaded_for_smoke, None, None);
    let run_paper_mode = !options.no_paper && (options.paper || options.geyser_confirmation_stream);
    let summary = if run_paper_mode && capability.can_enable && capability.endpoint_configured {
        let mut loaded_for_run = loaded_for_smoke.clone();
        loaded_for_run.config.environment.run_id = smoke_id.clone();
        let resolved = resolved_config(&loaded_for_run, Some(RuntimeMode::LiveDataPaper))?;
        let mut supervisor = Supervisor::new(resolved)?;
        let runtime_summary = supervisor
            .run_live_data_paper(LiveRunOptions {
                max_events: options.max_updates,
                duration: Some(time::Duration::seconds(
                    options.duration_seconds.max(1) as i64
                )),
                geyser_only: false,
                no_shred: options.no_shred,
                dry_run: true,
                with_deshred: true,
                require_deshred: options.require_deshred,
                run_id: Some(smoke_id.clone()),
                ..LiveRunOptions::default()
            })
            .await?;
        let store = storage_engine(&loaded_for_run)?;
        let events = store.read_normalized_events_filtered(Some(&runtime_summary.run_id), None)?;
        let geyser_reconciliations = events
            .iter()
            .filter(|record| {
                matches!(
                    &record.record.payload,
                    EventPayload::ShredSellIntentResolved(payload)
                        if payload.source == common::EarlyIntentSource::DeshredPreExecution
                )
            })
            .count() as u64;
        runtime::DeshredProviderSmokeSummary {
            endpoint_configured: capability.endpoint_configured,
            auth_configured: capability.auth_configured,
            auth_metadata_key_configured: !options.auth_metadata_key.trim().is_empty(),
            proto_support: capability.supported_by_proto,
            client_support: capability.supported_by_client,
            provider_status: if runtime_summary.health.deshred_events_received > 0 {
                "updates_received".to_owned()
            } else if runtime_summary.health.deshred_connected {
                "zero_updates".to_owned()
            } else {
                runtime_summary.health.deshred_provider_status.clone()
            },
            duration_seconds: options.duration_seconds,
            updates_received: runtime_summary.health.deshred_events_received,
            tentative_transactions_decoded: runtime_summary.health.deshred_transactions_decoded,
            pump_relevant_transactions: runtime_summary.health.deshred_transactions_decoded,
            tentative_sells_detected: runtime_summary.health.deshred_tentative_sells_total,
            decoded_sell_instructions: runtime_summary.health.deshred_tentative_sells_total,
            malicious_warnings: runtime_summary.health.deshred_malicious_warnings_total,
            emergency_exits_armed: runtime_summary.health.deshred_emergency_exits_armed_total,
            paper_emergency_exits_triggered: runtime_summary
                .health
                .deshred_emergency_exits_triggered_total,
            geyser_reconciliations,
            errors: Vec::new(),
            limitations: vec![
                "deshred_is_pre_execution_tentative_only".to_owned(),
                "geyser_account_effects_remain_canonical_truth".to_owned(),
                "raw_production_shred_decoder_remains_fail_closed".to_owned(),
            ],
            no_live_orders: true,
            rpc_calls_used: 0,
        }
    } else {
        smoke_deshred_provider(
            &loaded_for_smoke,
            DeshredProviderSmokeOptions {
                duration_seconds: options.duration_seconds,
                max_updates: options.max_updates,
                require_deshred: options.require_deshred && !options.allow_missing_endpoint_report,
                strict: options.strict || options.strict_env,
            },
        )
        .await?
    };
    if let Some(limit) = options.max_errors {
        if summary.errors.len() > limit {
            return Err(anyhow!(
                "deshred smoke exceeded max errors: {} > {}",
                summary.errors.len(),
                limit
            ));
        }
    }

    let report_root = resolve_report_root(
        &loaded_for_smoke,
        "deshred_smoke",
        &smoke_id,
        options.report_dir.as_deref(),
    );
    let stream_only_proof = wrapper_stream_only_summary(&loaded_for_smoke, &report_root)?;
    let redacted = redacted_deshred_config(&loaded_for_smoke, options.provider_name.as_deref());
    let markdown_report_path = options
        .write_report
        .then(|| report_root.join("deshred_provider_smoke.md"));
    let json_report_path = options
        .write_report
        .then(|| report_root.join("deshred_provider_smoke.json"));
    let operator_runbook_path = options
        .write_report
        .then(|| report_root.join("operator_next_steps.md"));
    let result = DeshredSmokeExecutionResult {
        smoke_run_id: smoke_id.clone(),
        provider_name: options
            .provider_name
            .clone()
            .filter(|value| !value.trim().is_empty())
            .or_else(|| {
                (!loaded_for_smoke.config.provider.name.trim().is_empty())
                    .then(|| loaded_for_smoke.config.provider.name.clone())
            }),
        endpoint_env: options.geyser_endpoint_env.clone(),
        endpoint_present,
        auth_token_env: options.auth_token_env.clone(),
        auth_present,
        strict_env: options.strict_env,
        redacted_config: redacted.clone(),
        capability: capability.clone(),
        summary: summary.clone(),
        report_root: report_root.display().to_string(),
        markdown_report_path: markdown_report_path
            .as_ref()
            .map(|path| path.display().to_string()),
        json_report_path: json_report_path
            .as_ref()
            .map(|path| path.display().to_string()),
        operator_runbook_path: operator_runbook_path
            .as_ref()
            .map(|path| path.display().to_string()),
        stream_only_proof,
    };

    if options.write_report {
        fs::create_dir_all(&report_root)?;
        let payload = serde_json::to_value(&result)?;
        if let Some(path) = &json_report_path {
            fs::write(path, serde_json::to_vec_pretty(&payload)?)?;
        }
        if let Some(path) = &markdown_report_path {
            write_report(
                path,
                &format!(
                    "# Deshred Provider Smoke\n\n- smoke_run_id: {}\n- provider_name: {}\n- endpoint_configured: {}\n- auth_configured: {}\n- proto_support: {}\n- client_support: {}\n- provider_status: {}\n- duration_seconds: {}\n- updates_received: {}\n- tentative_transactions_decoded: {}\n- pump_relevant_transactions: {}\n- tentative_sells_detected: {}\n- malicious_warnings: {}\n- emergency_exits_armed: {}\n- paper_emergency_exits_triggered: {}\n- geyser_reconciliations: {}\n- no_live_orders: {}\n- rpc_calls_used: {}\n- errors: {:?}\n- limitations: {:?}\n{}\n",
                    result.smoke_run_id,
                    result.provider_name.clone().unwrap_or_default(),
                    result.summary.endpoint_configured,
                    result.summary.auth_configured,
                    result.summary.proto_support,
                    result.summary.client_support,
                    result.summary.provider_status,
                    result.summary.duration_seconds,
                    result.summary.updates_received,
                    result.summary.tentative_transactions_decoded,
                    result.summary.pump_relevant_transactions,
                    result.summary.tentative_sells_detected,
                    result.summary.malicious_warnings,
                    result.summary.emergency_exits_armed,
                    result.summary.paper_emergency_exits_triggered,
                    result.summary.geyser_reconciliations,
                    result.summary.no_live_orders,
                    result.summary.rpc_calls_used,
                    result.summary.errors,
                    result.summary.limitations,
                    render_stream_only_proof(&result.stream_only_proof),
                ),
            )?;
        }
        if let Some(path) = &operator_runbook_path {
            let command = format!(
                "cargo run -q -p cli -- smoke-deshred-provider --config config/default.toml --duration-seconds {} --dry-run",
                options.duration_seconds
            );
            write_report(
                path,
                &render_operator_runbook(
                    &command,
                    &result.endpoint_env,
                    result.endpoint_present,
                    &result.auth_token_env,
                    result.auth_present,
                    &result.summary,
                ),
            )?;
        }
    }

    Ok(result)
}

#[allow(clippy::too_many_arguments)]
async fn smoke_deshred_provider_command(
    loaded: &LoadedConfig,
    duration_seconds: u64,
    max_updates: Option<usize>,
    geyser_endpoint_env: &str,
    auth_token_env: &str,
    auth_metadata_key: &str,
    require_deshred: bool,
    geyser_confirmation_stream: bool,
    _pump_only: bool,
    write_report_enabled: bool,
    no_paper: bool,
    paper: bool,
    no_shred: bool,
    strict: bool,
    strict_env: bool,
    allow_missing_endpoint_report: bool,
    allow_unsupported: bool,
    provider_name: Option<&str>,
    report_dir: Option<&str>,
    json_output: bool,
    markdown_output: bool,
    print_redacted_config: bool,
    max_errors: Option<usize>,
    connection_timeout_ms: Option<u64>,
    _dry_run: bool,
) -> Result<()> {
    let result = execute_deshred_smoke(
        loaded,
        &SmokeDeshredCommandOptions {
            duration_seconds,
            max_updates,
            geyser_endpoint_env: geyser_endpoint_env.to_owned(),
            auth_token_env: auth_token_env.to_owned(),
            auth_metadata_key: auth_metadata_key.to_owned(),
            require_deshred,
            geyser_confirmation_stream,
            write_report: write_report_enabled,
            no_paper,
            paper,
            no_shred,
            strict,
            strict_env,
            allow_missing_endpoint_report,
            provider_name: provider_name.map(ToOwned::to_owned),
            report_dir: report_dir.map(ToOwned::to_owned),
            max_errors,
            connection_timeout_ms,
        },
    )
    .await?;
    append_provider_compatibility_record(
        loaded,
        provider_compatibility_record_from_smoke(
            loaded,
            &result.capability,
            &result.summary,
            Some(&result.smoke_run_id),
            None,
            result.provider_name.as_deref(),
        ),
    )?;
    let mut payload = serde_json::to_value(&result)?;
    if !print_redacted_config {
        if let Some(object) = payload.as_object_mut() {
            object.remove("redacted_config");
        }
    }
    if markdown_output && !json_output {
        if let Some(path) = result.markdown_report_path.as_deref() {
            println!("{}", fs::read_to_string(path)?);
        } else {
            println!("{}", serde_json::to_string_pretty(&payload)?);
        }
    } else {
        println!("{}", serde_json::to_string_pretty(&payload)?);
    }
    if result.summary.provider_status == "not_attempted_missing_endpoint"
        && !allow_missing_endpoint_report
    {
        return Err(anyhow!(
            "deshred provider smoke not attempted because {} was not configured",
            result.endpoint_env
        ));
    }
    if matches!(
        result.summary.provider_status.as_str(),
        "unsupported_build" | "unimplemented"
    ) && !(allow_unsupported || allow_missing_endpoint_report)
    {
        return Err(anyhow!(
            "deshred provider smoke failed with status {}",
            result.summary.provider_status
        ));
    }
    if matches!(
        result.summary.provider_status.as_str(),
        "auth_rejected" | "connection_failed" | "stream_error"
    ) && (strict || strict_env || require_deshred)
    {
        return Err(anyhow!(
            "deshred provider smoke failed with status {}",
            result.summary.provider_status
        ));
    }
    Ok(())
}

fn inspect_provider_compatibility(loaded: &LoadedConfig, _json_output: bool) -> Result<()> {
    let records = load_provider_compatibility_records(loaded)?;
    let latest = records.last().cloned();
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "inspect-provider-compatibility",
            "path": provider_compatibility_path(loaded),
            "record_count": records.len(),
            "latest": latest,
            "records": records,
        }))?
    );
    Ok(())
}

fn export_provider_compatibility(loaded: &LoadedConfig, format: &str) -> Result<()> {
    if !format.eq_ignore_ascii_case("csv") {
        return Err(anyhow!(
            "provider compatibility export format {format} is not implemented; use --format csv"
        ));
    }
    let records = load_provider_compatibility_records(loaded)?;
    let path = storage_engine(loaded)?
        .layout()
        .report_dir
        .join("provider_compatibility.csv");
    write_provider_compatibility_csv(loaded, &path, &records)?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "export-provider-compatibility",
            "format": "csv",
            "path": path,
            "row_count": records.len(),
        }))?
    );
    Ok(())
}

async fn export_rpc_ledger(
    loaded: &LoadedConfig,
    run_id: Option<&str>,
    latest_run: bool,
    latest_source_run: bool,
) -> Result<()> {
    let selected_run_id = if let Some(run_id) = run_id {
        run_id.to_owned()
    } else {
        select_run_id(
            loaded,
            RunSelection {
                latest_run: latest_run || !latest_source_run,
                latest_source_run,
                ..Default::default()
            },
            false,
        )
        .await?
    };
    let store = storage_engine(loaded)?;
    let entries = load_rpc_ledger_entries(&store, &selected_run_id)?;
    let rows = entries
        .iter()
        .map(|entry| RpcLedgerRow {
            run_id: entry.request.run_id.clone(),
            timestamp: entry.request.timestamp,
            category: json_enum_label(&entry.request.category),
            method: entry.request.method.clone(),
            caller: entry.request.caller_module.clone(),
            reason: entry
                .denial_reason
                .clone()
                .unwrap_or_else(|| format!("{:?}", entry.request.reason)),
            allowed: entry.allowed,
            denied: entry.denied,
            network_touched: entry.network_touched,
            estimated_credits: entry.request.estimated_provider_credit_cost,
            actual_credits: entry
                .request
                .actual_provider_credit_cost
                .unwrap_or_default(),
            stream_only_enabled: entry.stream_only_enabled,
        })
        .collect::<Vec<_>>();
    let path = store
        .run_report_dir(&selected_run_id)
        .join("rpc_ledger.csv");
    write_rpc_ledger_csv(&path, &rows)?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "export-rpc-ledger",
            "run_id": selected_run_id,
            "path": path,
            "row_count": rows.len(),
            "allowed_network_rpc_rows": rows.iter().filter(|row| row.allowed && row.network_touched).count(),
            "denied_rows": rows.iter().filter(|row| row.denied).count(),
        }))?
    );
    Ok(())
}

fn provider_compatibility_report(loaded: &LoadedConfig) -> Result<()> {
    let records = load_provider_compatibility_records(loaded)?;
    let latest = records.last().cloned();
    let report_root = storage_engine(loaded)?
        .layout()
        .report_dir
        .join("provider_compatibility");
    fs::create_dir_all(&report_root)?;
    let report_path = report_root.join("provider_compatibility.md");
    let mut by_provider = BTreeMap::<String, Vec<&ProviderCompatibilityRecord>>::new();
    for record in &records {
        let key = format!(
            "{}:{}",
            record
                .provider_name
                .clone()
                .unwrap_or_else(|| "unknown".to_owned()),
            record.endpoint_host_hash
        );
        by_provider.entry(key).or_default().push(record);
    }
    let mut markdown = String::from("# Provider Compatibility\n\n");
    markdown.push_str(&format!("- record_count: {}\n", records.len()));
    if let Some(latest) = &latest {
        markdown.push_str(&format!(
            "- latest_status: {}\n- latest_confidence: {}\n\n",
            latest.subscribe_deshred_result, latest.supports_deshred_confidence
        ));
    }
    for (key, entries) in by_provider {
        let latest_entry = entries.last().copied();
        markdown.push_str(&format!("## {}\n", key));
        markdown.push_str(&format!("- attempts: {}\n", entries.len()));
        if let Some(entry) = latest_entry {
            markdown.push_str(&format!(
                "- latest_status: {}\n- confidence: {}\n- max_updates_observed: {}\n- max_duration_connected_ms: {}\n- status_history: {:?}\n\n",
                entry.subscribe_deshred_result,
                entry.supports_deshred_confidence,
                entry.max_updates_observed,
                entry.max_duration_connected_ms,
                entry.provider_status_history,
            ));
        }
    }
    write_report(&report_path, &markdown)?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "provider-compatibility-report",
            "path": report_path,
            "record_count": records.len(),
        }))?
    );
    Ok(())
}

fn benchmark_decoders(loaded: &LoadedConfig) -> Result<()> {
    let registry = DecoderRegistry::from_config(loaded)?;
    let sample = json!({
        "config_hash": loaded.hash,
        "idls_loaded": loaded.config.pump.idl_paths.len(),
        "sample_status": registry.decode_instruction(&[]).is_ok(),
    });
    println!("{}", serde_json::to_string_pretty(&sample)?);
    Ok(())
}

async fn run_live(loaded: &LoadedConfig) -> Result<()> {
    if !loaded.config.live.enabled {
        return Err(anyhow!(
            "live trading remains disabled by default; set live.enabled=true explicitly to reach guarded readiness checks"
        ));
    }
    let resolved = resolved_config(loaded, Some(RuntimeMode::GuardedLiveEnabled))?;
    let mut supervisor = Supervisor::new(resolved)?;
    let summary = supervisor.live_data_readiness()?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "run-live",
            "config_hash": loaded.hash,
            "idl_hash": combined_idl_hash(loaded)?,
            "status": "guarded_readiness_only",
            "mode": format!("{:?}", summary.mode),
            "health": summary.health,
            "safety": summary.safety,
        }))?
    );
    Ok(())
}

#[allow(clippy::too_many_arguments)]
async fn run_paper(
    loaded: &LoadedConfig,
    from_store: bool,
    live_data: bool,
    latest_run: bool,
    latest_any_run: bool,
    latest_source_run: bool,
    latest_paper_run: bool,
    latest_live_paper_run: bool,
    latest_mocked_live_run: bool,
    latest_mocked_early_intent_run: bool,
    latest_shred_exit_run: bool,
    latest_analysis_run: bool,
    latest_report_run: bool,
    latest_backtest_run: bool,
    latest_shred_exit_backtest_run: bool,
    run_id: Option<&str>,
    run_kind: Option<&str>,
    run_role: Option<&str>,
    scenario: Option<&str>,
    max_events: Option<usize>,
    duration_seconds: Option<u64>,
    geyser_only: bool,
    no_shred: bool,
    dry_run: bool,
    mock_live: bool,
    mock_early_intent: bool,
    mock_early_intent_scenario: Option<&str>,
    with_deshred: bool,
    require_deshred: bool,
    deshred_only_capability_check: bool,
    mock_deshred: bool,
    mock_deshred_scenario: Option<&str>,
    _reset_paper_state: bool,
    run_id_override: Option<&str>,
    _report_dir: Option<&str>,
    max_decisions: Option<usize>,
) -> Result<()> {
    if live_data {
        if deshred_only_capability_check {
            return inspect_deshred_capability_command(loaded);
        }
        let mut loaded_for_run = loaded.clone();
        loaded_for_run.config.environment.run_id = run_id_override
            .map(ToOwned::to_owned)
            .unwrap_or_else(|| derived_run_id("live-paper"));
        let resolved = resolved_config(&loaded_for_run, Some(RuntimeMode::LiveDataPaper))?;
        let mut supervisor = Supervisor::new(resolved)?;
        let summary = supervisor
            .run_live_data_paper(runtime::LiveRunOptions {
                max_events,
                max_decisions,
                duration: duration_seconds.map(|seconds| time::Duration::seconds(seconds as i64)),
                health_interval_ms: None,
                geyser_only,
                no_shred,
                dry_run,
                mock_live,
                mock_early_intent,
                mock_early_intent_scenario: mock_early_intent_scenario.map(ToOwned::to_owned),
                with_deshred,
                require_deshred,
                deshred_only_capability_check,
                mock_deshred,
                mock_deshred_scenario: mock_deshred_scenario.map(ToOwned::to_owned),
                run_id: run_id_override.map(ToOwned::to_owned),
                report_dir: None,
            })
            .await?;
        println!(
            "{}",
            serde_json::to_string_pretty(&json!({
                "command": "run-paper",
                "mode": "live_data",
                "mock_live": mock_live,
                "mock_early_intent": mock_early_intent,
                "mock_deshred": mock_deshred,
                "with_deshred": with_deshred,
                "config_hash": loaded.hash,
                "idl_hash": combined_idl_hash(loaded)?,
                "run_id": summary.run_id,
                "health": summary.health,
                "safety": summary.safety,
                "decisions_by_type": summary.decisions_by_type,
                "fills": summary.fills.len(),
            }))?
        );
        return Ok(());
    }

    let source_run_id = select_run_id(
        loaded,
        RunSelection {
            run_id,
            latest_run,
            latest_any_run,
            latest_source_run: latest_source_run || from_store || !loaded.config.shred.enabled,
            latest_paper_run,
            latest_live_paper_run,
            latest_mocked_live_run,
            latest_mocked_early_intent_run,
            latest_shred_exit_run,
            latest_analysis_run,
            latest_report_run,
            latest_backtest_run,
            latest_shred_exit_backtest_run,
            run_kind: parse_run_kind(run_kind)?,
            run_role: parse_run_role(run_role)?,
            ..Default::default()
        },
        true,
    )
    .await?;
    let mut loaded_for_run = loaded.clone();
    loaded_for_run.config.environment.run_id = derived_run_id("paper-replay");
    let resolved = RuntimeResolvedConfig::from_loaded(
        loaded_for_run.clone(),
        Some(RuntimeMode::PaperFromStore),
    )?;
    let mut supervisor = Supervisor::new(resolved)?;
    let summary = supervisor
        .run_from_store_selection(Some(&source_run_id), scenario)
        .await?;
    let events = storage_engine(loaded)?
        .deterministic_replay_for_run_and_scenario(Some(&source_run_id), scenario)?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "run-paper",
            "mode": "from_store",
            "run_id": summary.run_id,
            "source_run_id": source_run_id,
            "scenario": scenario,
            "config_hash": loaded.hash,
            "idl_hash": combined_idl_hash(loaded)?,
            "events_processed": events.len(),
            "tokens_discovered": summary.snapshot.tokens.len(),
            "active_tokens": summary.health.active_tokens,
            "discarded_tokens": summary.snapshot.discarded_summaries.len(),
            "decisions_by_type": summary.decisions_by_type,
            "paper_positions": summary.health.active_positions,
            "simulated_fills": summary.fills.len(),
            "paper_pnl": summary.health.paper_pnl,
            "queue_depths": {
                "total": summary.health.event_queue_depth,
                "canonical": summary.health.canonical_queue_depth,
                "tentative": summary.health.tentative_queue_depth,
            },
            "data_gap_active": summary.health.data_gap_active,
            "rpc_credits_used": RpcBudgetManager::new(
                loaded.config.rpc_budget.clone(),
                loaded.config.execution.clone(),
                loaded.config.stream_only.clone(),
                loaded.config.rpc.clone(),
            ).summary().daily_used,
            "health": summary.health,
            "safety": summary.safety,
        }))?
    );
    Ok(())
}

async fn run_fixture(loaded: &LoadedConfig, fixture: &str) -> Result<()> {
    let spec = load_fixture_spec(resolve_user_path(loaded, fixture))?;
    let mut loaded_for_run = loaded.clone();
    loaded_for_run.config.environment.run_id = derived_run_id(&format!("fixture-{}", spec.name));
    let resolved = resolved_config(&loaded_for_run, Some(RuntimeMode::Fixture))?;
    let mut supervisor = Supervisor::new(resolved)?;
    let summary = supervisor
        .run_fixture(build_fixture_scenario(&spec))
        .await?;
    let report = supervisor.render_token_report(
        summary
            .snapshot
            .tokens
            .keys()
            .next()
            .map(String::as_str)
            .unwrap_or("missing"),
    )?;
    let report_path = storage_engine(&loaded_for_run)?
        .layout()
        .report_dir
        .join(&summary.run_id)
        .join(format!("{}.md", spec.name));
    write_report(&report_path, &report)?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "run-fixture",
            "config_hash": loaded.hash,
            "idl_hash": combined_idl_hash(loaded)?,
            "run_id": summary.run_id,
            "fixture": spec.name,
            "events_processed": storage_engine(&loaded_for_run)?.deterministic_replay_for_run(Some(&summary.run_id))?.len(),
            "decisions_by_type": summary.decisions_by_type,
            "fills": summary.fills.len(),
            "paper_pnl": summary.health.paper_pnl,
            "health": summary.health,
            "report_path": report_path,
        }))?
    );
    Ok(())
}

async fn run_fixture_suite(loaded: &LoadedConfig, explain_failures: bool) -> Result<()> {
    let mut loaded_for_run = loaded.clone();
    loaded_for_run.config.environment.run_id = derived_run_id("fixture-suite");
    let resolved = resolved_config(&loaded_for_run, Some(RuntimeMode::Fixture))?;
    let mut supervisor = Supervisor::new(resolved)?;
    let specs = builtin_fixture_suite();
    let results = supervisor.run_fixture_suite(&specs).await?;
    let report_root = storage_engine(&loaded_for_run)?
        .layout()
        .report_dir
        .join(&loaded_for_run.config.environment.run_id);
    std::fs::create_dir_all(&report_root)?;
    let mut suite_markdown = format!(
        "# Fixture Suite {}\n\n",
        loaded_for_run.config.environment.run_id
    );
    for result in &results {
        suite_markdown.push_str(&format!(
            "- {} passed={} lifecycle={} decisions={:?} fills={} pnl={} data_gap={:?}\n",
            result.scenario_name,
            result.passed_expectation,
            result.final_lifecycle,
            result.actual_decisions,
            result.actual_paper_fills,
            result.final_pnl,
            result.data_gap_state,
        ));
        let scenario_path = report_root.join(format!("{}.md", result.scenario_name));
        let content = format!(
            "# Scenario {}\n\n- passed_expectation: {}\n- expected: {}\n- lifecycle: {}\n- decisions: {:?}\n- risk_flags: {:?}\n- discard_state: {:?}\n- fills: {}\n- pnl: {}\n- blocking: {:?}\n- positive: {:?}\n- negative: {:?}\n- data_gap: {:?}\n",
            result.scenario_name,
            result.passed_expectation,
            result.expected_summary,
            result.final_lifecycle,
            result.actual_decisions,
            result.actual_risk_flags,
            result.actual_discard_state,
            result.actual_paper_fills,
            result.final_pnl,
            result.top_blocking_reasons,
            result.top_positive_signals,
            result.top_negative_signals,
            result.data_gap_state,
        );
        write_report(&scenario_path, &content)?;
    }
    write_report(report_root.join("suite_summary.md"), &suite_markdown)?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "run-fixture-suite",
            "config_hash": loaded.hash,
            "idl_hash": combined_idl_hash(loaded)?,
            "run_id": loaded_for_run.config.environment.run_id,
            "scenario_count": results.len(),
            "failures": if explain_failures {
                results.iter().filter(|result| !result.passed_expectation).cloned().collect::<Vec<_>>()
            } else {
                Vec::new()
            },
            "results": results,
        }))?
    );
    Ok(())
}

