async fn execute_research_cycle_summary(
    loaded: &LoadedConfig,
    selected_run_id: &str,
) -> Result<ResearchCycleSummary> {
    let quality = analyze_live_collection_summary(loaded, selected_run_id, true).await?;
    let thresholds = current_backtest_thresholds(loaded);
    let readiness = backtest_readiness_summary(loaded, &quality, &thresholds)?;
    let mut replay_run_id = None;
    let mut shred_exit_backtest_run_id = None;
    let mut exported_artifacts = Vec::new();
    if readiness.ready {
        let mut loaded_for_run = loaded.clone();
        loaded_for_run.config.environment.run_id = derived_run_id("paper-replay");
        let resolved = RuntimeResolvedConfig::from_loaded(
            loaded_for_run.clone(),
            Some(RuntimeMode::PaperFromStore),
        )?;
        let mut supervisor = Supervisor::new(resolved)?;
        let replay_summary = supervisor
            .run_from_store_selection(Some(selected_run_id), None)
            .await?;
        replay_run_id = Some(replay_summary.run_id.clone());
        if quality
            .reconciliation_outcomes
            .values()
            .copied()
            .sum::<u64>()
            > 0
        {
            backtest_shred_exit(loaded, Some(selected_run_id), false).await?;
            shred_exit_backtest_run_id = Some(selected_run_id.to_owned());
        }
        export_features(
            loaded,
            "csv",
            replay_run_id.as_deref(),
            false,
            false,
            None,
            false,
            false,
            false,
            false,
            false,
        )
        .await?;
        export_decisions(loaded, replay_run_id.as_deref(), false, false, None).await?;
        export_fills(loaded, replay_run_id.as_deref(), false, false, None).await?;
        export_rpc_ledger(loaded, replay_run_id.as_deref(), false, false).await?;
        generate_report(
            loaded,
            None,
            replay_run_id.as_deref(),
            false,
            false,
            false,
            false,
            false,
            false,
            false,
            false,
            false,
            None,
            None,
            None,
            true,
            false,
        )
        .await?;
        exported_artifacts =
            collect_artifacts_for_run(&storage_engine(loaded)?, &replay_summary.run_id)?
                .into_iter()
                .map(|artifact| artifact.path)
                .collect();
    }
    Ok(ResearchCycleSummary {
        run_id: selected_run_id.to_owned(),
        quality_verdict: quality.verdict.clone(),
        ready_for_backtest: readiness.ready,
        replay_run_id,
        shred_exit_backtest_run_id,
        exported_artifacts,
        blockers: readiness.blockers,
        warnings: readiness.warnings,
        stream_only_proof: quality.stream_only_proof,
    })
}

fn decision_type_counts(
    decisions: &[StoredRecord<common::TradeDecisionEvent>],
) -> BTreeMap<String, u64> {
    let mut counts = BTreeMap::<String, u64>::new();
    for decision in decisions {
        *counts
            .entry(format!("{:?}", decision.record.decision))
            .or_default() += 1;
    }
    counts
}

fn aggregate_reason_code_counts(
    decisions: &[StoredRecord<common::TradeDecisionEvent>],
    include: impl Fn(&common::TradeDecisionEvent) -> bool,
) -> Vec<(String, u64)> {
    let mut counts = BTreeMap::<String, u64>::new();
    for decision in decisions {
        if !include(&decision.record) {
            continue;
        }
        for reason in &decision.record.reason_codes {
            *counts.entry(format!("{reason:?}")).or_default() += 1;
        }
    }
    let mut items = counts.into_iter().collect::<Vec<_>>();
    items.sort_by(|left, right| right.1.cmp(&left.1).then_with(|| left.0.cmp(&right.0)));
    items.truncate(10);
    items
}

fn strategy_research_rows(
    decisions: &[StoredRecord<common::TradeDecisionEvent>],
    fills: &[StoredRecord<common::FillEvent>],
) -> Vec<StrategyResearchRow> {
    let mut decision_map = BTreeMap::<String, BTreeMap<String, u64>>::new();
    for decision in decisions {
        *decision_map
            .entry(decision.record.strategy.clone())
            .or_default()
            .entry(format!("{:?}", decision.record.decision))
            .or_default() += 1;
    }
    let mut fill_map = BTreeMap::<String, Vec<&StoredRecord<common::FillEvent>>>::new();
    for fill in fills {
        fill_map
            .entry(
                fill.record
                    .strategy
                    .clone()
                    .unwrap_or_else(|| "unknown".to_owned()),
            )
            .or_default()
            .push(fill);
    }
    let strategy_names = decision_map
        .keys()
        .cloned()
        .chain(fill_map.keys().cloned())
        .collect::<BTreeSet<_>>();
    strategy_names
        .into_iter()
        .map(|strategy| {
            let strategy_fills = fill_map.remove(&strategy).unwrap_or_default();
            StrategyResearchRow {
                strategy: strategy.clone(),
                fills: strategy_fills.len(),
                net_pnl: strategy_fills
                    .iter()
                    .map(|fill| fill.record.net_pnl_quote.unwrap_or(Decimal::ZERO))
                    .sum(),
                fee_drag: strategy_fills
                    .iter()
                    .map(|fill| {
                        fill.record.base_fee_quote.unwrap_or(Decimal::ZERO)
                            + fill.record.priority_fee_quote.unwrap_or(Decimal::ZERO)
                            + fill.record.tip_quote.unwrap_or(Decimal::ZERO)
                            + fill.record.failed_tx_cost_quote.unwrap_or(Decimal::ZERO)
                    })
                    .sum(),
                slippage_drag: strategy_fills
                    .iter()
                    .map(|fill| fill.record.slippage_cost_quote.unwrap_or(Decimal::ZERO))
                    .sum(),
                latency_drag: strategy_fills
                    .iter()
                    .map(|fill| fill.record.latency_cost_quote.unwrap_or(Decimal::ZERO))
                    .sum(),
                impact_drag: strategy_fills
                    .iter()
                    .map(|fill| fill.record.curve_impact_cost_quote.unwrap_or(Decimal::ZERO))
                    .sum(),
                decisions_by_type: decision_map.remove(&strategy).unwrap_or_default(),
            }
        })
        .collect()
}

fn write_named_report<T: Serialize>(
    report_dir: &Path,
    stem: &str,
    markdown: String,
    payload: &T,
) -> Result<()> {
    write_report(&report_dir.join(format!("{stem}.md")), &markdown)?;
    fs::write(
        report_dir.join(format!("{stem}.json")),
        serde_json::to_vec_pretty(payload)?,
    )?;
    Ok(())
}

fn materialize_research_review_reports(
    loaded: &LoadedConfig,
    run_id: &str,
    quality: &LiveCollectionQualitySummary,
    readiness: &BacktestReadinessSummary,
) -> Result<()> {
    let store = storage_engine(loaded)?;
    let report_dir = run_report_dir_for(loaded, run_id)?;
    let events = store.read_normalized_events_filtered(Some(run_id), None)?;
    let decisions = store.read_trade_decisions_filtered(Some(run_id), None)?;
    let fills = store.read_fills_filtered(Some(run_id), None)?;
    let snapshot = build_snapshot_from_events(&events);
    let by_strategy = strategy_research_rows(&decisions, &fills);
    let pnl = PnlAttributionSummary {
        run_id: run_id.to_owned(),
        total_net_pnl: fills
            .iter()
            .map(|fill| fill.record.net_pnl_quote.unwrap_or(Decimal::ZERO))
            .sum(),
        total_fee_drag: fills
            .iter()
            .map(|fill| {
                fill.record.base_fee_quote.unwrap_or(Decimal::ZERO)
                    + fill.record.priority_fee_quote.unwrap_or(Decimal::ZERO)
                    + fill.record.tip_quote.unwrap_or(Decimal::ZERO)
                    + fill.record.failed_tx_cost_quote.unwrap_or(Decimal::ZERO)
            })
            .sum(),
        total_slippage_drag: fills
            .iter()
            .map(|fill| fill.record.slippage_cost_quote.unwrap_or(Decimal::ZERO))
            .sum(),
        total_latency_drag: fills
            .iter()
            .map(|fill| fill.record.latency_cost_quote.unwrap_or(Decimal::ZERO))
            .sum(),
        total_impact_drag: fills
            .iter()
            .map(|fill| fill.record.curve_impact_cost_quote.unwrap_or(Decimal::ZERO))
            .sum(),
        by_strategy: by_strategy.clone(),
    };
    let feature_distribution = FeatureDistributionResearchSummary {
        run_id: run_id.to_owned(),
        quality_verdict: quality.verdict.clone(),
        holder_confidence_distribution: quality.holder_confidence_distribution.clone(),
        top_holder_confidence_distribution: quality.top_holder_confidence_distribution.clone(),
        bonding_curve_update_coverage: quality.bonding_curve_update_coverage,
        transaction_decode_coverage: quality.transaction_decode_coverage,
        account_update_coverage: quality.account_update_coverage,
        feature_snapshot_count: quality.feature_snapshot_count,
    };
    let rejection = RejectionReasonResearchSummary {
        run_id: run_id.to_owned(),
        top_rejection_reasons: aggregate_rejection_reasons(&decisions)
            .into_iter()
            .take(10)
            .collect(),
        top_positive_signals: aggregate_reason_code_counts(&decisions, |decision| {
            decision.decision == common::TradeDecision::EnterPaper
        }),
        top_negative_signals: aggregate_reason_code_counts(&decisions, |decision| {
            decision.decision != common::TradeDecision::EnterPaper
        }),
    };
    let data_gap_impact = DataGapImpactSummary {
        run_id: run_id.to_owned(),
        source_data_gaps: quality.source_data_gaps,
        slot_gap_count: quality.slot_gap_count,
        data_gap_active: quality.source_data_gaps > 0,
        warnings: readiness.warnings.clone(),
    };
    let (r2_uploaded, r2_verified, r2_verified_count, r2_failed_count) =
        persisted_r2_status(loaded, run_id)?;
    let decisions_by_type = decision_type_counts(&decisions);
    let rug_count = snapshot
        .tokens
        .values()
        .filter(|token| token.lifecycle == state::TokenLifecycle::RugArchive)
        .count();
    let discard_count = snapshot
        .tokens
        .values()
        .filter(|token| {
            matches!(
                token.lifecycle,
                state::TokenLifecycle::SoftDiscarded | state::TokenLifecycle::HardDiscarded
            )
        })
        .count();
    let false_positives = fills
        .iter()
        .filter(|fill| fill.record.false_positive_exit)
        .count() as u64;
    let suitable_for_threshold_tuning =
        readiness.safe_for_backtest && quality.source_data_gaps == 0 && quality.fill_count >= 20;
    let review = FirstRealDatasetReviewSummary {
        run_id: run_id.to_owned(),
        duration_seconds: quality.duration_seconds,
        tokens_discovered: quality.tokens_discovered,
        complete_lifecycles: quality.complete_token_lifecycles,
        source_data_gaps: quality.source_data_gaps,
        stream_only_proof: quality.stream_only_proof.clone(),
        r2_uploaded,
        r2_verified,
        r2_verified_count,
        r2_failed_count,
        paper_pnl: quality.paper_pnl,
        fill_count: quality.fill_count,
        decisions_by_type,
        strategy_pnl_by_strategy: by_strategy
            .iter()
            .map(|row| (row.strategy.clone(), row.net_pnl))
            .collect(),
        fee_drag: pnl.total_fee_drag,
        slippage_drag: pnl.total_slippage_drag,
        latency_drag: pnl.total_latency_drag,
        top_rejection_reasons: rejection.top_rejection_reasons.clone(),
        top_positive_signals: rejection.top_positive_signals.clone(),
        top_negative_signals: rejection.top_negative_signals.clone(),
        rug_count,
        discard_count,
        false_positives,
        suitable_for_threshold_tuning,
        suitable_for_walk_forward_testing: false,
        recommendation: if !readiness.ready {
            "not enough data".to_owned()
        } else if quality.source_data_gaps > 0 || quality.fill_count < 15 {
            "keep collecting".to_owned()
        } else {
            "begin limited threshold analysis".to_owned()
        },
        readiness_level: readiness.readiness_level.clone(),
        readiness_confidence: readiness.readiness_confidence,
        warnings: readiness.warnings.clone(),
    };

    write_named_report(
        &report_dir,
        "strategy_summary",
        {
            let mut body = format!("# Strategy Summary\n\n- run_id: {}\n", run_id);
            for row in &by_strategy {
                body.push_str(&format!(
                    "\n## {}\n- fills: {}\n- net_pnl: {}\n- fee_drag: {}\n- slippage_drag: {}\n- latency_drag: {}\n- impact_drag: {}\n- decisions_by_type: {:?}\n",
                    row.strategy,
                    row.fills,
                    row.net_pnl,
                    row.fee_drag,
                    row.slippage_drag,
                    row.latency_drag,
                    row.impact_drag,
                    row.decisions_by_type,
                ));
            }
            body
        },
        &by_strategy,
    )?;
    write_named_report(
        &report_dir,
        "pnl_attribution",
        format!(
            "# PnL Attribution\n\n- run_id: {}\n- total_net_pnl: {}\n- total_fee_drag: {}\n- total_slippage_drag: {}\n- total_latency_drag: {}\n- total_impact_drag: {}\n- by_strategy: {:?}\n",
            pnl.run_id,
            pnl.total_net_pnl,
            pnl.total_fee_drag,
            pnl.total_slippage_drag,
            pnl.total_latency_drag,
            pnl.total_impact_drag,
            pnl.by_strategy
                .iter()
                .map(|row| (row.strategy.clone(), row.net_pnl))
                .collect::<Vec<_>>(),
        ),
        &pnl,
    )?;
    write_named_report(
        &report_dir,
        "feature_distribution_summary",
        format!(
            "# Feature Distribution Summary\n\n- run_id: {}\n- quality_verdict: {}\n- feature_snapshot_count: {}\n- holder_confidence_distribution: {:?}\n- top_holder_confidence_distribution: {:?}\n- bonding_curve_update_coverage: {}\n- transaction_decode_coverage: {}\n- account_update_coverage: {}\n",
            feature_distribution.run_id,
            feature_distribution.quality_verdict,
            feature_distribution.feature_snapshot_count,
            feature_distribution.holder_confidence_distribution,
            feature_distribution.top_holder_confidence_distribution,
            feature_distribution.bonding_curve_update_coverage,
            feature_distribution.transaction_decode_coverage,
            feature_distribution.account_update_coverage,
        ),
        &feature_distribution,
    )?;
    write_named_report(
        &report_dir,
        "rejection_reason_summary",
        format!(
            "# Rejection Reason Summary\n\n- run_id: {}\n- top_rejection_reasons: {:?}\n- top_positive_signals: {:?}\n- top_negative_signals: {:?}\n",
            rejection.run_id,
            rejection.top_rejection_reasons,
            rejection.top_positive_signals,
            rejection.top_negative_signals,
        ),
        &rejection,
    )?;
    write_named_report(
        &report_dir,
        "data_gap_impact",
        format!(
            "# Data Gap Impact\n\n- run_id: {}\n- source_data_gaps: {}\n- slot_gap_count: {}\n- data_gap_active: {}\n- warnings: {:?}\n",
            data_gap_impact.run_id,
            data_gap_impact.source_data_gaps,
            data_gap_impact.slot_gap_count,
            data_gap_impact.data_gap_active,
            data_gap_impact.warnings,
        ),
        &data_gap_impact,
    )?;
    write_named_report(
        &report_dir,
        "first_real_dataset_review",
        format!(
            "# First Real Dataset Review\n\n- run_id: {}\n- duration_seconds: {}\n- tokens_discovered: {}\n- complete_lifecycles: {}\n- source_data_gaps: {}\n- r2_uploaded: {}\n- r2_verified: {}\n- r2_verified_count: {}\n- r2_failed_count: {}\n- paper_pnl: {}\n- fill_count: {}\n- decisions_by_type: {:?}\n- strategy_pnl_by_strategy: {:?}\n- fee_drag: {}\n- slippage_drag: {}\n- latency_drag: {}\n- top_rejection_reasons: {:?}\n- top_positive_signals: {:?}\n- top_negative_signals: {:?}\n- rug_count: {}\n- discard_count: {}\n- false_positives: {}\n- suitable_for_threshold_tuning: {}\n- suitable_for_walk_forward_testing: {}\n- recommendation: {}\n- readiness_level: {:?}\n- readiness_confidence: {}\n- warnings: {:?}\n{}\n",
            review.run_id,
            review.duration_seconds,
            review.tokens_discovered,
            review.complete_lifecycles,
            review.source_data_gaps,
            review.r2_uploaded,
            review.r2_verified,
            review.r2_verified_count,
            review.r2_failed_count,
            review.paper_pnl,
            review.fill_count,
            review.decisions_by_type,
            review.strategy_pnl_by_strategy,
            review.fee_drag,
            review.slippage_drag,
            review.latency_drag,
            review.top_rejection_reasons,
            review.top_positive_signals,
            review.top_negative_signals,
            review.rug_count,
            review.discard_count,
            review.false_positives,
            review.suitable_for_threshold_tuning,
            review.suitable_for_walk_forward_testing,
            review.recommendation,
            review.readiness_level,
            review.readiness_confidence,
            review.warnings,
            render_stream_only_proof(&review.stream_only_proof),
        ),
        &review,
    )?;
    Ok(())
}

async fn export_autopilot_artifacts(
    loaded: &LoadedConfig,
    run_id: &str,
    with_tentative: bool,
) -> Result<Vec<String>> {
    export_features(
        loaded,
        "csv",
        Some(run_id),
        false,
        false,
        None,
        false,
        false,
        false,
        false,
        false,
    )
    .await?;
    export_decisions(loaded, Some(run_id), false, false, None).await?;
    export_fills(loaded, Some(run_id), false, false, None).await?;
    export_provider_compatibility(loaded, "csv")?;
    export_rpc_ledger(loaded, Some(run_id), false, false).await?;
    if with_tentative {
        export_shred_exit_events(loaded, Some(run_id), false, false).await?;
        export_shred_exit_reconciliation(loaded, Some(run_id), false, false).await?;
    }
    verify_export_schema_for_runs(loaded, run_id, with_tentative.then_some(run_id)).await?;
    Ok(collect_artifacts_for_run(&storage_engine(loaded)?, run_id)?
        .into_iter()
        .map(|artifact| artifact.path)
        .collect())
}

async fn autopilot_r2_offload_for_run(
    loaded: &LoadedConfig,
    run_id: &str,
) -> Result<R2UploadSummaryReport> {
    let started = std::time::Instant::now();
    let client = R2Client::new(&loaded.config.r2)?;
    let report_dir = run_report_dir_for(loaded, run_id)?;
    let quality_path = report_dir.join("live_collection_quality.json");
    let readiness_path = report_dir.join("backtest_readiness.json");
    let quality = read_json_file::<LiveCollectionQualitySummary>(&quality_path);
    let readiness = read_json_file::<BacktestReadinessSummary>(&readiness_path);
    let backfill = load_metadata_backfill_summary(&report_dir);
    let mut segment_manifest = load_existing_or_build_segment_manifest_for_run(loaded, run_id)?;
    let _ = close_open_segment_files_for_run(loaded, run_id, &mut segment_manifest)?;
    let _ = write_run_segment_manifest(loaded, &mut segment_manifest)?;
    if loaded
        .config
        .storage
        .segments
        .finalization
        .drain_pending_segments_on_finalize
    {
        let _ = drain_pending_segments_for_run(loaded, run_id, &mut segment_manifest).await?;
    }
    if loaded.config.storage.segments.delete_verified_segments
        && loaded.config.storage.segments.verify_before_local_delete
    {
        let _ = prune_verified_local_segment_sources(loaded, &mut segment_manifest)?;
    }
    let segment_manifest_path = write_run_segment_manifest(loaded, &mut segment_manifest)?;
    let _ = upload_run_segment_manifest_to_r2(loaded, run_id, &segment_manifest_path).await;
    let (mut manifest, candidates, manifest_path, remote_manifest_key) = build_artifact_manifest(
        loaded,
        run_id,
        &client,
        true,
        true,
        true,
        true,
        true,
        loaded.config.r2.autopilot.upload_rpc_ledger,
        None,
    )?;
    apply_terminal_manifest_state(
        &mut manifest,
        &segment_manifest,
        quality.is_some(),
        readiness.is_some(),
        "pending_refresh",
        quality.as_ref(),
        readiness.as_ref(),
        backfill.as_ref(),
        &Vec::new(),
    );
    write_manifest(&manifest_path, &manifest)?;
    let summary = upload_manifest_candidates(
        loaded,
        &client,
        &mut manifest,
        &candidates,
        &manifest_path,
        &remote_manifest_key,
        None,
        None,
    )
    .await?;
    let mut manifest = load_manifest(&manifest_path)?;
    let consistency = ensure_manifest_consistency_for_run(loaded, run_id, true, true).await?;
    let _ = apply_remote_first_verified_retention(loaded, run_id)?;
    manifest = load_manifest(&manifest_path)?;
    apply_terminal_manifest_state(
        &mut manifest,
        &segment_manifest,
        quality.is_some(),
        readiness.is_some(),
        "pending_refresh",
        quality.as_ref(),
        readiness.as_ref(),
        backfill.as_ref(),
        &summary.errors.clone(),
    );
    write_manifest(&manifest_path, &manifest)?;
    upload_artifact_manifest_file_to_r2(
        &client,
        &manifest_path,
        &manifest.remote_manifest_key,
        true,
    )
    .await?;
    let mut audit = build_r2_upload_audit(
        &manifest,
        stream_only_run_summary(loaded, run_id, None)?,
        {
            let mut errors = summary.errors.clone();
            if consistency.repaired {
                errors.push("segment_manifest_artifact_manifest_drift_repaired".to_owned());
            }
            errors
        },
        started.elapsed().as_millis() as u64,
    );
    audit.local_manifest_path = manifest_path.display().to_string();
    write_r2_upload_audit_reports(loaded, run_id, &audit)?;
    Ok(summary)
}

async fn run_autopilot_cycle(
    loaded: &LoadedConfig,
    options: &AutopilotRunOptions,
    state: &mut AutopilotPersistedState,
    lock: &AutopilotLockGuard,
) -> Result<AutopilotCycleSummary> {
    let cycle_root = autopilot_cycle_root(loaded, state.cycle_id);
    fs::create_dir_all(&cycle_root)?;
    state.current_report_dir = Some(cycle_root.display().to_string());
    refresh_autopilot_lock(lock, state.cycle_id)?;
    let mut alerts_written = Vec::new();
    let mut last_prune_summary = None::<VerifiedPruneSummary>;
    let mut last_dataset_index_summary = None::<DatasetIndexUploadSummary>;
    state.last_disk_free_mb = collect_disk_preflight_summary(loaded)?.free_mb;

    persist_autopilot_transition(loaded, state, AutopilotPhase::ValidatingConfig)?;
    validate_config(loaded)?;

    persist_autopilot_transition(loaded, state, AutopilotPhase::ValidatingStreamOnly)?;
    let stream_validation = loaded.validate_stream_only()?;
    state.last_stream_only_result = Some(stream_validation.passed);
    if loaded.config.autopilot.safety.stop_on_stream_only_failure && !stream_validation.passed {
        let _ = append_autopilot_alert(
            loaded,
            AutopilotAlertType::StreamOnlyViolation,
            "autopilot stopped because stream-only validation failed",
            Some(state.cycle_id),
            None,
            BTreeMap::new(),
        )?;
        return Err(anyhow!("stream-only validation failed"));
    }

    let mut preflight = collect_disk_preflight_summary(loaded)?;
    state.last_disk_free_mb = preflight.free_mb;
    if preflight.free_mb < loaded.config.autopilot.disk.warning_free_mb {
        if loaded.config.autopilot.disk.run_prune_before_cycle {
            let prune = prune_verified_local_runs_command(
                loaded,
                false,
                loaded.config.autopilot.disk.allow_prune_verified_exports,
                loaded.config.autopilot.disk.allow_prune_verified_reports,
                loaded.config.autopilot.disk.allow_prune_verified_raw_events,
                loaded.config.autopilot.disk.keep_minimal_manifest,
                loaded.config.autopilot.disk.keep_rpc_ledger,
                loaded.config.autopilot.disk.keep_calibration,
                Some(loaded.config.r2.retention.keep_last_n_local_runs),
                Some(loaded.config.r2.retention.keep_local_after_upload_hours),
                None,
                true,
                active_autopilot_run_id_from_state(state),
            )?;
            state.last_prune_attempted = true;
            state.last_prune_succeeded = prune.deleted_bytes > 0;
            state.last_pruned_bytes = prune.deleted_bytes;
            last_prune_summary = Some(prune);
        }
        let _ = clean_build_artifacts_command(loaded, false, true);
        preflight = collect_disk_preflight_summary(loaded)?;
        state.last_disk_free_mb = preflight.free_mb;
    }

    let disk_policy =
        evaluate_pre_cycle_disk_policy(loaded, state, &preflight, stream_validation.passed);
    match disk_policy.decision {
        PreCycleDiskDecision::StartNormal => {
            state.paused_reason = None;
        }
        PreCycleDiskDecision::StartAggressiveLowDisk => {
            let _ = append_autopilot_alert(
                loaded,
                AutopilotAlertType::DiskWarning,
                disk_policy.message.clone(),
                Some(state.cycle_id),
                state.current_run_id.as_deref(),
                disk_policy.details.clone(),
            )?;
            alerts_written.push(AutopilotAlertType::DiskWarning);
            state.paused_reason = None;
        }
        PreCycleDiskDecision::BlockBelowWarningPolicy
        | PreCycleDiskDecision::BlockBelowPreCycleMinimum => {
            let _ = append_autopilot_alert(
                loaded,
                AutopilotAlertType::StoragePreflightBlocked,
                disk_policy.message.clone(),
                Some(state.cycle_id),
                state.current_run_id.as_deref(),
                disk_policy.details.clone(),
            )?;
            alerts_written.push(AutopilotAlertType::StoragePreflightBlocked);
            state.paused_reason = Some(disk_policy.message.clone());
            persist_autopilot_transition(loaded, state, AutopilotPhase::Paused)?;
            return Err(anyhow!(disk_policy.message));
        }
        PreCycleDiskDecision::BlockCritical => {
            let _ = append_autopilot_alert(
                loaded,
                AutopilotAlertType::StorageLimitReached,
                disk_policy.message.clone(),
                Some(state.cycle_id),
                state.current_run_id.as_deref(),
                disk_policy.details.clone(),
            )?;
            alerts_written.push(AutopilotAlertType::StorageLimitReached);
            state.paused_reason = Some(disk_policy.message.clone());
            persist_autopilot_transition(loaded, state, AutopilotPhase::Paused)?;
            return Err(anyhow!(disk_policy.message));
        }
        PreCycleDiskDecision::BlockEmergency => {
            let _ = append_autopilot_alert(
                loaded,
                AutopilotAlertType::StorageEmergency,
                disk_policy.message.clone(),
                Some(state.cycle_id),
                state.current_run_id.as_deref(),
                disk_policy.details.clone(),
            )?;
            alerts_written.push(AutopilotAlertType::StorageEmergency);
            state.paused_reason = Some(disk_policy.message.clone());
            persist_autopilot_transition(loaded, state, AutopilotPhase::Paused)?;
            return Err(anyhow!(disk_policy.message));
        }
    }

    persist_autopilot_transition(loaded, state, AutopilotPhase::InspectingProvider)?;
    let provider_name = autopilot_provider_name(loaded);
    let deshred_requested = options.with_deshred
        || loaded.config.autopilot.require_deshred
        || loaded
            .config
            .ingest
            .deshred
            .as_ref()
            .map(|value| value.enabled)
            .unwrap_or(false);
    let precheck_report_dir = cycle_root.join("precheck").display().to_string();
    let (precheck, _) = provider_env_precheck_summary(
        loaded,
        provider_name.as_deref(),
        deshred_requested,
        loaded.config.autopilot.require_geyser,
        Some(precheck_report_dir.as_str()),
    )?;
    let mut notes = Vec::new();
    let geyser_status;
    let mut deshred_status = if options.geyser_only {
        "skipped_geyser_only".to_owned()
    } else {
        "not_requested".to_owned()
    };
    let endpoint_missing = !precheck.endpoint_present;
    let mock_allowed = options.mock_live
        || options.allow_mock_when_endpoint_missing
        || loaded.config.autopilot.allow_mock_when_endpoint_missing;
    let use_mock = options.mock_live || (endpoint_missing && mock_allowed);

    if endpoint_missing {
        let mut details = BTreeMap::new();
        details.insert(
            "ready_for_geyser_smoke".to_owned(),
            precheck.ready_for_geyser_smoke.to_string(),
        );
        details.insert(
            "ready_for_deshred_smoke".to_owned(),
            precheck.ready_for_deshred_smoke.to_string(),
        );
        let _ = append_autopilot_alert(
            loaded,
            AutopilotAlertType::ProviderEndpointMissing,
            "provider endpoint missing for autopilot cycle",
            Some(state.cycle_id),
            None,
            details,
        )?;
        alerts_written.push(AutopilotAlertType::ProviderEndpointMissing);
        notes.push("missing_endpoint_detected".to_owned());
    }

    if !endpoint_missing && !options.skip_smoke {
        persist_autopilot_transition(loaded, state, AutopilotPhase::SmokingGeyser)?;
        let geyser = execute_geyser_smoke(
            loaded,
            &SmokeGeyserCommandOptions {
                duration_seconds: loaded.config.autopilot.provider.smoke_duration_seconds,
                max_updates: None,
                provider_name: provider_name.clone(),
                strict_env: false,
                allow_missing_endpoint_report: true,
                report_dir: Some(cycle_root.join("geyser_smoke").display().to_string()),
            },
        )
        .await?;
        geyser_status = geyser.summary.provider_status.clone();
        state.last_geyser_status = Some(geyser_status.clone());
        if deshred_requested && !options.geyser_only {
            persist_autopilot_transition(loaded, state, AutopilotPhase::SmokingDeshred)?;
            let deshred = execute_deshred_smoke(
                loaded,
                &SmokeDeshredCommandOptions {
                    duration_seconds: loaded.config.autopilot.provider.smoke_duration_seconds,
                    max_updates: None,
                    geyser_endpoint_env: deshred_endpoint_env_name(loaded),
                    auth_token_env: deshred_auth_env_name(loaded),
                    auth_metadata_key: loaded
                        .config
                        .ingest
                        .deshred
                        .clone()
                        .unwrap_or_default()
                        .auth_metadata_key,
                    require_deshred: loaded.config.autopilot.require_deshred,
                    geyser_confirmation_stream: false,
                    write_report: true,
                    no_paper: true,
                    paper: false,
                    no_shred: true,
                    strict: false,
                    strict_env: false,
                    allow_missing_endpoint_report: true,
                    provider_name: provider_name.clone(),
                    report_dir: Some(cycle_root.join("deshred_smoke").display().to_string()),
                    max_errors: None,
                    connection_timeout_ms: None,
                },
            )
            .await?;
            deshred_status = deshred.summary.provider_status.clone();
            state.last_deshred_status = Some(deshred_status.clone());
            append_provider_compatibility_record(
                loaded,
                provider_compatibility_record_from_smoke(
                    loaded,
                    &deshred.capability,
                    &deshred.summary,
                    Some(&deshred.smoke_run_id),
                    None,
                    provider_name.as_deref(),
                ),
            )?;
            if loaded.config.autopilot.require_deshred
                && !matches!(deshred_status.as_str(), "updates_received" | "zero_updates")
            {
                let _ = append_autopilot_alert(
                    loaded,
                    AutopilotAlertType::DeshredUnsupported,
                    format!("deshred required but unavailable: {deshred_status}"),
                    Some(state.cycle_id),
                    None,
                    BTreeMap::new(),
                )?;
                alerts_written.push(AutopilotAlertType::DeshredUnsupported);
                return Err(anyhow!(
                    "deshred required but unavailable: {deshred_status}"
                ));
            }
        }
    } else if use_mock {
        geyser_status = "mock_mode".to_owned();
        if deshred_requested || options.mock_deshred {
            deshred_status = "mock_mode".to_owned();
        }
        notes.push("mock_collection_fallback_enabled".to_owned());
    } else {
        geyser_status = "not_attempted_missing_endpoint".to_owned();
        if deshred_requested && !options.geyser_only {
            deshred_status = "not_attempted_missing_endpoint".to_owned();
        }
    }
    state.last_provider_status = Some(if use_mock {
        "mock_mode".to_owned()
    } else if endpoint_missing {
        "not_attempted_missing_endpoint".to_owned()
    } else {
        geyser_status.clone()
    });
    state.last_geyser_status = Some(geyser_status.clone());
    state.last_deshred_status = Some(deshred_status.clone());

    persist_autopilot_transition(loaded, state, AutopilotPhase::ChoosingCollectionMode)?;
    let stream_only_proof = wrapper_stream_only_summary(loaded, &cycle_root)?;
    let can_collect_real = !endpoint_missing
        && matches!(
            geyser_status.as_str(),
            "updates_received" | "connected_zero_updates"
        );
    let collection_mode = if use_mock {
        "mock"
    } else if can_collect_real
        && deshred_requested
        && matches!(deshred_status.as_str(), "updates_received" | "zero_updates")
        && !options.geyser_only
    {
        "geyser_plus_deshred"
    } else if can_collect_real
        && (options.geyser_only
            || !deshred_requested
            || loaded
                .config
                .autopilot
                .allow_geyser_only_when_deshred_unsupported)
    {
        "geyser_only"
    } else {
        "no_collection"
    }
    .to_owned();
    let edge_mode = edge_collector_autopilot_mode(loaded, options);

    if collection_mode == "no_collection" {
        notes.push("collection_skipped_provider_unavailable".to_owned());
        return Ok(AutopilotCycleSummary {
            cycle_id: state.cycle_id,
            mode: collection_mode,
            provider_status: state.last_provider_status.clone().unwrap_or_default(),
            geyser_status,
            deshred_status,
            collection_run_id: None,
            quality_verdict: None,
            backtest_ready: None,
            research_cycle_run_id: None,
            exported_artifacts: Vec::new(),
            stream_only_proof,
            rpc_network_calls_total: 0,
            rpc_credits_used_total: 0,
            rpc_denials_total: 0,
            r2_enabled: loaded.config.r2.enabled,
            r2_upload_enabled: loaded.config.r2.upload_enabled,
            r2_dry_run: loaded.config.r2.dry_run,
            r2_upload_attempted: false,
            r2_uploaded_count: 0,
            r2_verified_count: 0,
            r2_failed_count: 0,
            r2_manifest_path: None,
            r2_remote_manifest_key: None,
            r2_local_prune_attempted: false,
            r2_local_prune_succeeded: false,
            last_pruned_bytes: last_prune_summary
                .as_ref()
                .map(|summary| summary.deleted_bytes)
                .unwrap_or(0),
            last_disk_free_mb: state.last_disk_free_mb,
            last_dataset_index_uploaded: last_dataset_index_summary
                .as_ref()
                .map(|summary| summary.verified || (summary.uploaded && summary.dry_run))
                .unwrap_or(state.last_dataset_index_uploaded),
            last_dataset_index_run_count: last_dataset_index_summary
                .as_ref()
                .map(|summary| summary.run_count)
                .unwrap_or(state.last_dataset_index_run_count),
            r2_errors: Vec::new(),
            alerts_written,
            no_live_orders: true,
            notes,
        });
    }

    let selected_run_id = derived_run_id("live-paper");
    state.current_run_id = Some(selected_run_id.clone());
    state.current_source_run_id = Some(selected_run_id.clone());
    state.current_report_dir = Some(cycle_root.display().to_string());
    persist_autopilot_transition(loaded, state, AutopilotPhase::Collecting)?;
    let preset = options
        .preset
        .as_deref()
        .unwrap_or(loaded.config.autopilot.schedule.collection_preset.as_str());
    let collection_report_dir = cycle_root.join("collection").display().to_string();
    if edge_mode {
        collect_edge_stream(
            loaded,
            preset,
            collection_mode == "geyser_plus_deshred" || options.mock_deshred,
            collection_mode == "geyser_only",
            loaded.config.autopilot.require_deshred,
            use_mock,
            options.mock_deshred || collection_mode == "mock",
            options.duration_seconds.or(Some(
                loaded.config.autopilot.schedule.collection_duration_seconds,
            )),
            None,
            Some(loaded.config.autopilot.schedule.checkpoint_interval_seconds),
            Some(selected_run_id.as_str()),
            Some(collection_report_dir.as_str()),
        )
        .await?;
    } else {
        collect_live_paper(
            loaded,
            preset,
            collection_mode == "geyser_plus_deshred" || options.mock_deshred,
            collection_mode == "geyser_only",
            loaded.config.autopilot.require_deshred,
            use_mock,
            options.mock_deshred || collection_mode == "mock",
            options.duration_seconds.or(Some(
                loaded.config.autopilot.schedule.collection_duration_seconds,
            )),
            None,
            Some(loaded.config.autopilot.schedule.checkpoint_interval_seconds),
            loaded.config.autopilot.safety.stop_on_global_data_gap,
            false,
            Some(selected_run_id.as_str()),
            Some(collection_report_dir.as_str()),
        )
        .await?;
    }
    state.current_run_id = Some(selected_run_id.clone());
    state.current_source_run_id = Some(selected_run_id.clone());
    state.last_successful_collection_at = Some(OffsetDateTime::now_utc());

    if edge_mode {
        persist_autopilot_transition(loaded, state, AutopilotPhase::FinalizingSegments)?;
        let r2_summary = autopilot_r2_offload_for_run(loaded, &selected_run_id).await?;
        persist_autopilot_transition(loaded, state, AutopilotPhase::RefreshingDatasetIndex)?;
        let uploaded_index = upload_dataset_index_r2_internal(
            loaded,
            loaded.config.r2.dry_run,
            loaded.config.r2.verify_after_upload,
            true,
            false,
        )
        .await?;
        last_dataset_index_summary = Some(uploaded_index.clone());
        state.last_dataset_index_uploaded =
            uploaded_index.verified || (uploaded_index.uploaded && uploaded_index.dry_run);
        state.last_dataset_index_run_count = uploaded_index.run_count;
        let manifest = load_manifest_if_present(loaded, &selected_run_id)?.ok_or_else(|| {
            anyhow!("artifact manifest missing after edge collector finalization")
        })?;
        persist_autopilot_transition(loaded, state, AutopilotPhase::TerminalizingRun)?;
        state.last_completed_run_id = Some(selected_run_id.clone());
        state.last_terminal_run_status = Some(manifest.run_status.clone());
        state.last_finalized_manifest_run_id = Some(selected_run_id.clone());
        state.last_manifest_consistency_passed = Some(manifest.manifest_consistency_passed);
        state.last_manifest_drift_detected = Some(manifest.manifest_drift_detected);
        state.last_manifest_drift_repaired = false;
        state.needs_recovery_run_id = None;
        persist_autopilot_transition(loaded, state, AutopilotPhase::ClearingCurrentRun)?;
        state.current_run_id = None;
        state.current_source_run_id = None;
        state.current_report_dir = None;
        persist_autopilot_transition(loaded, state, AutopilotPhase::CompletedCycle)?;
        return Ok(AutopilotCycleSummary {
            cycle_id: state.cycle_id,
            mode: "edge_collector".to_owned(),
            provider_status: state.last_provider_status.clone().unwrap_or_default(),
            geyser_status,
            deshred_status,
            collection_run_id: Some(selected_run_id),
            quality_verdict: None,
            backtest_ready: None,
            research_cycle_run_id: None,
            exported_artifacts: Vec::new(),
            stream_only_proof,
            rpc_network_calls_total: 0,
            rpc_credits_used_total: 0,
            rpc_denials_total: 0,
            r2_enabled: loaded.config.r2.enabled,
            r2_upload_enabled: loaded.config.r2.upload_enabled,
            r2_dry_run: loaded.config.r2.dry_run,
            r2_upload_attempted: r2_summary.upload_attempted,
            r2_uploaded_count: r2_summary.uploaded_count,
            r2_verified_count: r2_summary.verified_count,
            r2_failed_count: r2_summary.failed_count,
            r2_manifest_path: (!r2_summary.local_manifest_path.is_empty())
                .then(|| r2_summary.local_manifest_path.clone()),
            r2_remote_manifest_key: (!r2_summary.remote_manifest_key.is_empty())
                .then(|| r2_summary.remote_manifest_key.clone()),
            r2_local_prune_attempted: r2_summary.pruned_local,
            r2_local_prune_succeeded: r2_summary.pruned_local,
            last_pruned_bytes: last_prune_summary
                .as_ref()
                .map(|summary| summary.deleted_bytes)
                .unwrap_or(0),
            last_disk_free_mb: state.last_disk_free_mb,
            last_dataset_index_uploaded: state.last_dataset_index_uploaded,
            last_dataset_index_run_count: state.last_dataset_index_run_count,
            r2_errors: r2_summary.errors.clone(),
            alerts_written,
            no_live_orders: true,
            notes: {
                notes.push("edge_collector_mode".to_owned());
                notes.push("vps_research_and_exports_skipped".to_owned());
                notes
            },
        });
    }

    persist_autopilot_transition(loaded, state, AutopilotPhase::AnalyzingCollection)?;
    analyze_live_collection_command(
        loaded,
        Some(&selected_run_id),
        false,
        false,
        false,
        true,
        false,
        false,
    )
    .await?;
    let quality = analyze_live_collection_summary(loaded, &selected_run_id, true).await?;
    state.last_collection_quality_verdict = Some(quality.verdict.clone());
    state.queue_overflow_count = state.queue_overflow_count.saturating_add(u64::from(
        quality.tentative_queue_pressure > 0 || quality.canonical_queue_pressure > 0,
    ));
    state.global_data_gap_count = state
        .global_data_gap_count
        .saturating_add(quality.source_data_gaps);
    if quality.source_data_gaps > 0 && loaded.config.autopilot.alerts.alert_on_data_gap {
        let _ = append_autopilot_alert(
            loaded,
            AutopilotAlertType::GlobalDataGap,
            format!("source data gaps observed: {}", quality.source_data_gaps),
            Some(state.cycle_id),
            Some(&selected_run_id),
            BTreeMap::new(),
        )?;
        alerts_written.push(AutopilotAlertType::GlobalDataGap);
    }

    persist_autopilot_transition(loaded, state, AutopilotPhase::CheckingBacktestReadiness)?;
    let thresholds = current_backtest_thresholds(loaded);
    check_backtest_readiness_command(
        loaded,
        Some(&selected_run_id),
        false,
        false,
        false,
        true,
        Some(thresholds.min_tokens),
        Some(thresholds.min_complete_lifecycles),
        Some(thresholds.min_duration_seconds),
        Some(thresholds.min_feature_snapshots),
        thresholds.require_zero_rpc,
        thresholds.require_stream_only,
    )
    .await?;
    let readiness = backtest_readiness_summary(loaded, &quality, &thresholds)?;
    state.last_backtest_readiness = Some(readiness.ready);
    if readiness.ready && loaded.config.autopilot.alerts.alert_on_backtest_ready {
        let _ = append_autopilot_alert(
            loaded,
            AutopilotAlertType::BacktestReady,
            "collection reached backtest readiness".to_owned(),
            Some(state.cycle_id),
            Some(&selected_run_id),
            BTreeMap::new(),
        )?;
        alerts_written.push(AutopilotAlertType::BacktestReady);
    }

    let mut research_cycle_run_id = None;
    let mut exported_artifacts = Vec::new();
    let mut r2_summary = R2UploadSummaryReport::default();
    if readiness.ready
        && loaded
            .config
            .autopilot
            .schedule
            .run_research_cycle_after_collection
        && !options.skip_research_cycle
    {
        persist_autopilot_transition(loaded, state, AutopilotPhase::RunningResearchCycle)?;
        let research = execute_research_cycle_summary(loaded, &selected_run_id).await?;
        let report_root = run_report_dir_for(loaded, &selected_run_id)?;
        write_report(
            &report_root.join("research_cycle_summary.md"),
            &format!(
                "# Research Cycle Summary\n\n- run_id: {}\n- quality_verdict: {}\n- ready_for_backtest: {}\n- replay_run_id: {}\n- shred_exit_backtest_run_id: {}\n- exported_artifacts: {:?}\n- blockers: {:?}\n- warnings: {:?}\n{}\n",
                research.run_id,
                research.quality_verdict,
                research.ready_for_backtest,
                research.replay_run_id.clone().unwrap_or_default(),
                research
                    .shred_exit_backtest_run_id
                    .clone()
                    .unwrap_or_default(),
                research.exported_artifacts,
                research.blockers,
                research.warnings,
                render_stream_only_proof(&research.stream_only_proof),
            ),
        )?;
        research_cycle_run_id = Some(research.run_id.clone());
        state.last_research_cycle_run_id = research_cycle_run_id.clone();
        if loaded.config.autopilot.alerts.enabled {
            let _ = append_autopilot_alert(
                loaded,
                AutopilotAlertType::ResearchCycleCompleted,
                "research cycle completed".to_owned(),
                Some(state.cycle_id),
                Some(&selected_run_id),
                BTreeMap::new(),
            )?;
            alerts_written.push(AutopilotAlertType::ResearchCycleCompleted);
        }
    }

    if !options.skip_exports {
        persist_autopilot_transition(loaded, state, AutopilotPhase::Exporting)?;
        exported_artifacts = export_autopilot_artifacts(
            loaded,
            &selected_run_id,
            quality
                .reconciliation_outcomes
                .values()
                .copied()
                .sum::<u64>()
                > 0,
        )
        .await?;
    }

    persist_autopilot_transition(loaded, state, AutopilotPhase::DrainingSegments)?;
    persist_autopilot_transition(loaded, state, AutopilotPhase::WritingSegmentManifest)?;
    persist_autopilot_transition(loaded, state, AutopilotPhase::WritingArtifactManifest)?;
    persist_autopilot_transition(loaded, state, AutopilotPhase::VerifyingR2Upload)?;
    match autopilot_r2_offload_for_run(loaded, &selected_run_id).await {
        Ok(summary) => {
            state.r2_last_upload_run_id = Some(selected_run_id.clone());
            state.r2_last_upload_verified =
                Some(summary.verified_count > 0 && summary.failed_count == 0);
            state.r2_last_upload_failed_count = summary.failed_count;
            state.r2_last_upload_remote_manifest_key = Some(summary.remote_manifest_key.clone());
            state.r2_last_upload_at = Some(OffsetDateTime::now_utc());
            state.r2_last_error = None;
            r2_summary = summary;
            let backfill =
                collect_run_metadata_backfill_summary(loaded, &selected_run_id, false).await?;
            persist_backfilled_run_metadata(loaded, &backfill)?;
            let _ = write_metadata_backfill_reports(loaded, &backfill)?;
            state.last_collection_quality_verdict = Some(backfill.quality_verdict.clone());
            state.last_backtest_readiness = Some(backfill.backtest_ready);
            if backfill.recovered_run {
                state.last_recovered_run_id = Some(backfill.run_id.clone());
                state.last_recovered_quality_verdict = Some(backfill.quality_verdict.clone());
                state.last_recovered_backtest_ready = Some(backfill.backtest_ready);
                state.last_recovered_backtest_warnings =
                    backfill.backtest_readiness_warnings.clone();
                state.last_recovered_r2_verified = Some(backfill.r2_verified);
            }
            persist_autopilot_transition(loaded, state, AutopilotPhase::RefreshingDatasetIndex)?;
            let _ = apply_remote_first_verified_retention(loaded, &selected_run_id)?;
            let uploaded_index = upload_dataset_index_r2_internal(
                loaded,
                loaded.config.r2.dry_run,
                loaded.config.r2.verify_after_upload,
                true,
                false,
            )
            .await?;
            state.last_dataset_index_uploaded =
                uploaded_index.verified || (uploaded_index.uploaded && uploaded_index.dry_run);
            state.last_dataset_index_run_count = uploaded_index.run_count;
            if backfill.recovered_run {
                state.last_recovered_dataset_index_uploaded = state.last_dataset_index_uploaded;
            }
            last_dataset_index_summary = Some(uploaded_index);
            if loaded.config.autopilot.disk.run_prune_after_verified_upload {
                let prune = prune_verified_local_runs_command(
                    loaded,
                    false,
                    loaded.config.autopilot.disk.allow_prune_verified_exports,
                    loaded.config.autopilot.disk.allow_prune_verified_reports,
                    loaded.config.autopilot.disk.allow_prune_verified_raw_events,
                    loaded.config.autopilot.disk.keep_minimal_manifest,
                    loaded.config.autopilot.disk.keep_rpc_ledger,
                    loaded.config.autopilot.disk.keep_calibration,
                    Some(loaded.config.r2.retention.keep_last_n_local_runs),
                    Some(loaded.config.r2.retention.keep_local_after_upload_hours),
                    None,
                    true,
                    Some(&selected_run_id),
                )?;
                state.last_prune_attempted = true;
                state.last_prune_succeeded = prune.deleted_bytes > 0;
                state.last_pruned_bytes = prune.deleted_bytes;
                r2_summary.pruned_local = prune.deleted_bytes > 0;
                last_prune_summary = Some(prune);
                state.last_disk_free_mb = collect_disk_preflight_summary(loaded)?.free_mb;
            }
            let cleanup = run_post_cycle_cleanup(loaded, &selected_run_id)?;
            state.last_post_cycle_cleanup_bytes = cleanup.reclaimed_bytes;
            state.last_post_cycle_free_mb = cleanup.after_free_mb;
            state.last_disk_free_mb = cleanup.after_free_mb;
            if cleanup.reclaimed_bytes > 0 {
                let _ = append_autopilot_alert(
                    loaded,
                    AutopilotAlertType::PostCycleCleanupReclaimed,
                    format!(
                        "post-cycle cleanup reclaimed {} bytes; free_mb={}",
                        cleanup.reclaimed_bytes, cleanup.after_free_mb
                    ),
                    Some(state.cycle_id),
                    Some(&selected_run_id),
                    BTreeMap::from([
                        (
                            "before_free_mb".to_owned(),
                            cleanup.before_free_mb.to_string(),
                        ),
                        (
                            "after_free_mb".to_owned(),
                            cleanup.after_free_mb.to_string(),
                        ),
                    ]),
                )?;
                alerts_written.push(AutopilotAlertType::PostCycleCleanupReclaimed);
            }
            if cleanup.enabled
                && loaded
                    .config
                    .autopilot
                    .post_cycle_cleanup
                    .stop_if_unable_to_reach_pre_cycle_min
                && !cleanup.reached_pre_cycle_min_free_mb
            {
                let _ = append_autopilot_alert(
                    loaded,
                    AutopilotAlertType::PostCycleCleanupInsufficient,
                    format!(
                        "post-cycle cleanup left free_mb={} below pre_cycle_min_free_mb={}",
                        cleanup.after_free_mb, cleanup.pre_cycle_min_free_mb
                    ),
                    Some(state.cycle_id),
                    Some(&selected_run_id),
                    BTreeMap::from([
                        (
                            "reclaimed_bytes".to_owned(),
                            cleanup.reclaimed_bytes.to_string(),
                        ),
                        (
                            "target_free_mb_after_cycle".to_owned(),
                            cleanup.target_free_mb_after_cycle.to_string(),
                        ),
                    ]),
                )?;
                alerts_written.push(AutopilotAlertType::PostCycleCleanupInsufficient);
            }
            let _ = write_local_footprint_budget_report(loaded, &selected_run_id)?;
            persist_autopilot_transition(loaded, state, AutopilotPhase::TerminalizingRun)?;
            state.last_completed_run_id = Some(selected_run_id.clone());
            state.last_terminal_run_status = Some(backfill.run_terminal_status.clone());
            state.last_finalized_manifest_run_id = backfill
                .artifact_manifest_present
                .then(|| selected_run_id.clone());
            state.last_manifest_consistency_passed = Some(backfill.manifest_consistency_passed);
            state.last_manifest_drift_detected = Some(backfill.manifest_drift_detected);
            state.last_manifest_drift_repaired = false;
            state.needs_recovery_run_id = None;
            persist_autopilot_transition(loaded, state, AutopilotPhase::ClearingCurrentRun)?;
            state.current_run_id = None;
            state.current_source_run_id = None;
            state.current_report_dir = None;
            persist_autopilot_transition(loaded, state, AutopilotPhase::CompletedCycle)?;
        }
        Err(error) => {
            state.r2_last_upload_run_id = Some(selected_run_id.clone());
            state.r2_last_upload_verified = Some(false);
            state.r2_last_upload_failed_count = 1;
            state.r2_last_error = Some(error.to_string());
            let _ = append_autopilot_alert(
                loaded,
                AutopilotAlertType::R2UploadFailed,
                format!("R2 upload/offload failed: {error}"),
                Some(state.cycle_id),
                Some(&selected_run_id),
                BTreeMap::new(),
            )?;
            alerts_written.push(AutopilotAlertType::R2UploadFailed);
            notes.push("r2_upload_failed".to_owned());
            let backfill =
                collect_run_metadata_backfill_summary(loaded, &selected_run_id, false).await?;
            persist_backfilled_run_metadata(loaded, &backfill)?;
            let _ = write_metadata_backfill_reports(loaded, &backfill)?;
            state.last_collection_quality_verdict = Some(backfill.quality_verdict.clone());
            state.last_backtest_readiness = Some(backfill.backtest_ready);
            if backfill.recovered_run {
                state.last_recovered_run_id = Some(backfill.run_id.clone());
                state.last_recovered_quality_verdict = Some(backfill.quality_verdict.clone());
                state.last_recovered_backtest_ready = Some(backfill.backtest_ready);
                state.last_recovered_backtest_warnings =
                    backfill.backtest_readiness_warnings.clone();
                state.last_recovered_r2_verified = Some(backfill.r2_verified);
                state.last_recovered_dataset_index_uploaded = false;
            }
            state.last_dataset_index_run_count = refresh_dataset_index(loaded)?.runs.len();
            state.last_dataset_index_uploaded = false;
            state.last_terminal_run_status = Some(backfill.run_terminal_status.clone());
            state.last_finalized_manifest_run_id = backfill
                .artifact_manifest_present
                .then(|| selected_run_id.clone());
            if load_manifest_if_present(loaded, &selected_run_id)?.is_some() {
                persist_autopilot_transition(loaded, state, AutopilotPhase::TerminalizingRun)?;
                state.needs_recovery_run_id = Some(selected_run_id.clone());
                persist_autopilot_transition(loaded, state, AutopilotPhase::ClearingCurrentRun)?;
                state.current_run_id = None;
                state.current_source_run_id = None;
                state.current_report_dir = None;
                persist_autopilot_transition(loaded, state, AutopilotPhase::PartialCycle)?;
            } else {
                state.needs_recovery_run_id = Some(selected_run_id.clone());
                persist_autopilot_transition(loaded, state, AutopilotPhase::FailedCycle)?;
            }
            if loaded.config.r2.autopilot.pause_autopilot_on_upload_failure {
                return Err(anyhow!("R2 upload/offload failed: {error}"));
            }
        }
    }

    if !options.no_retention && loaded.config.autopilot.retention.enabled {
        persist_autopilot_transition(loaded, state, AutopilotPhase::RotatingStorage)?;
        let retention = build_autopilot_retention_summary(loaded, false, Some(&selected_run_id))?;
        if retention.total_storage_bytes > retention.max_storage_bytes {
            let _ = append_autopilot_alert(
                loaded,
                AutopilotAlertType::StorageLimitReached,
                "autopilot storage usage exceeded configured limit".to_owned(),
                Some(state.cycle_id),
                Some(&selected_run_id),
                BTreeMap::new(),
            )?;
            alerts_written.push(AutopilotAlertType::StorageLimitReached);
        }
        let _ = write_retention_reports(loaded, &retention)?;
    }

    state.last_rpc_network_calls_total = quality.rpc_network_calls_total;
    state.last_rpc_credits_used_total = quality.rpc_credits_used_total;
    if loaded.config.autopilot.safety.stop_on_nonzero_rpc_usage
        && (quality.rpc_network_calls_total > 0 || quality.rpc_credits_used_total > 0)
    {
        let _ = append_autopilot_alert(
            loaded,
            AutopilotAlertType::RpcNetworkCallDetected,
            "nonzero RPC usage detected during autopilot cycle".to_owned(),
            Some(state.cycle_id),
            Some(&selected_run_id),
            BTreeMap::new(),
        )?;
        alerts_written.push(AutopilotAlertType::RpcNetworkCallDetected);
        return Err(anyhow!("nonzero RPC usage detected during autopilot cycle"));
    }

    Ok(AutopilotCycleSummary {
        cycle_id: state.cycle_id,
        mode: collection_mode,
        provider_status: state.last_provider_status.clone().unwrap_or_default(),
        geyser_status,
        deshred_status,
        collection_run_id: Some(selected_run_id),
        quality_verdict: Some(quality.verdict),
        backtest_ready: Some(readiness.ready),
        research_cycle_run_id,
        exported_artifacts,
        stream_only_proof: quality.stream_only_proof.clone(),
        rpc_network_calls_total: quality.rpc_network_calls_total,
        rpc_credits_used_total: quality.rpc_credits_used_total,
        rpc_denials_total: quality.rpc_denials_total,
        r2_enabled: loaded.config.r2.enabled,
        r2_upload_enabled: loaded.config.r2.upload_enabled,
        r2_dry_run: loaded.config.r2.dry_run,
        r2_upload_attempted: r2_summary.upload_attempted,
        r2_uploaded_count: r2_summary.uploaded_count,
        r2_verified_count: r2_summary.verified_count,
        r2_failed_count: r2_summary.failed_count,
        r2_manifest_path: (!r2_summary.local_manifest_path.is_empty())
            .then(|| r2_summary.local_manifest_path.clone()),
        r2_remote_manifest_key: (!r2_summary.remote_manifest_key.is_empty())
            .then(|| r2_summary.remote_manifest_key.clone()),
        r2_local_prune_attempted: r2_summary.pruned_local,
        r2_local_prune_succeeded: r2_summary.pruned_local,
        last_pruned_bytes: last_prune_summary
            .as_ref()
            .map(|summary| summary.deleted_bytes)
            .unwrap_or(0),
        last_disk_free_mb: state.last_disk_free_mb,
        last_dataset_index_uploaded: last_dataset_index_summary
            .as_ref()
            .map(|summary| summary.verified || (summary.uploaded && summary.dry_run))
            .unwrap_or(state.last_dataset_index_uploaded),
        last_dataset_index_run_count: last_dataset_index_summary
            .as_ref()
            .map(|summary| summary.run_count)
            .unwrap_or(state.last_dataset_index_run_count),
        r2_errors: r2_summary.errors.clone(),
        alerts_written,
        no_live_orders: true,
        notes,
    })
}

async fn run_autopilot(loaded: &LoadedConfig, options: AutopilotRunOptions) -> Result<()> {
    let _ = loaded.validate_autopilot()?;
    if loaded.config.live.enabled || loaded.config.execution.live_enabled {
        return Err(anyhow!(
            "autopilot requires live trading to remain disabled"
        ));
    }
    let mut state = load_or_default_autopilot_state(loaded);
    // An explicit `run-autopilot` invocation should start a fresh cycle even if a
    // previous stop request left the persisted shutdown latch set.
    state.shutdown_requested = false;
    let cycle_id = state.cycle_id.saturating_add(1);
    let guard = acquire_autopilot_lock(loaded, cycle_id)?;
    persist_autopilot_transition(loaded, &mut state, AutopilotPhase::Starting)?;
    let continuous = if options.continuous {
        true
    } else if options.once {
        false
    } else {
        loaded.config.autopilot.schedule.continuous
    };
    let max_cycles = if options.once || !continuous {
        Some(1)
    } else {
        options.test_max_cycles
    };
    let sleep_seconds = options
        .status_interval_seconds
        .unwrap_or(loaded.config.autopilot.cycle_sleep_seconds)
        .max(1);
    let mut completed_cycles = 0u64;
    loop {
        if state.shutdown_requested {
            break;
        }
        state.cycle_id = state.cycle_id.saturating_add(1);
        let cycle_summary = match run_autopilot_cycle(loaded, &options, &mut state, &guard).await {
            Ok(summary) => {
                state.total_cycles_completed = state.total_cycles_completed.saturating_add(1);
                persist_autopilot_transition(loaded, &mut state, AutopilotPhase::Idle)?;
                summary
            }
            Err(error) => {
                state.total_cycles_failed = state.total_cycles_failed.saturating_add(1);
                if !matches!(state.current_state, AutopilotPhase::Paused) {
                    persist_autopilot_transition(loaded, &mut state, AutopilotPhase::Failed)?;
                    let _ = append_autopilot_alert(
                        loaded,
                        AutopilotAlertType::AutopilotFailed,
                        format!("autopilot cycle failed: {error}"),
                        Some(state.cycle_id),
                        state.current_run_id.as_deref(),
                        BTreeMap::new(),
                    )?;
                }
                write_autopilot_status_reports(loaded)?;
                if options.once {
                    return Err(error);
                }
                break;
            }
        };
        let _ = write_autopilot_cycle_reports(loaded, &cycle_summary)?;
        let _ = write_autopilot_status_reports(loaded)?;
        completed_cycles = completed_cycles.saturating_add(1);
        if max_cycles
            .map(|value| completed_cycles >= value)
            .unwrap_or(false)
        {
            break;
        }
        if !continuous {
            break;
        }
        persist_autopilot_transition(loaded, &mut state, AutopilotPhase::Sleeping)?;
        refresh_autopilot_lock(&guard, state.cycle_id)?;
        tokio::select! {
            _ = tokio::time::sleep(std::time::Duration::from_secs(sleep_seconds)) => {}
            result = tokio::signal::ctrl_c() => {
                if result.is_ok() {
                    state.shutdown_requested = true;
                    persist_autopilot_transition(loaded, &mut state, AutopilotPhase::Stopping)?;
                    break;
                }
            }
        }
    }
    persist_autopilot_transition(loaded, &mut state, AutopilotPhase::Stopped)?;
    let _ = write_autopilot_status_reports(loaded)?;
    Ok(())
}

fn run_report_dir_for(loaded: &LoadedConfig, run_id: &str) -> Result<PathBuf> {
    Ok(storage_engine(loaded)?.run_report_dir(run_id))
}

fn load_runtime_audits_for_run(
    store: &StorageEngine,
    run_id: &str,
) -> Result<Vec<StoredRecord<runtime::RuntimeAuditEvent>>> {
    #[derive(Deserialize)]
    struct RawRuntimeAuditEvent {
        at: OffsetDateTime,
        kind: runtime::RuntimeAuditKind,
        run_id: String,
        #[serde(default)]
        details: BTreeMap<String, serde_json::Value>,
        #[serde(default)]
        reason_codes: Vec<ReasonCode>,
    }

    let path = &store.layout().runtime_audit_log;
    if !path.exists() {
        return Ok(Vec::new());
    }
    let content = fs::read_to_string(path)?;
    let mut records = Vec::new();
    for line in content.lines().filter(|line| !line.trim().is_empty()) {
        let Ok(record) = serde_json::from_str::<StoredRecord<serde_json::Value>>(line) else {
            continue;
        };
        if record.run_id.as_deref() != Some(run_id) {
            continue;
        }
        let Ok(raw_event) = serde_json::from_value::<RawRuntimeAuditEvent>(record.record.clone())
        else {
            continue;
        };
        let details = raw_event
            .details
            .into_iter()
            .map(|(key, value)| {
                let normalized = match value {
                    serde_json::Value::String(text) => text,
                    other => other.to_string(),
                };
                (key, normalized)
            })
            .collect::<BTreeMap<_, _>>();
        records.push(StoredRecord {
            schema_version: record.schema_version,
            config_hash: record.config_hash,
            idl_hash: record.idl_hash,
            strategy_version: record.strategy_version,
            run_id: record.run_id,
            scenario_id: record.scenario_id,
            runtime_sequence_number: record.runtime_sequence_number,
            source_event_id: record.source_event_id,
            trigger_event_id: record.trigger_event_id,
            calibration_snapshot_hash: record.calibration_snapshot_hash,
            deterministic_replay_hash: record.deterministic_replay_hash,
            replay_equivalence_group_id: record.replay_equivalence_group_id,
            source: record.source,
            canonicality: record.canonicality,
            no_lookahead_timestamp: record.no_lookahead_timestamp,
            dataset: record.dataset,
            record: runtime::RuntimeAuditEvent {
                at: raw_event.at,
                kind: raw_event.kind,
                run_id: raw_event.run_id,
                details,
                reason_codes: raw_event.reason_codes,
            },
        });
    }
    Ok(records)
}

async fn select_live_collection_run_id(
    loaded: &LoadedConfig,
    run_id: Option<&str>,
    latest_live_paper_run: bool,
    latest_real_live_paper_run: bool,
    latest_mock_live_run: bool,
    latest_source_run: bool,
) -> Result<String> {
    select_run_id(
        loaded,
        RunSelection {
            run_id,
            latest_live_paper_run: latest_live_paper_run
                || (!latest_real_live_paper_run && !latest_mock_live_run && run_id.is_none()),
            latest_real_live_paper_run,
            latest_mocked_live_run: latest_mock_live_run,
            latest_source_run,
            ..Default::default()
        },
        false,
    )
    .await
}

fn confidence_bucket(confidence: Decimal) -> String {
    if confidence >= Decimal::ONE {
        "1.0".to_owned()
    } else if confidence >= Decimal::new(75, 2) {
        "0.75_to_0.99".to_owned()
    } else if confidence >= Decimal::new(50, 2) {
        "0.50_to_0.74".to_owned()
    } else if confidence > Decimal::ZERO {
        "0.01_to_0.49".to_owned()
    } else {
        "0.0".to_owned()
    }
}

fn complete_lifecycle(lifecycle: &state::TokenLifecycle) -> bool {
    matches!(
        lifecycle,
        state::TokenLifecycle::Completed
            | state::TokenLifecycle::SoftDiscarded
            | state::TokenLifecycle::HardDiscarded
            | state::TokenLifecycle::RugArchive
            | state::TokenLifecycle::Migrated
    )
}

fn cached_live_collection_quality_if_terminal(
    loaded: &LoadedConfig,
    run_id: &str,
) -> Result<Option<LiveCollectionQualitySummary>> {
    let report_dir = run_report_dir_for(loaded, run_id)?;
    let path = report_dir.join("live_collection_quality.json");
    let Some(summary) = read_json_file::<LiveCollectionQualitySummary>(&path) else {
        return Ok(None);
    };
    let (run_status, finalization_status, artifact_manifest_present, _) =
        terminal_manifest_state_for_run(loaded, run_id)?;
    let terminal_status = run_status.starts_with("completed_") || run_status.starts_with("failed_");
    let terminal_finalize = matches!(
        finalization_status.as_str(),
        "completed" | "partial" | "verified" | "failed"
    );
    if artifact_manifest_present && (terminal_status || terminal_finalize) {
        return Ok(Some(summary));
    }
    Ok(None)
}

async fn analyze_live_collection_summary(
    loaded: &LoadedConfig,
    run_id: &str,
    allow_remote_segments: bool,
) -> Result<LiveCollectionQualitySummary> {
    if let Some(summary) = cached_live_collection_quality_if_terminal(loaded, run_id)? {
        return Ok(summary);
    }
    compute_live_collection_summary(loaded, run_id, allow_remote_segments).await
}

async fn compute_live_collection_summary(
    loaded: &LoadedConfig,
    run_id: &str,
    allow_remote_segments: bool,
) -> Result<LiveCollectionQualitySummary> {
    let store = storage_engine(loaded)?;
    let metadata = latest_metadata_for_run(&store, run_id)?;
    let events = store.read_normalized_events_filtered(Some(run_id), None)?;
    let decisions = store.read_trade_decisions_filtered(Some(run_id), None)?;
    let fills = store.read_fills_filtered(Some(run_id), None)?;
    let feature_snapshots =
        load_feature_snapshots_for_run(loaded, run_id, allow_remote_segments).await?;
    let token_summaries = store.read_token_summaries_filtered(Some(run_id), None)?;
    let audits = load_runtime_audits_for_run(&store, run_id)?;
    let stream_only_proof = stream_only_run_summary(loaded, run_id, metadata.as_ref())?;
    let source_summary =
        source_specific_early_intent_summary(loaded, run_id, metadata.as_ref(), &events, &fills)?;
    let shred_artifacts = build_shred_exit_artifacts(
        loaded,
        run_id.to_owned(),
        run_id.to_owned(),
        events.clone(),
        fills.clone(),
    )?;
    let mut events_by_source = BTreeMap::<String, u64>::new();
    let mut holder_confidence_distribution = BTreeMap::<String, u64>::new();
    let mut top_holder_confidence_distribution = BTreeMap::<String, u64>::new();
    let mut token_mints = BTreeSet::<String>::new();
    let mut bonding_curve_mints = BTreeSet::<String>::new();
    let mut holder_update_mints = BTreeSet::<String>::new();
    let mut observed_transactions = 0u64;
    let mut decoded_domain_events = 0u64;
    let mut missing_holder_owner_mappings = 0u64;
    let mut slot_gap_count = 0u64;
    for record in &events {
        *events_by_source
            .entry(json_enum_label(&record.record.meta.source))
            .or_default() += 1;
        match &record.record.payload {
            EventPayload::TokenCreated(payload) => {
                token_mints.insert(payload.mint.0.clone());
                decoded_domain_events = decoded_domain_events.saturating_add(1);
            }
            EventPayload::PumpBuy(payload) => {
                token_mints.insert(payload.mint.0.clone());
                decoded_domain_events = decoded_domain_events.saturating_add(1);
            }
            EventPayload::PumpSell(payload) => {
                token_mints.insert(payload.mint.0.clone());
                decoded_domain_events = decoded_domain_events.saturating_add(1);
            }
            EventPayload::BondingCurveUpdate(payload) => {
                bonding_curve_mints.insert(payload.mint.0.clone());
                decoded_domain_events = decoded_domain_events.saturating_add(1);
            }
            EventPayload::HolderBalanceUpdate(payload) => {
                holder_update_mints.insert(payload.mint.0.clone());
                *holder_confidence_distribution
                    .entry(confidence_bucket(payload.confidence))
                    .or_default() += 1;
                if payload.owner_wallet.0.is_empty() || payload.token_account.0.is_empty() {
                    missing_holder_owner_mappings = missing_holder_owner_mappings.saturating_add(1);
                }
                decoded_domain_events = decoded_domain_events.saturating_add(1);
            }
            EventPayload::WalletFunding(_) => {
                decoded_domain_events = decoded_domain_events.saturating_add(1);
            }
            EventPayload::ObservedTransaction(_) => {
                observed_transactions = observed_transactions.saturating_add(1);
            }
            EventPayload::DataGap(_) => {
                slot_gap_count = slot_gap_count.saturating_add(1);
            }
            _ => {}
        }
    }
    for summary in &token_summaries {
        let bucket = if summary.record.holder_count == 0 {
            "unknown"
        } else if summary.record.top1_holder_pct > Decimal::ZERO {
            "derived_from_local_state"
        } else {
            "weak_local_state"
        };
        *top_holder_confidence_distribution
            .entry(bucket.to_owned())
            .or_default() += 1;
    }
    let start = events
        .first()
        .map(|record| record.record.meta.received_at_wall_time)
        .or_else(|| {
            metadata
                .as_ref()
                .map(|record| record.record.created_at_wall_time)
        });
    let end = events
        .last()
        .map(|record| record.record.meta.received_at_wall_time)
        .or_else(|| {
            metadata
                .as_ref()
                .and_then(|record| record.record.completed_at_wall_time)
        });
    let duration_seconds = match (start, end) {
        (Some(start), Some(end)) => (end - start).whole_seconds().max(0) as u64,
        _ => 0,
    };
    let event_rate_per_second = if duration_seconds == 0 {
        Decimal::ZERO
    } else {
        Decimal::from(events.len() as u64) / Decimal::from(duration_seconds)
    };
    let complete_token_lifecycles = token_summaries
        .iter()
        .filter(|record| complete_lifecycle(&record.record.lifecycle))
        .count();
    let incomplete_token_lifecycles = token_summaries
        .len()
        .saturating_sub(complete_token_lifecycles);
    let bonding_curve_update_coverage = if token_mints.is_empty() {
        Decimal::ZERO
    } else {
        Decimal::from(bonding_curve_mints.len() as u64) / Decimal::from(token_mints.len() as u64)
    };
    let transaction_decode_coverage = if observed_transactions == 0 {
        Decimal::ZERO
    } else {
        Decimal::from(decoded_domain_events.min(observed_transactions) as u64)
            / Decimal::from(observed_transactions)
    };
    let account_update_coverage = if token_mints.is_empty() {
        Decimal::ZERO
    } else {
        Decimal::from(holder_update_mints.len() as u64) / Decimal::from(token_mints.len() as u64)
    };
    let mut deshred_lead_time_distribution = BTreeMap::<String, u64>::new();
    let mut reconciliation_outcomes = BTreeMap::<String, u64>::new();
    for row in &shred_artifacts.reconciliation_rows {
        *reconciliation_outcomes
            .entry(row.outcome.clone())
            .or_default() += 1;
        if let Some(delta) = row.deshred_to_geyser_processed_latency_ms {
            let bucket = if delta < 0 {
                "negative"
            } else if delta == 0 {
                "zero"
            } else if delta <= 100 {
                "1_to_100"
            } else {
                "over_100"
            };
            *deshred_lead_time_distribution
                .entry(bucket.to_owned())
                .or_default() += 1;
        }
    }
    let queue_overflows = audits
        .iter()
        .filter(|record| matches!(record.record.kind, runtime::RuntimeAuditKind::QueueOverflow))
        .count() as u64;
    let canonical_queue_pressure = queue_overflows as usize;
    let tentative_queue_pressure = metadata
        .as_ref()
        .and_then(|record| metadata_note_u64(Some(record), "source_dedup_count="))
        .unwrap_or(source_summary.source_dedup_count) as usize;
    let verdict =
        if !stream_only_proof.stream_only_passed || stream_only_proof.rpc_network_calls_total > 0 {
            "unusable_due_to_gaps"
        } else if duration_seconds < 60 || token_mints.len() < 2 || feature_snapshots.len() < 5 {
            "smoke_only"
        } else if complete_token_lifecycles < 2 {
            "usable_for_basic_feature_distribution"
        } else if fills.is_empty() || decisions.is_empty() {
            "insufficient_data"
        } else {
            "usable_for_strategy_backtest"
        }
        .to_owned();
    Ok(LiveCollectionQualitySummary {
        run_id: run_id.to_owned(),
        duration_seconds,
        event_rate_per_second,
        events_by_source,
        tokens_discovered: token_mints.len().max(token_summaries.len()),
        complete_token_lifecycles,
        incomplete_token_lifecycles,
        missing_holder_owner_mappings,
        holder_confidence_distribution,
        top_holder_confidence_distribution,
        bonding_curve_update_coverage,
        transaction_decode_coverage,
        account_update_coverage,
        slot_gap_count,
        source_data_gaps: slot_gap_count,
        canonical_queue_pressure,
        tentative_queue_pressure,
        feature_snapshot_count: feature_snapshots.len(),
        decision_count: decisions.len(),
        fill_count: fills.len(),
        paper_pnl: fills
            .iter()
            .map(|record| record.record.net_pnl_quote.unwrap_or(Decimal::ZERO))
            .sum(),
        rpc_network_calls_total: stream_only_proof.rpc_network_calls_total,
        rpc_denials_total: stream_only_proof.rpc_denials_total,
        rpc_credits_used_total: stream_only_proof.rpc_credits_used_total,
        deshred_lead_time_distribution,
        reconciliation_outcomes,
        verdict,
        stream_only_proof,
    })
}

fn backtest_readiness_summary(
    loaded: &LoadedConfig,
    quality: &LiveCollectionQualitySummary,
    thresholds: &BacktestRequiredThresholds,
) -> Result<BacktestReadinessSummary> {
    let mut blockers = Vec::new();
    let mut warnings = Vec::new();
    if quality.tokens_discovered < thresholds.min_tokens {
        blockers.push(format!(
            "tokens_discovered {} < required {}",
            quality.tokens_discovered, thresholds.min_tokens
        ));
    }
    if quality.complete_token_lifecycles < thresholds.min_complete_lifecycles {
        blockers.push(format!(
            "complete_token_lifecycles {} < required {}",
            quality.complete_token_lifecycles, thresholds.min_complete_lifecycles
        ));
    }
    if quality.duration_seconds < thresholds.min_duration_seconds {
        blockers.push(format!(
            "duration_seconds {} < required {}",
            quality.duration_seconds, thresholds.min_duration_seconds
        ));
    }
    if quality.feature_snapshot_count < thresholds.min_feature_snapshots {
        blockers.push(format!(
            "feature_snapshot_count {} < required {}",
            quality.feature_snapshot_count, thresholds.min_feature_snapshots
        ));
    }
    if quality.decision_count == 0 {
        blockers.push("no paper decisions were recorded".to_owned());
    }
    if quality.fill_count == 0 {
        warnings.push("no paper fills were recorded".to_owned());
    }
    if thresholds.require_zero_rpc && quality.stream_only_proof.rpc_network_calls_total > 0 {
        blockers.push("rpc network calls were observed".to_owned());
    }
    if thresholds.require_stream_only && !quality.stream_only_proof.stream_only_passed {
        blockers.push("stream-only proof did not pass".to_owned());
    }
    if quality.source_data_gaps > 0 {
        warnings.push(format!("source_data_gaps={}", quality.source_data_gaps));
    }
    if quality.paper_pnl < Decimal::ZERO {
        warnings.push(format!("negative_paper_pnl={}", quality.paper_pnl));
    }
    let suggested_next_collection_duration = if quality.duration_seconds < 300 {
        "300 seconds".to_owned()
    } else if quality.complete_token_lifecycles < thresholds.min_complete_lifecycles {
        "1800 seconds".to_owned()
    } else {
        "collection looks sufficient".to_owned()
    };
    let recommended_next_collection_duration_seconds = if quality.duration_seconds < 300 {
        300
    } else if quality.fill_count < 10
        || quality.source_data_gaps > 0
        || quality.complete_token_lifecycles < 50
    {
        1800
    } else {
        3600
    };
    let suggested_backtest_commands = vec![
        format!(
            "cargo run -q -p cli -- run-paper --config config/default.toml --from-store --run-id {}",
            quality.run_id
        ),
        format!(
            "cargo run -q -p cli -- backtest-shred-exit --config config/default.toml --run-id {}",
            quality.run_id
        ),
    ];
    let ready = blockers.is_empty();
    let readiness_level = if ready {
        BacktestReadinessLevel::SingleRunBacktestReady
    } else if quality.verdict == "smoke_only" {
        BacktestReadinessLevel::SmokeOnly
    } else if quality.verdict == "usable_for_basic_feature_distribution"
        || (quality.duration_seconds >= 300
            && quality.tokens_discovered >= thresholds.min_tokens
            && quality.feature_snapshot_count >= thresholds.min_feature_snapshots)
    {
        BacktestReadinessLevel::BasicFeatureDistributionReady
    } else {
        BacktestReadinessLevel::NotReady
    };
    let mut readiness_warning_flags = Vec::new();
    if quality.source_data_gaps > 0 {
        readiness_warning_flags.push("source_data_gaps".to_owned());
    }
    if quality.fill_count < 10 {
        readiness_warning_flags.push("low_fill_count".to_owned());
    }
    if quality.complete_token_lifecycles < 50 {
        readiness_warning_flags.push("low_complete_lifecycles".to_owned());
    }
    if quality.paper_pnl < Decimal::ZERO {
        readiness_warning_flags.push("negative_paper_pnl".to_owned());
    }
    if !quality.stream_only_proof.stream_only_passed || quality.rpc_network_calls_total > 0 {
        readiness_warning_flags.push("stream_only_violation".to_owned());
    }
    if quality.slot_gap_count > 0 {
        readiness_warning_flags.push("slot_gaps_present".to_owned());
    }
    let mut readiness_confidence = match readiness_level {
        BacktestReadinessLevel::NotReady => Decimal::new(10, 2),
        BacktestReadinessLevel::SmokeOnly => Decimal::new(15, 2),
        BacktestReadinessLevel::BasicFeatureDistributionReady => Decimal::new(40, 2),
        BacktestReadinessLevel::SingleRunBacktestReady => Decimal::new(65, 2),
        BacktestReadinessLevel::MultiRunBacktestReady => Decimal::new(80, 2),
        BacktestReadinessLevel::WalkForwardCandidate => Decimal::new(90, 2),
        BacktestReadinessLevel::ProductionCandidateNever => Decimal::ZERO,
    };
    if quality.source_data_gaps > 0 {
        readiness_confidence -= Decimal::new(15, 2);
    }
    if quality.fill_count < 10 {
        readiness_confidence -= Decimal::new(10, 2);
    }
    if quality.complete_token_lifecycles < 50 {
        readiness_confidence -= Decimal::new(5, 2);
    }
    if quality.paper_pnl < Decimal::ZERO {
        readiness_confidence -= Decimal::new(5, 2);
    }
    if !quality.stream_only_proof.stream_only_passed || quality.rpc_network_calls_total > 0 {
        readiness_confidence = Decimal::new(5, 2);
    }
    if readiness_confidence < Decimal::new(5, 2) {
        readiness_confidence = Decimal::new(5, 2);
    }
    if readiness_confidence > Decimal::new(95, 2) {
        readiness_confidence = Decimal::new(95, 2);
    }
    let (run_terminal_status, finalization_status, _, r2_full_verification_status) =
        terminal_manifest_state_for_run(loaded, &quality.run_id)?;
    Ok(BacktestReadinessSummary {
        run_id: quality.run_id.clone(),
        ready,
        blockers,
        warnings: warnings.clone(),
        backtest_ready_with_warnings: ready && !warnings.is_empty(),
        safe_for_backtest: ready
            && quality.stream_only_proof.stream_only_passed
            && quality.rpc_network_calls_total == 0,
        safe_for_walk_forward: false,
        readiness_level,
        readiness_confidence,
        readiness_warning_flags,
        suggested_next_collection_duration,
        recommended_next_collection_duration_seconds,
        recommended_minimum_additional_runs: if ready { 2 } else { 3 },
        suggested_backtest_commands,
        stream_only_proof: quality.stream_only_proof.clone(),
        tokens_discovered: quality.tokens_discovered,
        complete_lifecycles: quality.complete_token_lifecycles,
        duration_seconds: quality.duration_seconds,
        feature_snapshot_count: quality.feature_snapshot_count,
        decision_count: quality.decision_count,
        fill_count: quality.fill_count,
        source_data_gaps: quality.source_data_gaps,
        slot_gap_count: quality.slot_gap_count,
        data_gap_active: quality.source_data_gaps > 0,
        holder_confidence_floor: if quality.missing_holder_owner_mappings > 0 {
            "degraded_due_to_missing_owner_mappings".to_owned()
        } else {
            "stream_local_only".to_owned()
        },
        required_thresholds: Some(thresholds.clone()),
        observed_values: Some(BacktestObservedValues {
            duration_seconds: quality.duration_seconds,
            tokens_discovered: quality.tokens_discovered,
            complete_lifecycles: quality.complete_token_lifecycles,
            feature_snapshot_count: quality.feature_snapshot_count,
            decision_count: quality.decision_count,
            fill_count: quality.fill_count,
            source_data_gaps: quality.source_data_gaps,
            slot_gap_count: quality.slot_gap_count,
            data_gap_active: quality.source_data_gaps > 0,
            paper_pnl: quality.paper_pnl,
            stream_only_passed: quality.stream_only_proof.stream_only_passed,
            rpc_network_calls_total: quality.stream_only_proof.rpc_network_calls_total,
            rpc_credits_used_total: quality.stream_only_proof.rpc_credits_used_total,
        }),
        r2_verified: r2_full_verification_status == "verified",
        run_terminal_status,
        finalization_status,
        stream_only_passed: quality.stream_only_proof.stream_only_passed,
        rpc_network_calls_total: quality.stream_only_proof.rpc_network_calls_total,
        rpc_credits_used_total: quality.stream_only_proof.rpc_credits_used_total,
    })
}

fn write_backtest_readiness_reports(
    loaded: &LoadedConfig,
    summary: &BacktestReadinessSummary,
) -> Result<(PathBuf, PathBuf)> {
    let report_root = run_report_dir_for(loaded, &summary.run_id)?;
    fs::create_dir_all(&report_root)?;
    let markdown_path = report_root.join("backtest_readiness.md");
    let json_path = report_root.join("backtest_readiness.json");
    write_report(
        &markdown_path,
        &format!(
            "# Backtest Readiness\n\n- run_id: {}\n- ready: {}\n- backtest_ready_with_warnings: {}\n- safe_for_backtest: {}\n- safe_for_walk_forward: {}\n- readiness_level: {:?}\n- readiness_confidence: {}\n- readiness_warning_flags: {:?}\n- blockers: {:?}\n- warnings: {:?}\n- suggested_next_collection_duration: {}\n- recommended_next_collection_duration_seconds: {}\n- recommended_minimum_additional_runs: {}\n- suggested_backtest_commands: {:?}\n- tokens_discovered: {}\n- complete_lifecycles: {}\n- duration_seconds: {}\n- feature_snapshot_count: {}\n- decision_count: {}\n- fill_count: {}\n- source_data_gaps: {}\n- slot_gap_count: {}\n- data_gap_active: {}\n- holder_confidence_floor: {}\n- run_terminal_status: {}\n- finalization_status: {}\n- stream_only_passed: {}\n- rpc_network_calls_total: {}\n- rpc_credits_used_total: {}\n- r2_verified: {}\n- required_thresholds: {}\n- observed_values: {}\n{}\n",
            summary.run_id,
            summary.ready,
            summary.backtest_ready_with_warnings,
            summary.safe_for_backtest,
            summary.safe_for_walk_forward,
            summary.readiness_level,
            summary.readiness_confidence,
            summary.readiness_warning_flags,
            summary.blockers,
            summary.warnings,
            summary.suggested_next_collection_duration,
            summary.recommended_next_collection_duration_seconds,
            summary.recommended_minimum_additional_runs,
            summary.suggested_backtest_commands,
            summary.tokens_discovered,
            summary.complete_lifecycles,
            summary.duration_seconds,
            summary.feature_snapshot_count,
            summary.decision_count,
            summary.fill_count,
            summary.source_data_gaps,
            summary.slot_gap_count,
            summary.data_gap_active,
            summary.holder_confidence_floor,
            summary.run_terminal_status,
            summary.finalization_status,
            summary.stream_only_passed,
            summary.rpc_network_calls_total,
            summary.rpc_credits_used_total,
            summary.r2_verified,
            summary
                .required_thresholds
                .as_ref()
                .map(|value| serde_json::to_string(value).unwrap_or_default())
                .unwrap_or_default(),
            summary
                .observed_values
                .as_ref()
                .map(|value| serde_json::to_string(value).unwrap_or_default())
                .unwrap_or_default(),
            render_stream_only_proof(&summary.stream_only_proof),
        ),
    )?;
    fs::write(&json_path, serde_json::to_vec_pretty(summary)?)?;
    Ok((markdown_path, json_path))
}

async fn smoke_streams_command(
    loaded: &LoadedConfig,
    with_deshred: bool,
    require_deshred: bool,
    geyser_only: bool,
    duration_seconds: u64,
    max_geyser_updates: Option<usize>,
    max_deshred_updates: Option<usize>,
    provider_name: Option<&str>,
    strict_env: bool,
    allow_missing_endpoint_report: bool,
    report_dir: Option<&str>,
    _dry_run: bool,
) -> Result<()> {
    let stream_smoke_id = derived_run_id("stream-smoke");
    let report_root = resolve_report_root(loaded, "stream_smoke", &stream_smoke_id, report_dir);
    fs::create_dir_all(&report_root)?;
    let precheck = provider_env_precheck_summary(
        loaded,
        provider_name,
        with_deshred || require_deshred,
        true,
        report_dir,
    )?
    .0;
    let geyser = execute_geyser_smoke(
        loaded,
        &SmokeGeyserCommandOptions {
            duration_seconds,
            max_updates: max_geyser_updates,
            provider_name: provider_name.map(ToOwned::to_owned),
            strict_env,
            allow_missing_endpoint_report,
            report_dir: Some(report_root.join("geyser").display().to_string()),
        },
    )
    .await?;
    let deshred_requested = !geyser_only
        && (with_deshred
            || loaded
                .config
                .ingest
                .deshred
                .as_ref()
                .map(|value| value.enabled)
                .unwrap_or(false));
    let deshred_status = if deshred_requested {
        let deshred = execute_deshred_smoke(
            loaded,
            &SmokeDeshredCommandOptions {
                duration_seconds,
                max_updates: max_deshred_updates,
                geyser_endpoint_env: deshred_endpoint_env_name(loaded),
                auth_token_env: deshred_auth_env_name(loaded),
                auth_metadata_key: loaded
                    .config
                    .ingest
                    .deshred
                    .clone()
                    .unwrap_or_default()
                    .auth_metadata_key,
                require_deshred,
                geyser_confirmation_stream: false,
                write_report: true,
                no_paper: true,
                paper: false,
                no_shred: true,
                strict: strict_env,
                strict_env,
                allow_missing_endpoint_report,
                provider_name: provider_name.map(ToOwned::to_owned),
                report_dir: Some(report_root.join("deshred").display().to_string()),
                max_errors: None,
                connection_timeout_ms: None,
            },
        )
        .await?;
        append_provider_compatibility_record(
            loaded,
            provider_compatibility_record_from_smoke(
                loaded,
                &deshred.capability,
                &deshred.summary,
                Some(&deshred.smoke_run_id),
                None,
                provider_name,
            ),
        )?;
        deshred.summary.provider_status
    } else if geyser_only {
        "skipped_geyser_only".to_owned()
    } else {
        "not_requested".to_owned()
    };
    let stream_only_proof = wrapper_stream_only_summary(loaded, &report_root)?;
    let summary = StreamSmokeSummary {
        run_id: stream_smoke_id.clone(),
        provider_name: provider_name
            .filter(|value| !value.trim().is_empty())
            .map(ToOwned::to_owned)
            .or_else(|| {
                (!loaded.config.provider.name.trim().is_empty())
                    .then(|| loaded.config.provider.name.clone())
            }),
        geyser_status: geyser.summary.provider_status.clone(),
        deshred_status: deshred_status.clone(),
        stream_only_proof,
        endpoint_present: geyser.endpoint_present,
        no_live_orders: true,
        notes: vec![format!(
            "next_recommended_command={}",
            if geyser.summary.provider_status == "updates_received"
                && (!deshred_requested
                    || matches!(
                        deshred_status.as_str(),
                        "updates_received"
                            | "zero_updates"
                            | "not_requested"
                            | "skipped_geyser_only"
                    ))
            {
                "collect-first-live-paper short"
            } else if deshred_status == "auth_rejected" {
                "fix auth and rerun smoke-deshred-provider"
            } else if deshred_status == "unimplemented" {
                "use geyser-only collection"
            } else {
                "fix endpoint/auth and rerun smoke"
            }
        )],
    };
    let json_path = report_root.join("stream_smoke_summary.json");
    let markdown_path = report_root.join("stream_smoke_summary.md");
    fs::write(&json_path, serde_json::to_vec_pretty(&summary)?)?;
    write_report(
        &markdown_path,
        &format!(
            "# Stream Smoke Summary\n\n- run_id: {}\n- provider_name: {}\n- endpoint_present: {}\n- geyser_status: {}\n- deshred_status: {}\n- no_live_orders: {}\n- precheck_blockers: {:?}\n- precheck_warnings: {:?}\n- notes: {:?}\n{}\n",
            summary.run_id,
            summary.provider_name.clone().unwrap_or_default(),
            summary.endpoint_present,
            summary.geyser_status,
            summary.deshred_status,
            summary.no_live_orders,
            precheck.blockers,
            precheck.warnings,
            summary.notes,
            render_stream_only_proof(&summary.stream_only_proof),
        ),
    )?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "smoke-streams",
            "summary": summary,
            "markdown_path": markdown_path,
            "json_path": json_path,
        }))?
    );
    if require_deshred && !matches!(deshred_status.as_str(), "updates_received" | "zero_updates") {
        return Err(anyhow!(
            "deshred was required but stream smoke returned {deshred_status}"
        ));
    }
    if geyser.summary.provider_status == "not_attempted_missing_endpoint"
        && !allow_missing_endpoint_report
    {
        return Err(anyhow!("geyser endpoint missing for stream smoke"));
    }
    Ok(())
}

async fn collect_first_live_paper(
    loaded: &LoadedConfig,
    with_deshred: bool,
    geyser_only: bool,
    require_deshred: bool,
    duration_seconds: u64,
    max_events: Option<usize>,
    checkpoint_interval_seconds: Option<u64>,
    _stop_on_global_data_gap: bool,
    _stop_on_provider_error: bool,
    provider_name: Option<&str>,
    report_dir: Option<&str>,
    mock_live: bool,
    mock_deshred: bool,
    _dry_run: bool,
) -> Result<()> {
    if !mock_live {
        let (precheck, _) = provider_env_precheck_summary(
            loaded,
            provider_name,
            with_deshred || require_deshred,
            true,
            report_dir,
        )?;
        if !precheck.blockers.is_empty() {
            return Err(anyhow!(
                "provider environment not ready: {}",
                precheck.blockers.join("; ")
            ));
        }
    }
    let run_id = derived_run_id("live-paper");
    let mut loaded_for_run = loaded.clone();
    loaded_for_run.config.environment.run_id = run_id.clone();
    let resolved = resolved_config(&loaded_for_run, Some(RuntimeMode::LiveDataPaper))?;
    let mut supervisor = Supervisor::new(resolved)?;
    let runtime_summary = supervisor
        .run_live_data_paper(LiveRunOptions {
            duration: Some(time::Duration::seconds(duration_seconds.max(1) as i64)),
            max_events,
            geyser_only,
            with_deshred,
            require_deshred,
            dry_run: true,
            mock_live,
            mock_deshred,
            mock_deshred_scenario: mock_deshred.then(|| "dev_sell".to_owned()),
            run_id: Some(run_id.clone()),
            ..LiveRunOptions::default()
        })
        .await?;
    let store = storage_engine(&loaded_for_run)?;
    let report_root = if let Some(path) = report_dir {
        resolve_user_path(&loaded_for_run, path).join(&runtime_summary.run_id)
    } else {
        store.run_report_dir(&runtime_summary.run_id)
    };
    fs::create_dir_all(&report_root)?;
    let events = store.read_normalized_events_filtered(Some(&runtime_summary.run_id), None)?;
    let decisions = store.read_trade_decisions_filtered(Some(&runtime_summary.run_id), None)?;
    let fills = store.read_fills_filtered(Some(&runtime_summary.run_id), None)?;
    let audits = load_runtime_audits_for_run(&store, &runtime_summary.run_id)?;
    let stream_only_proof = stream_only_run_summary(
        &loaded_for_run,
        &runtime_summary.run_id,
        latest_metadata_for_run(&store, &runtime_summary.run_id)?.as_ref(),
    )?;
    let pump_creates = events
        .iter()
        .filter(|record| matches!(record.record.payload, EventPayload::TokenCreated(_)))
        .count() as u64;
    let pump_buys = events
        .iter()
        .filter(|record| matches!(record.record.payload, EventPayload::PumpBuy(_)))
        .count() as u64;
    let pump_sells = events
        .iter()
        .filter(|record| matches!(record.record.payload, EventPayload::PumpSell(_)))
        .count() as u64;
    let bonding_curve_updates = events
        .iter()
        .filter(|record| matches!(record.record.payload, EventPayload::BondingCurveUpdate(_)))
        .count() as u64;
    let holder_updates = events
        .iter()
        .filter(|record| matches!(record.record.payload, EventPayload::HolderBalanceUpdate(_)))
        .count() as u64;
    let tentative_sells = events
        .iter()
        .filter(|record| {
            matches!(
                record.record.payload,
                EventPayload::TentativeSellIntentDetected(_)
            )
        })
        .count() as u64;
    let data_gaps = events
        .iter()
        .filter(|record| matches!(record.record.payload, EventPayload::DataGap(_)))
        .count() as u64;
    let queue_overflows = audits
        .iter()
        .filter(|record| matches!(record.record.kind, runtime::RuntimeAuditKind::QueueOverflow))
        .count() as u64;
    let summary = FirstLiveCollectionSummary {
        run_id: runtime_summary.run_id.clone(),
        provider_name: provider_name
            .filter(|value| !value.trim().is_empty())
            .map(ToOwned::to_owned)
            .or_else(|| {
                (!loaded.config.provider.name.trim().is_empty())
                    .then(|| loaded.config.provider.name.clone())
            }),
        duration_seconds: duration_seconds.max(1),
        checkpoint_interval_seconds: checkpoint_interval_seconds.unwrap_or(duration_seconds.max(1)),
        mode: runtime_summary.health.live_source_mode.clone(),
        provider_status: if mock_live {
            "mock_mode".to_owned()
        } else if with_deshred {
            runtime_summary.health.deshred_provider_status.clone()
        } else {
            "geyser_only".to_owned()
        },
        stream_only_proof,
        geyser_events: runtime_summary.health.geyser_events_received,
        deshred_events: runtime_summary.health.deshred_events_received,
        tokens_discovered: runtime_summary.snapshot.tokens.len(),
        pump_creates,
        pump_buys,
        pump_sells,
        bonding_curve_updates,
        holder_updates,
        tentative_sells,
        emergency_exits: runtime_summary
            .decisions_by_type
            .get("EmergencyExit")
            .copied()
            .unwrap_or_default(),
        paper_decisions: decisions.len() as u64,
        paper_fills: fills.len(),
        paper_pnl: runtime_summary.health.paper_pnl,
        data_gaps,
        decode_errors: runtime_summary.health.deshred_decode_errors,
        unknown_instructions: 0,
        queue_overflows,
        memory_approximation_items: runtime_summary.health.event_queue_depth
            + runtime_summary.health.tentative_queue_depth
            + runtime_summary.health.canonical_queue_depth
            + runtime_summary.snapshot.tokens.len()
            + runtime_summary.health.active_positions,
        sufficient_for_backtest: duration_seconds >= 300
            && runtime_summary.snapshot.tokens.len() >= 3,
        next_recommended_collection_duration: if duration_seconds < 300 {
            "300 seconds".to_owned()
        } else if runtime_summary.snapshot.tokens.len() < 3 {
            "1800 seconds".to_owned()
        } else {
            "review quality report and backtest readiness".to_owned()
        },
        no_live_orders: true,
        notes: vec!["checkpoint_reports_are_final_snapshots_in_this_wrapper".to_owned()],
    };
    let summary_json = report_root.join("first_live_collection_summary.json");
    let summary_md = report_root.join("first_live_collection_summary.md");
    let checkpoint_json = report_root.join("checkpoint_1.json");
    let checkpoint_md = report_root.join("checkpoint_1.md");
    fs::write(&summary_json, serde_json::to_vec_pretty(&summary)?)?;
    fs::write(&checkpoint_json, serde_json::to_vec_pretty(&summary)?)?;
    write_report(
        &summary_md,
        &format!(
            "# First Live Collection Summary\n\n- run_id: {}\n- provider_name: {}\n- duration_seconds: {}\n- checkpoint_interval_seconds: {}\n- mode: {}\n- provider_status: {}\n- geyser_events: {}\n- deshred_events: {}\n- tokens_discovered: {}\n- pump_creates: {}\n- pump_buys: {}\n- pump_sells: {}\n- bonding_curve_updates: {}\n- holder_updates: {}\n- tentative_sells: {}\n- emergency_exits: {}\n- paper_decisions: {}\n- paper_fills: {}\n- paper_pnl: {}\n- data_gaps: {}\n- decode_errors: {}\n- unknown_instructions: {}\n- queue_overflows: {}\n- memory_approximation_items: {}\n- sufficient_for_backtest: {}\n- next_recommended_collection_duration: {}\n- no_live_orders: {}\n- notes: {:?}\n{}\n",
            summary.run_id,
            summary.provider_name.clone().unwrap_or_default(),
            summary.duration_seconds,
            summary.checkpoint_interval_seconds,
            summary.mode,
            summary.provider_status,
            summary.geyser_events,
            summary.deshred_events,
            summary.tokens_discovered,
            summary.pump_creates,
            summary.pump_buys,
            summary.pump_sells,
            summary.bonding_curve_updates,
            summary.holder_updates,
            summary.tentative_sells,
            summary.emergency_exits,
            summary.paper_decisions,
            summary.paper_fills,
            summary.paper_pnl,
            summary.data_gaps,
            summary.decode_errors,
            summary.unknown_instructions,
            summary.queue_overflows,
            summary.memory_approximation_items,
            summary.sufficient_for_backtest,
            summary.next_recommended_collection_duration,
            summary.no_live_orders,
            summary.notes,
            render_stream_only_proof(&summary.stream_only_proof),
        ),
    )?;
    write_report(
        &checkpoint_md,
        &format!(
            "# Collection Checkpoint 1\n\n- run_id: {}\n- mode: {}\n- paper_pnl: {}\n- tokens_discovered: {}\n- geyser_events: {}\n- deshred_events: {}\n- queue_overflows: {}\n{}\n",
            summary.run_id,
            summary.mode,
            summary.paper_pnl,
            summary.tokens_discovered,
            summary.geyser_events,
            summary.deshred_events,
            summary.queue_overflows,
            render_stream_only_proof(&summary.stream_only_proof),
        ),
    )?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

async fn analyze_live_collection_command(
    loaded: &LoadedConfig,
    run_id: Option<&str>,
    latest_live_paper_run: bool,
    latest_real_live_paper_run: bool,
    latest_mock_live_run: bool,
    allow_remote_segments: bool,
    json_output: bool,
    markdown_output: bool,
) -> Result<()> {
    let selected_run_id = select_live_collection_run_id(
        loaded,
        run_id,
        latest_live_paper_run,
        latest_real_live_paper_run,
        latest_mock_live_run,
        false,
    )
    .await?;
    let summary =
        analyze_live_collection_summary(loaded, &selected_run_id, allow_remote_segments).await?;
    let report_root = run_report_dir_for(loaded, &selected_run_id)?;
    let json_path = report_root.join("live_collection_quality.json");
    let markdown_path = report_root.join("live_collection_quality.md");
    fs::write(&json_path, serde_json::to_vec_pretty(&summary)?)?;
    write_report(
        &markdown_path,
        &format!(
            "# Live Collection Quality\n\n- run_id: {}\n- duration_seconds: {}\n- event_rate_per_second: {}\n- events_by_source: {:?}\n- tokens_discovered: {}\n- complete_token_lifecycles: {}\n- incomplete_token_lifecycles: {}\n- missing_holder_owner_mappings: {}\n- holder_confidence_distribution: {:?}\n- top_holder_confidence_distribution: {:?}\n- bonding_curve_update_coverage: {}\n- transaction_decode_coverage: {}\n- account_update_coverage: {}\n- slot_gap_count: {}\n- source_data_gaps: {}\n- canonical_queue_pressure: {}\n- tentative_queue_pressure: {}\n- feature_snapshot_count: {}\n- decision_count: {}\n- fill_count: {}\n- paper_pnl: {}\n- deshred_lead_time_distribution: {:?}\n- reconciliation_outcomes: {:?}\n- verdict: {}\n{}\n",
            summary.run_id,
            summary.duration_seconds,
            summary.event_rate_per_second,
            summary.events_by_source,
            summary.tokens_discovered,
            summary.complete_token_lifecycles,
            summary.incomplete_token_lifecycles,
            summary.missing_holder_owner_mappings,
            summary.holder_confidence_distribution,
            summary.top_holder_confidence_distribution,
            summary.bonding_curve_update_coverage,
            summary.transaction_decode_coverage,
            summary.account_update_coverage,
            summary.slot_gap_count,
            summary.source_data_gaps,
            summary.canonical_queue_pressure,
            summary.tentative_queue_pressure,
            summary.feature_snapshot_count,
            summary.decision_count,
            summary.fill_count,
            summary.paper_pnl,
            summary.deshred_lead_time_distribution,
            summary.reconciliation_outcomes,
            summary.verdict,
            render_stream_only_proof(&summary.stream_only_proof),
        ),
    )?;
    if markdown_output && !json_output {
        println!("{}", fs::read_to_string(&markdown_path)?);
    } else {
        println!(
            "{}",
            serde_json::to_string_pretty(&json!({
                "command": "analyze-live-collection",
                "summary": summary,
                "markdown_path": markdown_path,
                "json_path": json_path,
            }))?
        );
    }
    Ok(())
}

async fn check_backtest_readiness_command(
    loaded: &LoadedConfig,
    run_id: Option<&str>,
    latest_live_paper_run: bool,
    latest_real_live_paper_run: bool,
    latest_source_run: bool,
    allow_remote_segments: bool,
    min_tokens: Option<usize>,
    min_complete_lifecycles: Option<usize>,
    min_duration_seconds: Option<u64>,
    min_feature_snapshots: Option<usize>,
    require_zero_rpc: bool,
    require_stream_only: bool,
) -> Result<()> {
    let selected_run_id = select_live_collection_run_id(
        loaded,
        run_id,
        latest_live_paper_run,
        latest_real_live_paper_run,
        false,
        latest_source_run,
    )
    .await?;
    let quality =
        analyze_live_collection_summary(loaded, &selected_run_id, allow_remote_segments).await?;
    let thresholds = resolve_backtest_thresholds(
        loaded,
        min_tokens,
        min_complete_lifecycles,
        min_duration_seconds,
        min_feature_snapshots,
        require_zero_rpc,
        require_stream_only,
    );
    let readiness = backtest_readiness_summary(loaded, &quality, &thresholds)?;
    let _ = write_backtest_readiness_reports(loaded, &readiness)?;
    println!("{}", serde_json::to_string_pretty(&readiness)?);
    Ok(())
}

async fn run_research_cycle_command(
    loaded: &LoadedConfig,
    run_id: Option<&str>,
    latest_live_paper_run: bool,
) -> Result<()> {
    forbid_heavy_vps_research_paths_in_edge_mode(loaded, "run-research-cycle")?;
    let selected_run_id =
        select_live_collection_run_id(loaded, run_id, latest_live_paper_run, false, false, false)
            .await?;
    let quality = analyze_live_collection_summary(loaded, &selected_run_id, true).await?;
    let thresholds = current_backtest_thresholds(loaded);
    let readiness = backtest_readiness_summary(loaded, &quality, &thresholds)?;
    let mut replay_run_id = None;
    let mut shred_exit_backtest_run_id = None;
    let mut exported_artifacts = Vec::new();
    if readiness.ready {
        let mut loaded_for_run = loaded.clone();
        loaded_for_run.config.environment.run_id = derived_run_id("paper-replay");
        let resolved = RuntimeResolvedConfig::from_loaded(
            loaded_for_run.clone(),
            Some(RuntimeMode::PaperFromStore),
        )?;
        let mut supervisor = Supervisor::new(resolved)?;
        let replay_summary = supervisor
            .run_from_store_selection(Some(&selected_run_id), None)
            .await?;
        replay_run_id = Some(replay_summary.run_id.clone());
        if quality
            .reconciliation_outcomes
            .values()
            .copied()
            .sum::<u64>()
            > 0
        {
            backtest_shred_exit(loaded, Some(&selected_run_id), false).await?;
            shred_exit_backtest_run_id = Some(selected_run_id.clone());
        }
        export_features(
            loaded,
            "csv",
            replay_run_id.as_deref(),
            false,
            false,
            None,
            false,
            false,
            false,
            false,
            false,
        )
        .await?;
        export_decisions(loaded, replay_run_id.as_deref(), false, false, None).await?;
        export_fills(loaded, replay_run_id.as_deref(), false, false, None).await?;
        export_rpc_ledger(loaded, replay_run_id.as_deref(), false, false).await?;
        generate_report(
            loaded,
            None,
            replay_run_id.as_deref(),
            false,
            false,
            false,
            false,
            false,
            false,
            false,
            false,
            false,
            None,
            None,
            None,
            true,
            false,
        )
        .await?;
        exported_artifacts =
            collect_artifacts_for_run(&storage_engine(loaded)?, &replay_summary.run_id)?
                .into_iter()
                .map(|artifact| artifact.path)
                .collect();
    }
    let summary = ResearchCycleSummary {
        run_id: selected_run_id.clone(),
        quality_verdict: quality.verdict.clone(),
        ready_for_backtest: readiness.ready,
        replay_run_id,
        shred_exit_backtest_run_id,
        exported_artifacts,
        blockers: readiness.blockers.clone(),
        warnings: readiness.warnings.clone(),
        stream_only_proof: quality.stream_only_proof.clone(),
    };
    let report_root = run_report_dir_for(loaded, &selected_run_id)?;
    let report_path = report_root.join("research_cycle_summary.md");
    let report_json_path = report_root.join("research_cycle_summary.json");
    write_report(
        &report_path,
        &format!(
            "# Research Cycle Summary\n\n- run_id: {}\n- quality_verdict: {}\n- ready_for_backtest: {}\n- readiness_level: {:?}\n- readiness_confidence: {}\n- replay_run_id: {}\n- shred_exit_backtest_run_id: {}\n- exported_artifacts: {:?}\n- blockers: {:?}\n- warnings: {:?}\n{}\n",
            summary.run_id,
            summary.quality_verdict,
            summary.ready_for_backtest,
            readiness.readiness_level,
            readiness.readiness_confidence,
            summary.replay_run_id.clone().unwrap_or_default(),
            summary
                .shred_exit_backtest_run_id
                .clone()
                .unwrap_or_default(),
            summary.exported_artifacts,
            summary.blockers,
            summary.warnings,
            render_stream_only_proof(&summary.stream_only_proof),
        ),
    )?;
    fs::write(&report_json_path, serde_json::to_vec_pretty(&summary)?)?;
    materialize_research_review_reports(loaded, &selected_run_id, &quality, &readiness)?;
    println!("{}", serde_json::to_string_pretty(&summary)?);
    Ok(())
}

fn select_research_worker_run_ids(
    index: &DatasetIndex,
    run_id: Option<&str>,
    latest_run: bool,
    latest_n_runs: Option<usize>,
    require_normalized_events: bool,
    allow_source_events_fallback: bool,
) -> Result<Vec<String>> {
    if let Some(run_id) = run_id {
        if let Some(entry) = index.runs.iter().find(|entry| entry.run_id == run_id) {
            if require_normalized_events
                && !allow_source_events_fallback
                && !run_is_normalized_complete(entry)
            {
                return Err(anyhow!(
                    "normalized_events_required_but_unavailable for source run {run_id}"
                ));
            }
        }
        return Ok(vec![run_id.to_owned()]);
    }
    let mut runs = index
        .runs
        .iter()
        .filter(|entry| {
            (entry.edge_mode || entry.run_role == "source_run")
                && entry.r2_verified
                && entry.edge_segments_count > 0
                && entry.edge_segments_verified == entry.edge_segments_count
                && (!require_normalized_events || run_is_normalized_complete(entry))
        })
        .collect::<Vec<_>>();
    if runs.is_empty() && !require_normalized_events {
        runs = index.runs.iter().collect::<Vec<_>>();
    }
    runs.sort_by(|left, right| {
        run_completed_at(left)
            .cmp(&run_completed_at(right))
            .then_with(|| left.run_id.cmp(&right.run_id))
    });
    let take = latest_n_runs.unwrap_or_else(|| usize::from(latest_run).max(1));
    let mut selected = runs
        .into_iter()
        .rev()
        .take(take)
        .map(|entry| entry.run_id.clone())
        .collect::<Vec<_>>();
    selected.reverse();
    if selected.is_empty() {
        return Err(anyhow!("no runs available for research worker selection"));
    }
    Ok(selected)
}

#[derive(Debug, Clone, Default)]
struct ResearchWorkerRemoteKeys {
    feature_outputs_remote_key: Option<String>,
    decision_outputs_remote_key: Option<String>,
    fill_outputs_remote_key: Option<String>,
    backtest_outputs_remote_key: Option<String>,
    calibration_outputs_remote_key: Option<String>,
    research_manifest_remote_key: Option<String>,
}

fn research_worker_output_remote_keys(
    manifest: Option<&ArtifactManifest>,
) -> ResearchWorkerRemoteKeys {
    let Some(manifest) = manifest else {
        return ResearchWorkerRemoteKeys::default();
    };
    let feature_outputs_remote_key = manifest
        .artifacts
        .iter()
        .find(|artifact| {
            artifact.relative_path.contains("features")
                || artifact.relative_path.contains("feature_distribution")
                || artifact
                    .relative_path
                    .ends_with("export_chunks_manifest.json")
        })
        .map(|artifact| artifact.remote_key.clone());
    let backtest_outputs_remote_key = manifest
        .artifacts
        .iter()
        .find(|artifact| {
            artifact.relative_path.contains("research_cycle_summary")
                || artifact.relative_path.contains("backtest_readiness")
                || artifact.relative_path.contains("live_collection_quality")
        })
        .map(|artifact| artifact.remote_key.clone())
        .or_else(|| Some(manifest.remote_manifest_key.clone()));
    let calibration_outputs_remote_key = manifest
        .artifacts
        .iter()
        .find(|artifact| {
            artifact.artifact_type == "calibration"
                || artifact.relative_path.contains("calibration")
        })
        .map(|artifact| artifact.remote_key.clone());
    let decision_outputs_remote_key = manifest
        .artifacts
        .iter()
        .find(|artifact| artifact.relative_path.contains("decisions"))
        .map(|artifact| artifact.remote_key.clone());
    let fill_outputs_remote_key = manifest
        .artifacts
        .iter()
        .find(|artifact| artifact.relative_path.contains("fills"))
        .map(|artifact| artifact.remote_key.clone());
    ResearchWorkerRemoteKeys {
        feature_outputs_remote_key,
        decision_outputs_remote_key,
        fill_outputs_remote_key,
        backtest_outputs_remote_key,
        calibration_outputs_remote_key,
        research_manifest_remote_key: Some(manifest.remote_manifest_key.clone()),
    }
}

