async fn refresh_replay_research_metadata(
    loaded: &LoadedConfig,
    replay_run_id: &str,
) -> Result<(BacktestReadinessSummary, RunMetadataBackfillSummary, Option<ArtifactManifest>)> {
    let _ = verify_r2_manifest_for_run(loaded, replay_run_id, false, true).await?;
    let refreshed_quality = analyze_live_collection_summary(loaded, replay_run_id, false).await?;
    let refreshed_readiness = backtest_readiness_summary(
        loaded,
        &refreshed_quality,
        &current_backtest_thresholds(loaded),
    )?;
    let _ = write_backtest_readiness_reports(loaded, &refreshed_readiness)?;
    materialize_research_review_reports(
        loaded,
        replay_run_id,
        &refreshed_quality,
        &refreshed_readiness,
    )?;
    let mut backfill = collect_run_metadata_backfill_summary(loaded, replay_run_id, false).await?;
    persist_backfilled_run_metadata(loaded, &backfill)?;
    let _ = write_metadata_backfill_reports(loaded, &backfill)?;
    let _ = write_canonical_run_summary_reports(loaded, replay_run_id, &backfill)?;
    let _ = write_canonical_runtime_health_reports(loaded, replay_run_id, &backfill)?;
    let _ = refresh_backtest_readiness_reports_from_backfill(loaded, replay_run_id, &backfill)?;
    let mut manifest = load_manifest_if_present(loaded, replay_run_id)?;
    if let Some(entry) = manifest.as_mut() {
        if entry.finalization_status == "manifest_initialized"
            && entry.r2_full_verification_status == "verified"
            && entry.manifest_consistency_passed
        {
            entry.finalization_status = "completed".to_owned();
            entry.run_status = current_manifest_run_status(entry);
            write_manifest(&r2_manifest_path_for_run(loaded, replay_run_id)?, entry)?;
            backfill = collect_run_metadata_backfill_summary(loaded, replay_run_id, false).await?;
            persist_backfilled_run_metadata(loaded, &backfill)?;
            let _ = write_metadata_backfill_reports(loaded, &backfill)?;
            let _ = write_canonical_run_summary_reports(loaded, replay_run_id, &backfill)?;
            let _ =
                refresh_backtest_readiness_reports_from_backfill(loaded, replay_run_id, &backfill)?;
        }
    }
    Ok((refreshed_readiness, backfill, manifest))
}

fn resolve_research_worker_output_dir(local_output_dir: &Path, source_run_id: &str) -> PathBuf {
    let nested = local_output_dir.join(source_run_id);
    if nested.join("research_worker_summary.json").exists() {
        nested
    } else {
        local_output_dir.to_path_buf()
    }
}

fn derive_research_batch_id(base_output_dir: &Path, explicit: Option<&str>) -> String {
    explicit
        .filter(|value| !value.trim().is_empty())
        .map(ToOwned::to_owned)
        .or_else(|| {
            base_output_dir
                .file_name()
                .and_then(|value| value.to_str())
                .map(ToOwned::to_owned)
        })
        .unwrap_or_else(|| "research_batch".to_owned())
}

fn research_batch_root(base_output_dir: &Path, batch_id: &str, explicit: bool) -> PathBuf {
    if explicit
        && base_output_dir
            .file_name()
            .and_then(|value| value.to_str())
            != Some(batch_id)
    {
        base_output_dir.join(batch_id)
    } else {
        base_output_dir.to_path_buf()
    }
}

fn research_batch_state_path(batch_root: &Path) -> PathBuf {
    batch_root.join("research_batch_state.json")
}

fn write_research_batch_state(batch_root: &Path, state: &ResearchBatchState) -> Result<()> {
    fs::create_dir_all(batch_root)?;
    let state_path = research_batch_state_path(batch_root);
    fs::write(&state_path, serde_json::to_vec_pretty(state)?)?;
    let markdown = format!(
        "# Research Batch State\n\n- batch_id: {}\n- selected_source_runs: {:?}\n- completed_source_runs: {:?}\n- failed_source_runs: {:?}\n- skipped_source_runs: {:?}\n- in_progress_source_run: {}\n- aggregate_status: {}\n",
        state.batch_id,
        state.selected_source_runs,
        state.completed_source_runs,
        state.failed_source_runs,
        state.skipped_source_runs,
        state.in_progress_source_run.clone().unwrap_or_default(),
        state.aggregate_status,
    );
    write_report(&batch_root.join("research_batch_state.md"), &markdown)?;
    Ok(())
}

fn load_research_batch_state_if_present(batch_root: &Path) -> Result<Option<ResearchBatchState>> {
    let path = research_batch_state_path(batch_root);
    if !path.exists() {
        return Ok(None);
    }
    Ok(Some(serde_json::from_slice(&fs::read(path)?)?))
}

fn inspect_research_batch_command(
    loaded: &LoadedConfig,
    batch_id: &str,
    local_output_dir: Option<&str>,
) -> Result<()> {
    let base_output_dir =
        PathBuf::from(local_output_dir.unwrap_or(&loaded.config.research_worker.local_output_dir));
    let batch_root = research_batch_root(&base_output_dir, batch_id, true);
    let state = load_research_batch_state_if_present(&batch_root)?.ok_or_else(|| {
        anyhow!(
            "research batch state not found at {}",
            research_batch_state_path(&batch_root).display()
        )
    })?;
    println!("{}", serde_json::to_string_pretty(&state)?);
    Ok(())
}

fn research_outputs_remote_prefix(source_run_id: &str, replay_run_id: Option<&str>) -> String {
    match replay_run_id {
        Some(replay_run_id) if !replay_run_id.trim().is_empty() => {
            format!("{source_run_id}/{replay_run_id}")
        }
        _ => format!("{source_run_id}/derived_unknown"),
    }
}

fn research_remote_base_prefix(client: &R2Client) -> String {
    let _ = client;
    "research".to_owned()
}

fn classify_research_output_relative_path(
    output_dir: &Path,
    replay_report_dir: Option<&Path>,
    path: &Path,
    idx: usize,
) -> String {
    let file_name = path
        .file_name()
        .and_then(|value| value.to_str())
        .unwrap_or("artifact");
    if path.starts_with(output_dir) {
        return format!("reports/{file_name}");
    }
    if let Some(report_dir) = replay_report_dir {
        if path.starts_with(report_dir) {
            let relative = path
                .strip_prefix(report_dir)
                .unwrap_or(path)
                .to_string_lossy()
                .replace('\\', "/");
            let relative_lower = relative.to_ascii_lowercase();
            if relative_lower.contains("artifact_manifest")
                || relative_lower.contains("r2_upload_summary")
                || relative_lower.contains("metadata_backfill")
            {
                return format!("manifest/{relative}");
            }
            if relative_lower.contains("calibration") {
                return format!("calibration/{relative}");
            }
            if relative_lower.contains("fills") {
                return format!("fills/{relative}");
            }
            if relative_lower.contains("decision") {
                return format!("decisions/{relative}");
            }
            if relative_lower.contains("feature")
                || relative_lower.contains("export_chunks_manifest")
            {
                return format!("features/{relative}");
            }
            return format!("reports/{relative}");
        }
    }
    format!("generated/{idx:04}_{file_name}")
}

async fn upload_research_results_r2_internal(
    loaded: &LoadedConfig,
    source_run_id: &str,
    local_output_dir: &str,
    verify: bool,
) -> Result<ResearchResultsUploadCommandResult> {
    let output_dir = resolve_research_worker_output_dir(Path::new(local_output_dir), source_run_id);
    let summary_path = output_dir.join("research_worker_summary.json");
    if !summary_path.exists() {
        return Err(anyhow!(
            "research worker summary not found at {}",
            summary_path.display()
        ));
    }
    let mut summary = read_json_file::<ResearchWorkerRunSummary>(&summary_path)
        .ok_or_else(|| anyhow!("failed to parse {}", summary_path.display()))?;
    let source_index = load_dataset_index_local_or_r2(loaded, true).await.ok();
    let source_entry = source_index
        .as_ref()
        .and_then(|index| index.runs.iter().find(|entry| entry.run_id == source_run_id));
    normalize_research_worker_summary_from_source_entry(loaded, source_entry, &mut summary)?;
    let source_report_dir = run_report_dir_for(loaded, source_run_id)?;
    let client = r2_client_for_command(loaded, false, true, false)?;
    let bucket = client.bucket_for_reports()?;

    let mut upload_paths = Vec::<PathBuf>::new();
    for name in ["research_worker_summary.json", "research_worker_summary.md"] {
        let path = output_dir.join(name);
        if path.exists() {
            upload_paths.push(path);
        }
    }
    for artifact in &summary.generated_artifacts {
        let path = PathBuf::from(artifact);
        if path.exists() {
            upload_paths.push(path);
        }
    }
    upload_paths.sort();
    upload_paths.dedup();

    let replay_report_dir = summary
        .replay_run_id
        .as_deref()
        .map(|run_id| run_report_dir_for(loaded, run_id))
        .transpose()?;
    let remote_prefix = research_outputs_remote_prefix(
        source_run_id,
        summary.replay_run_id.as_deref(),
    );

    let mut uploaded_files = Vec::new();
    let mut verified_files = Vec::new();
    let mut failed_files = Vec::new();
    let mut research_outputs_remote_prefix = Some(format!(
        "{}/{}",
        research_remote_base_prefix(&client),
        remote_prefix
    ));
    let mut feature_outputs_remote_key = summary.feature_outputs_remote_key.clone();
    let mut backtest_outputs_remote_key = summary.backtest_outputs_remote_key.clone();
    let mut calibration_outputs_remote_key = summary.calibration_outputs_remote_key.clone();
    let mut decision_outputs_remote_key = summary.decision_outputs_remote_key.clone();
    let mut fill_outputs_remote_key = summary.fill_outputs_remote_key.clone();
    let mut research_manifest_remote_key = summary.research_manifest_remote_key.clone();

    for (idx, path) in upload_paths.iter().enumerate() {
        let relative =
            classify_research_output_relative_path(&output_dir, replay_report_dir.as_deref(), path, idx);
        let remote_key = client.managed_key(
            &research_remote_base_prefix(&client),
            &format!("{remote_prefix}/{relative}"),
        );
        let prepared = client.prepare_upload(
            path,
            bucket.clone(),
            remote_key.clone(),
            &artifact_content_type(path),
            BTreeMap::new(),
            Some(false),
        )?;
        let result = client
            .upload_prepared(&prepared, verify.then_some(true))
            .await?;
        if result.uploaded {
            uploaded_files.push(remote_key.clone());
        }
        if verify && result.verified {
            verified_files.push(remote_key.clone());
        }
        if verify && !result.verified {
            failed_files.push(remote_key.clone());
        }
        let path_text = path.to_string_lossy();
        let path_text_lower = path_text.to_ascii_lowercase();
        if path_text_lower.contains("export_chunks_manifest") {
            feature_outputs_remote_key = Some(remote_key.clone());
        } else if feature_outputs_remote_key.is_none()
            && (path_text_lower.contains("features")
                || path_text_lower.contains("feature_distribution"))
        {
            feature_outputs_remote_key = Some(remote_key.clone());
        }
        if path_text_lower.contains("decisions") {
            decision_outputs_remote_key = Some(remote_key.clone());
        }
        if path_text_lower.contains("fills") {
            fill_outputs_remote_key = Some(remote_key.clone());
        }
        if path_text_lower.ends_with("backtest_readiness.json") {
            backtest_outputs_remote_key = Some(remote_key.clone());
        } else if backtest_outputs_remote_key.is_none()
            && (path_text_lower.contains("backtest")
                || path_text_lower.contains("research_cycle_summary")
                || path_text_lower.contains("strategy_summary")
                || path_text_lower.contains("live_collection_quality")
                || path_text_lower.contains("readiness")
                || path_text_lower.contains("pnl_attribution")
                || path_text_lower.contains("rejection_reason_summary"))
        {
            backtest_outputs_remote_key = Some(remote_key.clone());
        }
        if path_text_lower.contains("calibration") {
            calibration_outputs_remote_key = Some(remote_key.clone());
        }
        if path_text_lower.contains("artifact_manifest") {
            research_manifest_remote_key = Some(remote_key.clone());
        } else if research_manifest_remote_key.is_none() && path_text_lower.contains("r2_upload_summary")
        {
            research_manifest_remote_key = Some(remote_key.clone());
        }
    }

    summary.research_outputs_available = !uploaded_files.is_empty();
    summary.research_worker_processed = true;
    summary.research_outputs_remote_prefix = research_outputs_remote_prefix.clone();
    summary.feature_outputs_remote_key = feature_outputs_remote_key.clone();
    summary.backtest_outputs_remote_key = backtest_outputs_remote_key.clone();
    summary.calibration_outputs_remote_key = calibration_outputs_remote_key.clone();
    summary.decision_outputs_remote_key = decision_outputs_remote_key.clone();
    summary.fill_outputs_remote_key = fill_outputs_remote_key.clone();
    summary.research_manifest_remote_key = research_manifest_remote_key.clone();
    summary.research_r2_verified = verify && failed_files.is_empty() && !verified_files.is_empty();
    summary.research_r2_verified_count = verified_files.len() as u64;
    summary.research_r2_failed_count = failed_files.len() as u64;
    write_research_worker_summary_files(&source_report_dir, &output_dir, &summary)?;

    let upload_summary = ResearchResultsUploadSummary {
        command: "upload-research-results-r2".to_owned(),
        source_run_id: source_run_id.to_owned(),
        replay_run_id: summary.replay_run_id.clone(),
        output_dir: output_dir.display().to_string(),
        uploaded_files,
        verified_files,
        failed_files,
        research_outputs_available: summary.research_outputs_available,
        research_outputs_remote_prefix,
        feature_outputs_remote_key,
        backtest_outputs_remote_key,
        calibration_outputs_remote_key,
        decision_outputs_remote_key,
        fill_outputs_remote_key,
        research_manifest_remote_key,
        research_r2_verified: summary.research_r2_verified,
        research_r2_verified_count: summary.research_r2_verified_count,
        research_r2_failed_count: summary.research_r2_failed_count,
    };
    for root in [&source_report_dir, &output_dir] {
        write_report(
            &root.join("research_results_upload_summary.md"),
            &format!(
                "# Research Results Upload Summary\n\n- source_run_id: {}\n- replay_run_id: {}\n- uploaded_files: {:?}\n- verified_files: {:?}\n- failed_files: {:?}\n- research_outputs_remote_prefix: {}\n- feature_outputs_remote_key: {}\n- decision_outputs_remote_key: {}\n- fill_outputs_remote_key: {}\n- backtest_outputs_remote_key: {}\n- calibration_outputs_remote_key: {}\n- research_manifest_remote_key: {}\n- research_r2_verified: {}\n- research_r2_verified_count: {}\n- research_r2_failed_count: {}\n",
                upload_summary.source_run_id,
                upload_summary.replay_run_id.clone().unwrap_or_default(),
                upload_summary.uploaded_files,
                upload_summary.verified_files,
                upload_summary.failed_files,
                upload_summary
                    .research_outputs_remote_prefix
                    .clone()
                    .unwrap_or_default(),
                upload_summary
                    .feature_outputs_remote_key
                    .clone()
                    .unwrap_or_default(),
                upload_summary
                    .decision_outputs_remote_key
                    .clone()
                    .unwrap_or_default(),
                upload_summary
                    .fill_outputs_remote_key
                    .clone()
                    .unwrap_or_default(),
                upload_summary
                    .backtest_outputs_remote_key
                    .clone()
                    .unwrap_or_default(),
                upload_summary
                    .calibration_outputs_remote_key
                    .clone()
                    .unwrap_or_default(),
                upload_summary
                    .research_manifest_remote_key
                    .clone()
                    .unwrap_or_default(),
                upload_summary.research_r2_verified,
                upload_summary.research_r2_verified_count,
                upload_summary.research_r2_failed_count,
            ),
        )?;
        fs::write(
            root.join("research_results_upload_summary.json"),
            serde_json::to_vec_pretty(&upload_summary)?,
        )?;
    }

    let dataset_index_guard =
        acquire_dataset_index_lock(loaded, "upload-research-results-r2")?;
    refresh_dataset_index_lock(&dataset_index_guard, "upload-research-results-r2")?;
    let mut authoritative_index = match download_dataset_index_from_r2(loaded).await {
        Ok(index) => index,
        Err(_) => load_dataset_index_local_or_r2(loaded, false).await?,
    };
    let local_index = build_dataset_index(loaded)?;
    if let Some(source_entry) = local_index
        .runs
        .iter()
        .find(|entry| entry.run_id == source_run_id)
        .cloned()
    {
        upsert_dataset_index_entry(&mut authoritative_index, source_entry);
    }
    apply_research_outputs_to_dataset_index(
        loaded,
        &mut authoritative_index,
        source_run_id,
        &summary,
        &upload_summary,
    )
    .await?;
    if let Some(replay_run_id) = summary.replay_run_id.as_deref() {
        if let Some(replay_entry) = local_index
            .runs
            .iter()
            .find(|entry| entry.run_id == replay_run_id)
            .cloned()
        {
            upsert_dataset_index_entry(&mut authoritative_index, replay_entry);
        }
    }
    refresh_dataset_index_lock(&dataset_index_guard, "upload-research-results-r2")?;
    let dataset_index_upload =
        upload_dataset_index_value_r2(loaded, &authoritative_index, false, verify).await?;
    Ok(ResearchResultsUploadCommandResult {
        upload_summary,
        dataset_index_updated: dataset_index_upload,
    })
}

async fn upload_research_results_r2_command(
    loaded: &LoadedConfig,
    source_run_id: &str,
    local_output_dir: &str,
    verify: bool,
) -> Result<()> {
    let result =
        upload_research_results_r2_internal(loaded, source_run_id, local_output_dir, verify)
            .await?;
    println!("{}", serde_json::to_string_pretty(&result)?);
    Ok(())
}

async fn refresh_research_worker_summary_command(
    loaded: &LoadedConfig,
    source_run_id: &str,
    local_output_dir: &str,
    dataset_index_r2: bool,
) -> Result<()> {
    let output_dir = resolve_research_worker_output_dir(Path::new(local_output_dir), source_run_id);
    let summary_path = output_dir.join("research_worker_summary.json");
    if !summary_path.exists() {
        return Err(anyhow!(
            "research worker summary not found at {}",
            summary_path.display()
        ));
    }
    let mut summary = read_json_file::<ResearchWorkerRunSummary>(&summary_path)
        .ok_or_else(|| anyhow!("failed to parse {}", summary_path.display()))?;
    let source_index = load_dataset_index_local_or_r2(loaded, dataset_index_r2)
        .await
        .with_context(|| "loading dataset index for research summary refresh")?;
    let source_entry = source_index
        .runs
        .iter()
        .find(|entry| entry.run_id == source_run_id);
    normalize_research_worker_summary_from_source_entry(loaded, source_entry, &mut summary)?;
    let source_report_dir = run_report_dir_for(loaded, source_run_id)?;
    write_research_worker_summary_files(&source_report_dir, &output_dir, &summary)?;
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "refresh-research-worker-summary",
            "source_run_id": source_run_id,
            "output_dir": output_dir.display().to_string(),
            "summary_path": summary_path.display().to_string(),
            "fallback_used": summary.fallback_used,
            "fallback_source": summary.fallback_source,
            "normalized_segments_processed": summary.normalized_segments_processed,
            "normalized_records_loaded": summary.normalized_records_loaded,
            "edge_dataset_complete": summary.edge_dataset_complete,
            "research_replay_confidence": summary.research_replay_confidence,
            "source_artifact_type_used": summary.source_artifact_type_used,
            "source_segments_verified": summary.source_segments_verified,
            "derived_run_id": summary.derived_run_id,
        }))?
    );
    Ok(())
}

async fn run_research_worker_command(
    loaded: &LoadedConfig,
    run_id: Option<&str>,
    latest_run: bool,
    latest_n_runs: Option<usize>,
    dataset_index_r2: bool,
    from_r2: bool,
    local_output_dir: Option<&str>,
    compute_features: bool,
    run_backtests: bool,
    generate_exports: bool,
    update_calibration: bool,
    resume: bool,
    resume_batch: Option<&str>,
    enable_enrichment: bool,
    enrichment_canary: bool,
    max_runs_this_invocation: Option<usize>,
    require_normalized_events: bool,
    allow_source_events_fallback: bool,
    skip_completed_research: bool,
    no_live_streams: bool,
) -> Result<()> {
    forbid_heavy_vps_research_paths_in_edge_mode(loaded, "run-research-worker")?;
    if !no_live_streams {
        return Err(anyhow!(
            "run-research-worker requires --no-live-streams; it must not connect to live Geyser or shreds"
        ));
    }
    let explicit_work_requested =
        compute_features || run_backtests || generate_exports || update_calibration;
    let effective_compute_features = if explicit_work_requested {
        compute_features || run_backtests || generate_exports || update_calibration
    } else {
        loaded.config.research_worker.compute_features
    };
    let effective_run_backtests = if explicit_work_requested {
        run_backtests
    } else {
        loaded.config.research_worker.run_backtests
    };
    let effective_generate_exports = if explicit_work_requested {
        generate_exports
    } else {
        loaded.config.research_worker.generate_exports
    };
    let effective_update_calibration = if explicit_work_requested {
        update_calibration
    } else {
        loaded.config.research_worker.update_calibration
    };
    let prefer_r2_index = dataset_index_r2
        || loaded
            .config
            .research_worker
            .input
            .trim()
            .eq_ignore_ascii_case("r2");
    let allow_remote_segments = from_r2
        || loaded.config.research_worker.download_segments
        || loaded.config.research_worker.stream_segments_from_r2;
    let index = load_dataset_index_local_or_r2(loaded, prefer_r2_index)
        .await
        .with_context(|| {
            format!("loading dataset index for research worker (prefer_r2_index={prefer_r2_index})")
        })?;
    let selected_run_ids = select_research_worker_run_ids(
        &index,
        run_id,
        latest_run,
        latest_n_runs,
        require_normalized_events,
        allow_source_events_fallback,
    )?;
    let base_output_dir =
        PathBuf::from(local_output_dir.unwrap_or(&loaded.config.research_worker.local_output_dir));
    let batch_id = derive_research_batch_id(&base_output_dir, resume_batch);
    let batch_root = research_batch_root(&base_output_dir, &batch_id, resume_batch.is_some());
    fs::create_dir_all(&batch_root)?;
    let mut batch_state = if resume || resume_batch.is_some() {
        load_research_batch_state_if_present(&batch_root)?.unwrap_or_else(|| ResearchBatchState {
            batch_id: batch_id.clone(),
            selected_source_runs: selected_run_ids.clone(),
            aggregate_status: "initialized".to_owned(),
            ..Default::default()
        })
    } else {
        ResearchBatchState {
            batch_id: batch_id.clone(),
            selected_source_runs: selected_run_ids.clone(),
            aggregate_status: "initialized".to_owned(),
            ..Default::default()
        }
    };
    if batch_state.selected_source_runs.is_empty() {
        batch_state.selected_source_runs = selected_run_ids.clone();
    }
    write_research_batch_state(&batch_root, &batch_state)?;
    let mut batch = ResearchWorkerBatchSummary {
        command: "run-research-worker".to_owned(),
        run_count: batch_state.selected_source_runs.len(),
        summaries: Vec::new(),
    };
    let mut processed_this_invocation = 0usize;
    for source_run_id in batch_state.selected_source_runs.clone() {
        if batch_state.completed_source_runs.contains(&source_run_id) {
            continue;
        }
        let source_entry = index
            .runs
            .iter()
            .find(|entry| entry.run_id == source_run_id)
            .cloned();
        if skip_completed_research {
            if let Some(entry) = source_entry.as_ref() {
                if run_has_verified_research_outputs(entry) {
                    batch_state.in_progress_source_run = None;
                    if !batch_state.completed_source_runs.contains(&source_run_id) {
                        batch_state.completed_source_runs.push(source_run_id.clone());
                    }
                    if !batch_state.skipped_source_runs.contains(&source_run_id) {
                        batch_state.skipped_source_runs.push(source_run_id.clone());
                    }
                    batch_state.per_run_status.insert(
                        source_run_id.clone(),
                        "skipped_existing_verified_research".to_owned(),
                    );
                    if let Some(derived_run_id) = entry.research_latest_derived_run_id.clone() {
                        batch_state
                            .per_run_derived_run_id
                            .insert(source_run_id.clone(), derived_run_id);
                    }
                    batch_state.per_run_r2_upload_status.insert(
                        source_run_id.clone(),
                        format!(
                            "verified_existing:{}/{}",
                            entry.research_r2_verified_count,
                            entry.research_r2_verified_count + entry.research_r2_failed_count
                        ),
                    );
                    batch_state.aggregate_status = if batch_state.completed_source_runs.len()
                        == batch_state.selected_source_runs.len()
                    {
                        "completed".to_owned()
                    } else if batch_state.failed_source_runs.is_empty() {
                        "partial_incomplete".to_owned()
                    } else {
                        "partial_with_failures".to_owned()
                    };
                    write_research_batch_state(&batch_root, &batch_state)?;
                    continue;
                }
            }
        }
        if let Some(limit) = max_runs_this_invocation {
            if processed_this_invocation >= limit {
                break;
            }
        }
        if require_normalized_events
            && !allow_source_events_fallback
            && source_entry
                .as_ref()
                .map(|entry| !run_is_normalized_complete(entry))
                .unwrap_or(false)
        {
            if !batch_state.skipped_source_runs.contains(&source_run_id) {
                batch_state.skipped_source_runs.push(source_run_id.clone());
            }
            batch_state.per_run_status.insert(
                source_run_id.clone(),
                "normalized_events_required_but_unavailable".to_owned(),
            );
            batch_state.in_progress_source_run = None;
            batch_state.aggregate_status = if batch_state.completed_source_runs.len()
                == batch_state.selected_source_runs.len()
            {
                "completed".to_owned()
            } else if batch_state.failed_source_runs.is_empty() {
                "partial_incomplete".to_owned()
            } else {
                "partial_with_failures".to_owned()
            };
            write_research_batch_state(&batch_root, &batch_state)?;
            continue;
        }
        batch_state.in_progress_source_run = Some(source_run_id.clone());
        batch_state
            .per_run_status
            .insert(source_run_id.clone(), "in_progress".to_owned());
        write_research_batch_state(&batch_root, &batch_state)?;
        let output_dir = batch_root.join(&source_run_id);
        let run_result: Result<(ResearchWorkerRunSummary, String)> = async {
            let hydration = hydrate_normalized_event_segments_for_run(
                loaded,
                &source_run_id,
                allow_remote_segments,
            )
            .await
            .with_context(|| format!("hydrating normalized edge segments for {source_run_id}"))?;
            if require_normalized_events
                && !allow_source_events_fallback
                && (hydration.fallback_used
                    || hydration.source_artifact_type_used.as_deref()
                        != Some("normalized_events")
                    || hydration.normalized_records_loaded == 0)
            {
                return Err(anyhow!(
                    "normalized_events_required_but_unavailable for source run {source_run_id}"
                ));
            }
            let mut loaded_for_run = loaded.clone();
            loaded_for_run.config.runtime.mode = RuntimeModeName::ResearchWorker;
            loaded_for_run.config.research_worker.enabled = true;
            loaded_for_run.config.environment.run_id = derived_run_id("paper-replay");
            let resolved = RuntimeResolvedConfig::from_loaded(
                loaded_for_run.clone(),
                Some(RuntimeMode::PaperFromStore),
            )
            .with_context(|| {
                format!("resolving runtime config for research replay {source_run_id}")
            })?;
            let mut supervisor = Supervisor::new(resolved)
                .with_context(|| format!("creating supervisor for {source_run_id}"))?;
            let replay_summary = supervisor
                .run_from_store_selection(Some(&source_run_id), None)
                .await
                .with_context(|| {
                    format!("replaying normalized events from store for {source_run_id}")
                })?;
            let replay_run_id = replay_summary.run_id.clone();
            let quality = analyze_live_collection_summary(&loaded_for_run, &replay_run_id, false)
                .await
                .with_context(|| format!("analyzing replay output for {replay_run_id}"))?;
            let readiness = backtest_readiness_summary(
                &loaded_for_run,
                &quality,
                &current_backtest_thresholds(&loaded_for_run),
            )
            .with_context(|| format!("computing readiness for replay run {replay_run_id}"))?;
            let _ = write_backtest_readiness_reports(&loaded_for_run, &readiness)
                .with_context(|| format!("writing readiness reports for {replay_run_id}"))?;
            materialize_research_review_reports(
                &loaded_for_run,
                &replay_run_id,
                &quality,
                &readiness,
            )
            .with_context(|| {
                format!("materializing research review reports for {replay_run_id}")
            })?;
            if effective_generate_exports {
                export_features(
                    &loaded_for_run,
                    "csv",
                    Some(&replay_run_id),
                    false,
                    false,
                    None,
                    false,
                    false,
                    false,
                    false,
                    false,
                )
                .await
                .with_context(|| format!("exporting features for replay run {replay_run_id}"))?;
                export_decisions(&loaded_for_run, Some(&replay_run_id), false, false, None)
                    .await
                    .with_context(|| format!("exporting decisions for replay run {replay_run_id}"))?;
                export_fills(&loaded_for_run, Some(&replay_run_id), false, false, None)
                    .await
                    .with_context(|| format!("exporting fills for replay run {replay_run_id}"))?;
            }
            if effective_run_backtests || effective_generate_exports {
                export_rpc_ledger(&loaded_for_run, Some(&replay_run_id), false, false)
                    .await
                    .with_context(|| format!("exporting RPC ledger for replay run {replay_run_id}"))?;
            }
            let mut warnings = hydration.skipped_segments.clone();
            if effective_update_calibration {
                let replay_metadata =
                    latest_metadata_for_run(&storage_engine(&loaded_for_run)?, &replay_run_id)
                        .with_context(|| format!("loading replay metadata for {replay_run_id}"))?;
                if replay_metadata
                    .as_ref()
                    .and_then(|record| record.record.post_run_calibration_hash.clone())
                    .is_none()
                {
                    warnings.push(
                        "calibration_update_requested_but_no_post_run_calibration_hash_present"
                            .to_owned(),
                    );
                }
            }
            if enable_enrichment {
                warnings.push(
                    "enrichment_requested_but_not_yet_executed_in_phase48_batch_runner"
                        .to_owned(),
                );
            }
            if enrichment_canary {
                warnings.push(
                    "enrichment_canary_requested_but_not_yet_executed_in_phase49_batch_runner"
                        .to_owned(),
                );
            }
            let mut refreshed_readiness = None;
            let mut refreshed_backfill = None;
            let mut replay_manifest = None;
            if loaded_for_run.config.r2.enabled && loaded_for_run.config.r2.upload_enabled {
                upload_artifacts_r2_command(
                    &loaded_for_run,
                    Some(&replay_run_id),
                    false,
                    false,
                    false,
                    false,
                    false,
                    false,
                    false,
                    true,
                    effective_generate_exports,
                    effective_update_calibration,
                    false,
                    true,
                    false,
                    false,
                    true,
                    false,
                    false,
                    false,
                    true,
                    None,
                    None,
                    true,
                )
                .await
                .with_context(|| {
                    format!("uploading research replay artifacts for {replay_run_id}")
                })?;
                let (readiness, backfill, manifest) =
                    refresh_replay_research_metadata(&loaded_for_run, &replay_run_id)
                        .await
                        .with_context(|| {
                            format!(
                                "refreshing replay metadata after verified upload for {replay_run_id}"
                            )
                        })?;
                refreshed_readiness = Some(readiness);
                refreshed_backfill = Some(backfill);
                replay_manifest = manifest;
            }
            if replay_manifest.is_none() {
                replay_manifest = load_manifest_if_present(&loaded_for_run, &replay_run_id)
                    .with_context(|| {
                        format!("loading artifact manifest for replay run {replay_run_id}")
                    })?;
            }
            let remote_keys = research_worker_output_remote_keys(replay_manifest.as_ref());
            let generated_artifacts =
                collect_artifacts_for_run(&storage_engine(&loaded_for_run)?, &replay_run_id)?
                    .into_iter()
                    .map(|artifact| artifact.path)
                    .collect::<Vec<_>>();
            let source_report_dir = run_report_dir_for(&loaded_for_run, &source_run_id)?;
            let mut summary = ResearchWorkerRunSummary {
                run_id: source_run_id.clone(),
                source_run_id: source_run_id.clone(),
                replay_run_id: Some(replay_run_id.clone()),
                derived_run_id: Some(replay_run_id.clone()),
                hydrated_from_r2: hydration.hydrated_from_r2,
                normalized_segments_processed: hydration.normalized_segments_processed,
                normalized_records_loaded: hydration.normalized_records_loaded,
                compute_features: effective_compute_features,
                run_backtests: effective_run_backtests,
                generate_exports: effective_generate_exports,
                update_calibration: effective_update_calibration,
                research_outputs_available: !generated_artifacts.is_empty(),
                research_worker_processed: true,
                local_output_dir: output_dir.display().to_string(),
                generated_artifacts,
                research_outputs_remote_prefix: None,
                feature_outputs_remote_key: remote_keys.feature_outputs_remote_key,
                backtest_outputs_remote_key: remote_keys.backtest_outputs_remote_key,
                calibration_outputs_remote_key: remote_keys.calibration_outputs_remote_key,
                decision_outputs_remote_key: remote_keys.decision_outputs_remote_key,
                fill_outputs_remote_key: remote_keys.fill_outputs_remote_key,
                research_manifest_remote_key: remote_keys.research_manifest_remote_key,
                research_r2_verified: refreshed_backfill
                    .as_ref()
                    .map(|summary| summary.r2_verified)
                    .unwrap_or(false),
                research_r2_verified_count: refreshed_backfill
                    .as_ref()
                    .map(|summary| summary.r2_verified_count)
                    .unwrap_or_default(),
                research_r2_failed_count: refreshed_backfill
                    .as_ref()
                    .map(|summary| summary.r2_failed_count)
                    .unwrap_or_default(),
                research_derived_ready: refreshed_backfill
                    .as_ref()
                    .map(|summary| summary.backtest_ready)
                    .or_else(|| refreshed_readiness.as_ref().map(|summary| summary.ready))
                    .unwrap_or(readiness.ready),
                research_derived_readiness_level: refreshed_backfill
                    .as_ref()
                    .map(|summary| summary.readiness_level.clone())
                    .or_else(|| {
                        refreshed_readiness
                            .as_ref()
                            .map(|summary| summary.readiness_level.clone())
                    })
                    .unwrap_or_else(|| readiness.readiness_level.clone()),
                edge_dataset_complete: hydration.edge_dataset_complete,
                normalized_events_missing: hydration.normalized_events_missing,
                fallback_used: hydration.fallback_used,
                fallback_reason: hydration.fallback_reason.clone(),
                fallback_source: hydration.fallback_source.clone(),
                invalid_segment_count: hydration.invalid_segment_count,
                invalid_segments: hydration.invalid_segments.clone(),
                unresolved_segment_warnings: hydration.unresolved_segment_warnings.clone(),
                fallback_replay_affected: hydration.fallback_replay_affected,
                normalized_replay_warning: hydration.normalized_replay_warning,
                normalized_replay_affected: hydration.normalized_replay_affected,
                normalized_invalid_segment_count: hydration.normalized_invalid_segment_count,
                source_fallback_warning: hydration.source_fallback_warning,
                source_fallback_affected: hydration.source_fallback_affected,
                source_artifact_type_used: hydration.source_artifact_type_used.clone(),
                source_segments_verified: hydration.source_segments_verified,
                research_replay_confidence: hydration.research_replay_confidence,
                warnings,
            };
            normalize_research_worker_summary_from_source_entry(
                loaded,
                source_entry.as_ref(),
                &mut summary,
            )?;
            write_research_worker_summary_files(&source_report_dir, &output_dir, &summary)?;
            let mut upload_status = "not_uploaded".to_owned();
            if loaded_for_run.config.r2.enabled && loaded_for_run.config.r2.upload_enabled {
                let upload_result = upload_research_results_r2_internal(
                    &loaded_for_run,
                    &source_run_id,
                    &output_dir.display().to_string(),
                    true,
                )
                .await
                .with_context(|| {
                    format!("uploading research worker results for source run {source_run_id}")
                })?;
                upload_status = if upload_result.upload_summary.research_r2_verified {
                    format!(
                        "verified:{}/{}",
                        upload_result.upload_summary.research_r2_verified_count,
                        upload_result.upload_summary.research_r2_verified_count
                            + upload_result.upload_summary.research_r2_failed_count
                    )
                } else {
                    format!(
                        "partial:{}_verified_{}_failed",
                        upload_result.upload_summary.research_r2_verified_count,
                        upload_result.upload_summary.research_r2_failed_count
                    )
                };
            }
            Ok((summary, upload_status))
        }
        .await;
        processed_this_invocation = processed_this_invocation.saturating_add(1);
        match run_result {
            Ok((summary, upload_status)) => {
                batch_state.in_progress_source_run = None;
                if !batch_state.completed_source_runs.contains(&source_run_id) {
                    batch_state.completed_source_runs.push(source_run_id.clone());
                }
                batch_state.failed_source_runs.remove(&source_run_id);
                batch_state
                    .per_run_status
                    .insert(source_run_id.clone(), "completed".to_owned());
                if let Some(replay_run_id) = summary.replay_run_id.clone() {
                    batch_state
                        .per_run_derived_run_id
                        .insert(source_run_id.clone(), replay_run_id);
                }
                batch_state
                    .per_run_warnings
                    .insert(source_run_id.clone(), summary.warnings.clone());
                batch_state
                    .per_run_r2_upload_status
                    .insert(source_run_id.clone(), upload_status);
                batch.summaries.push(summary);
            }
            Err(error) => {
                batch_state.in_progress_source_run = None;
                batch_state
                    .failed_source_runs
                    .insert(source_run_id.clone(), error.to_string());
                batch_state
                    .per_run_status
                    .insert(source_run_id.clone(), "failed".to_owned());
            }
        }
        batch_state.aggregate_status = if batch_state.completed_source_runs.len()
            == batch_state.selected_source_runs.len()
        {
            "completed".to_owned()
        } else if batch_state.failed_source_runs.is_empty() {
            "partial_incomplete".to_owned()
        } else {
            "partial_with_failures".to_owned()
        };
        write_research_batch_state(&batch_root, &batch_state)?;
    }
    println!("{}", serde_json::to_string_pretty(&batch)?);
    Ok(())
}

