async fn backtest(loaded: &LoadedConfig) -> Result<()> {
    let artifacts = rebuild_from_storage_latest(loaded).await?;
    let result = replay_paper_mode(loaded, &artifacts)?;
    let feature_engine = FeatureEngine::default();
    let risk_engine = RiskEngine::default();
    let simulator = Simulator::new(FeeModel::default());
    let labels = artifacts
        .snapshot
        .tokens
        .values()
        .map(|token| {
            let features =
                feature_engine.compute_snapshot(token, &artifacts.snapshot, now_for_token(token));
            let _risk = risk_engine.evaluate(token, &features, now_for_token(token));
            simulator.generate_labels(token, &features, Decimal::from(10u64))
        })
        .collect::<Vec<_>>();
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "backtest",
            "config_hash": loaded.hash,
            "idl_hash": artifacts.idl_hash,
            "run_id": artifacts.run_id,
            "tokens_labeled": labels.len(),
            "paper_closed_pnl": result.ledger().closed_pnl,
            "paper_fee_drag": result.ledger().fee_drag,
            "paper_fills": result.ledger().fills.len(),
        }))?
    );
    Ok(())
}

