fn feature_datum_to_string_cli(value: &Option<features::FeatureDatum>) -> String {
    match value {
        Some(features::FeatureDatum::Numeric(value)) => value.normalize().to_string(),
        Some(features::FeatureDatum::Text(value)) => value.clone(),
        Some(features::FeatureDatum::Boolean(value)) => value.to_string(),
        None => String::new(),
    }
}

fn feature_export_header() -> Vec<String> {
    vec![
        "run_id",
        "parent_run_id",
        "source_run_id",
        "scenario_id",
        "run_kind",
        "run_role",
        "schema_version",
        "config_hash",
        "idl_hash",
        "calibration_snapshot_hash",
        "runtime_sequence_number",
        "event_id",
        "decision_id",
        "mint",
        "strategy",
        "feature_snapshot_hash",
        "feature_name",
        "feature_category",
        "feature_value",
        "feature_status",
        "feature_confidence",
        "feature_timestamp",
        "source",
        "canonicality",
    ]
    .into_iter()
    .map(ToOwned::to_owned)
    .collect()
}

fn estimate_feature_export_bytes(records: &[StoredRecord<FeatureSnapshot>]) -> u64 {
    let feature_rows = records
        .iter()
        .map(|record| record.record.values.len() as u64)
        .sum::<u64>();
    feature_rows.saturating_mul(160)
}

fn write_chunked_feature_export(
    loaded: &LoadedConfig,
    run_id: &str,
    records: &[StoredRecord<FeatureSnapshot>],
    compress: bool,
) -> Result<ExportChunkManifest> {
    let store = storage_engine(loaded)?;
    let report_dir = store.run_report_dir(run_id);
    let run_lookup = store
        .list_runs()?
        .into_iter()
        .map(|record| (record.record.run_id.clone(), record))
        .collect::<std::collections::HashMap<_, _>>();
    let mut decision_lookup = std::collections::HashMap::<
        (String, Option<String>, String),
        StoredRecord<common::TradeDecisionEvent>,
    >::new();
    for record in store.read_trade_decisions()? {
        let Some(decision_run_id) = &record.run_id else {
            continue;
        };
        decision_lookup
            .entry((
                decision_run_id.clone(),
                record.scenario_id.clone(),
                record.record.feature_snapshot_hash.clone(),
            ))
            .or_insert(record);
    }
    let compression = export_compression_name(loaded, compress);
    let mut writer = CsvChunkWriter::new(
        report_dir.clone(),
        "features",
        feature_export_header(),
        export_chunk_rows(loaded),
        compression.is_some(),
        compression.clone(),
    )?;
    let feature_engine = FeatureEngine::default();
    let mut sorted = records.to_vec();
    sorted.sort_by(|left, right| {
        left.run_id
            .cmp(&right.run_id)
            .then_with(|| left.scenario_id.cmp(&right.scenario_id))
            .then_with(|| {
                left.runtime_sequence_number
                    .cmp(&right.runtime_sequence_number)
            })
            .then_with(|| left.record.mint.0.cmp(&right.record.mint.0))
            .then_with(|| left.record.observed_at.cmp(&right.record.observed_at))
            .then_with(|| left.source_event_id.cmp(&right.source_event_id))
    });
    for record in sorted {
        let run_metadata = record
            .run_id
            .as_deref()
            .and_then(|value| run_lookup.get(value));
        let key = (
            record.run_id.clone().unwrap_or_default(),
            record.scenario_id.clone(),
            record.record.vector_hash.clone(),
        );
        let decision = decision_lookup.get(&key);
        let mut feature_ids = record.record.values.keys().cloned().collect::<Vec<_>>();
        feature_ids.sort();
        for feature_id in feature_ids {
            let feature = record.record.values.get(&feature_id).expect("feature");
            let row = vec![
                record.run_id.clone().unwrap_or_default(),
                run_metadata
                    .and_then(|metadata| metadata.record.parent_run_id.clone())
                    .unwrap_or_default(),
                run_metadata
                    .and_then(|metadata| metadata.record.source_run_id.clone())
                    .unwrap_or_default(),
                record.scenario_id.clone().unwrap_or_default(),
                run_metadata
                    .map(|metadata| json_enum_label(&metadata.record.run_kind))
                    .unwrap_or_else(|| "unknown".to_owned()),
                run_metadata
                    .map(|metadata| json_enum_label(&metadata.record.run_role))
                    .unwrap_or_else(|| "unknown".to_owned()),
                record.schema_version.to_string(),
                record.config_hash.clone(),
                record.idl_hash.clone(),
                record
                    .calibration_snapshot_hash
                    .clone()
                    .or_else(|| {
                        run_metadata
                            .and_then(|metadata| metadata.record.calibration_snapshot_hash.clone())
                    })
                    .unwrap_or_default(),
                record
                    .runtime_sequence_number
                    .unwrap_or_default()
                    .to_string(),
                record.source_event_id.clone().unwrap_or_default(),
                decision
                    .map(|decision| decision.record.decision_id.clone())
                    .unwrap_or_default(),
                record.record.mint.0.clone(),
                decision
                    .map(|decision| decision.record.strategy.clone())
                    .unwrap_or_default(),
                record.record.vector_hash.clone(),
                feature_id.clone(),
                feature_engine
                    .registry()
                    .descriptor(&feature_id)
                    .map(|descriptor| descriptor.category.clone())
                    .unwrap_or_else(|| "unknown".to_owned()),
                feature_datum_to_string_cli(&feature.value),
                format!("{:?}", feature.status).to_lowercase(),
                feature.confidence.normalize().to_string(),
                record.record.observed_at.unix_timestamp_nanos().to_string(),
                record.source.clone(),
                record.canonicality.clone(),
            ];
            writer.write_row(&row)?;
        }
    }
    let chunks = writer.finish()?;
    persist_export_chunk_entries(loaded, run_id, "features", chunks, "chunked_local")
}

async fn export_features(
    loaded: &LoadedConfig,
    format: &str,
    run_id: Option<&str>,
    latest_run: bool,
    latest_shred_exit_run: bool,
    run_kind: Option<&str>,
    chunked: bool,
    compress: bool,
    upload_r2: bool,
    verify_r2: bool,
    allow_large_local_export: bool,
) -> Result<()> {
    forbid_heavy_vps_research_paths_in_edge_mode(loaded, "export-features")?;
    if !format.eq_ignore_ascii_case("csv") {
        return Err(anyhow!(
            "feature export format {format} is not implemented in this pass; use --format csv"
        ));
    }
    let selected_run_id =
        if run_id.is_some() || latest_run || latest_shred_exit_run || run_kind.is_some() {
            select_run_id(
                loaded,
                RunSelection {
                    run_id,
                    latest_run,
                    latest_source_run: false,
                    latest_shred_exit_run,
                    run_kind: parse_run_kind(run_kind)?,
                    ..Default::default()
                },
                false,
            )
            .await?
        } else {
            ensure_store_seeded(loaded).await?
        };
    let store = storage_engine(loaded)?;
    let mut records = load_feature_snapshots_for_run(loaded, &selected_run_id, true).await?;
    if records.is_empty() {
        let mut loaded_for_run = loaded.clone();
        loaded_for_run.config.environment.run_id = derived_run_id("paper-replay");
        let resolved = RuntimeResolvedConfig::from_loaded(
            loaded_for_run.clone(),
            Some(RuntimeMode::PaperFromStore),
        )?;
        let mut supervisor = Supervisor::new(resolved)?;
        let _ = supervisor
            .run_from_store_selection(Some(&selected_run_id), None)
            .await?;
        records = load_feature_snapshots_for_run(
            &loaded_for_run,
            &loaded_for_run.config.environment.run_id,
            true,
        )
        .await?;
    }
    let estimated_bytes = estimate_feature_export_bytes(&records);
    let force_chunked = chunked
        || (loaded.config.exports.chunked_enabled
            && estimated_bytes > export_max_uncompressed_bytes(loaded)
            && loaded.config.exports.prevent_monolithic_large_exports
            && !allow_large_local_export);
    let mut path = store.run_report_dir(&selected_run_id).join("features.csv");
    let mut chunk_manifest = None;
    if force_chunked {
        chunk_manifest = Some(write_chunked_feature_export(
            loaded,
            &selected_run_id,
            &records,
            compress,
        )?);
        if path.exists() {
            let _ = fs::remove_file(&path);
        }
    } else {
        path =
            store.export_feature_snapshots_csv(&records, Some(&selected_run_id), "features.csv")?;
        let _ = chunk_existing_export_if_needed(loaded, &selected_run_id, "features", &path)?;
    }
    if upload_r2 {
        upload_artifacts_r2_command(
            loaded,
            Some(&selected_run_id),
            false,
            false,
            false,
            false,
            false,
            false,
            false,
            false,
            true,
            false,
            false,
            false,
            false,
            true,
            verify_r2,
            !verify_r2,
            false,
            false,
            false,
            None,
            None,
            true,
        )
        .await?;
        if let Some(artifact_manifest) = load_manifest_if_present(loaded, &selected_run_id)? {
            let _ = sync_export_chunk_manifest_with_artifact_manifest(
                &store.run_report_dir(&selected_run_id),
                &artifact_manifest,
            )?;
        }
    }
    println!(
        "{}",
        serde_json::to_string_pretty(&json!({
            "command": "export-features",
            "format": "csv",
            "config_hash": loaded.hash,
            "idl_hash": combined_idl_hash(loaded)?,
            "run_id": selected_run_id,
            "rows": records.len(),
            "path": path,
            "chunked": force_chunked,
            "chunk_manifest_path": chunk_manifest.as_ref().map(|_| store.run_report_dir(&selected_run_id).join("export_chunks_manifest.json").display().to_string()),
        }))?
    );
    Ok(())
}

